-- Poems batch 157
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('2eafa2ad-d503-4cad-a247-dcbf865dc8f3','蔣慈谿挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','伊昔丹丘去，相逢意氣傾。',48,'全唐诗/poet.song.159000.json','["伊昔丹丘去，相逢意氣傾。", "樓前巾子秀，山下育泉清。", "敬梓情逾厚，交梨論益明。", "淒涼千古意，潮落又潮生。"]'),
('9aeacf0a-40f5-4f13-89e7-987aad6299c6','蔣慈谿挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','下筆欲生風，磨礱日有功。',48,'全唐诗/poet.song.159000.json','["下筆欲生風，磨礱日有功。", "推敲詩益鍊，駢儷語尤工。", "經問南雷叟，家傳十八公。", "詞人誰可繼，文陣滑稽雄。"]'),
('f2235e65-a4f1-482c-8207-0e6374d8951d','吳大監挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','庠校聲名早，朝廷譽望尊。',48,'全唐诗/poet.song.159000.json','["庠校聲名早，朝廷譽望尊。", "忠言如日皎，笑語若春溫。", "四擁皇華節，屢登金馬門。", "用才終不盡，流慶在仍昆。"]'),
('b2199d9f-c16b-404d-870a-796938e4032a','吳大監挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','曠典將行日，南宮得舍人。',48,'全唐诗/poet.song.159000.json','["曠典將行日，南宮得舍人。", "銓衡輕易地，造化漫勞神。", "舊事誰能記，交情我獨親。", "吁嗟三昧手，不見掌絲綸。"]'),
('32c3d2d4-0115-4f84-90f0-862ae5554ec8','梁運使挽詞','樓鑰','宋','宋诗','song-poetry','','[]','風月詩千首，煙霞宅一區。',48,'全唐诗/poet.song.159000.json','["風月詩千首，煙霞宅一區。", "三年著朝蹟，一節僨亨途。", "南海瞻遺堞，西門破老巫。", "才高不盡用，無地寄長吁。"]'),
('3cdda320-5f13-402d-9014-5727d81fd440','李撫州挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','與物初無忤，臺評反謂傾。',48,'全唐诗/poet.song.159000.json','["與物初無忤，臺評反謂傾。", "麾符成漫仕，林壑寄平生。", "跪履嗟何晚，揮犀空復情。", "天台隔風浪，無地拜佳城。"]'),
('c6991c92-b22b-4ff2-9f94-95d0d40a0802','李撫州挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','李下真無徑，門前可設羅。',48,'全唐诗/poet.song.159000.json','["李下真無徑，門前可設羅。", "詩如翰林逸，書似鄴侯多。", "奇字今誰問，遺編尚不磨。", "從來好哀挽，薤露忍興歌。"]'),
('9aff416d-515e-40de-bb29-a4ca155dbe3c','李撫州挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','蚤歲文聲振，長沙見賈生。',48,'全唐诗/poet.song.159000.json','["蚤歲文聲振，長沙見賈生。", "積薪看晚輩，推轂致名卿。", "子舍真連璧，生涯付短檠。", "風流今李漢，極口贊冰清。"]'),
('3e84be7d-21bf-4250-9716-555705c731d7','王遂安挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','淮水占王氏，生平熟義方。',48,'全唐诗/poet.song.159000.json','["淮水占王氏，生平熟義方。", "三珠欣競秀，兩桂蚤聯芳。", "才大用何嗇，源深流自長。", "青氈傳令子，一箭取雙鶬。"]'),
('c20d9a27-868c-41fc-a7c2-32ce2186b587','王遂安挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','學問自冰翁，詞章聳巨公。',48,'全唐诗/poet.song.159000.json','["學問自冰翁，詞章聳巨公。", "不慙循吏傳，真有古人風。", "捫蝨書猶在，飛鳬迹遽空。", "人琴悲子敬，三讀愴深衷。"]'),
('5097ddc7-803f-47da-8550-2c1f7cf69b44','趙提荆挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','毓秀從天派，盱衡動至尊。',48,'全唐诗/poet.song.159000.json','["毓秀從天派，盱衡動至尊。", "使星方炳耀，卿月遽侵昏。", "已矣悲吳館，誰歟護北門。", "慶源流未艾，文獻藹諸孫。"]'),
('a5a9eb60-ca58-488d-90ea-c0f5026827b2','趙提荆挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','處事才游刃，論文辯粲花。',48,'全唐诗/poet.song.159000.json','["處事才游刃，論文辯粲花。", "英姿凜熊豹，健華走龍蛇。", "持橐身終外，垂車夢到家。", "平泉花木在，愁絕舊生涯。"]'),
('44b85445-c749-43d7-9a5b-a06a5ed2f60a','趙提荆挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','客授早登龍，襟期一笑同。',48,'全唐诗/poet.song.159000.json','["客授早登龍，襟期一笑同。", "門清心似水，論正氣如虹。", "近問書猶濕，重來跡遂空。", "無因送丹旐，老淚灑西風。"]'),
('37534d70-eb17-44d2-988e-73023b07e6ee','李度支挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','忽作堂堂去，門前爵已羅。',48,'全唐诗/poet.song.159000.json','["忽作堂堂去，門前爵已羅。", "夢隨彈指斷，事向盖棺多。", "心繫六州鐵，身傾千丈坡。", "喑喑晝夜哭，柰此敬姜何。"]'),
('a89f0536-9b7c-4e21-84ed-d3418c4d3206','李度支挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','孰匪同升素，君於我最親。',48,'全唐诗/poet.song.159000.json','["孰匪同升素，君於我最親。", "詞章傳自舊，翰墨恍猶新。", "別去情逾篤，歸來跡遽陳。", "無從效經紀，悲結淚沾巾。"]'),
('e1e62935-4644-4c11-b4dc-bb742ebc300f','安人鄭氏挽詞','樓鑰','宋','宋诗','song-poetry','','[]','勤儉佐家肥，猶齊舉案眉。',48,'全唐诗/poet.song.159000.json','["勤儉佐家肥，猶齊舉案眉。", "錦封俱被寵，鸞鑑可勝悲。", "謝砌森群玉，郄林先一枝。", "木華文雋麗，銘德粲堂碑。"]'),
('cf9d175c-9e2c-4f47-b6a2-003fa5c77ab0','王夫人挽詞','樓鑰','宋','宋诗','song-poetry','','[]','淑質依名士，身期百不憂。',48,'全唐诗/poet.song.159000.json','["淑質依名士，身期百不憂。", "藁砧家萬里，蓬首日三秋。", "隨母傳遺業，嵇孤託舊游。", "幽原誦詩傳，無媿柏爲舟。"]'),
('8a957d69-8713-418e-bf55-a41610f3e0f3','方運使挽詞','樓鑰','宋','宋诗','song-poetry','','[]','聖主一見決，孤忠自致身。',48,'全唐诗/poet.song.159000.json','["聖主一見決，孤忠自致身。", "籌邊滿軀膽，處事掇皮真。", "氣直老彌壯，言高用未伸。", "留屯十二事，公論付淮民。"]'),
('44843e46-43e7-48d7-8bbf-6279f922c619','祝通判挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','坦坦曾無我，休休蚤見幾。',48,'全唐诗/poet.song.159000.json','["坦坦曾無我，休休蚤見幾。", "虛舟寧忤物，抱甕自忘機。", "老去心逾壯，歸來事已非。", "賞延推不及，有子尚家肥。"]'),
('2f2bbd6d-8aaf-4d27-9e8d-8c6b1b04db4a','祝通判挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','花縣弦歌化，蓮城水竹居。',48,'全唐诗/poet.song.159000.json','["花縣弦歌化，蓮城水竹居。", "舊寮情義厚，近別信音疎。", "不作三刀夢，空垂別駕車。", "新阡何處是，東望倍欷歔。"]'),
('41c86c4c-6f31-4a19-9c71-001ed01148c6','王武陵挽詞','樓鑰','宋','宋诗','song-poetry','','[]','胡虜久未殄，功名誰與同。',48,'全唐诗/poet.song.159000.json','["胡虜久未殄，功名誰與同。", "惟公負才氣，遇事等英雄。", "井井清邊瑣，駸駸有父風。", "惜哉天不憗，遺恨渺無窮。"]'),
('0409847d-6e9e-46e9-afb0-0bb4339fbb14','袁府君挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','家學傳三世，几間無二書。',48,'全唐诗/poet.song.159000.json','["家學傳三世，几間無二書。", "力行真勇猛，進取故舒徐。", "前輩多遺墨，先人祇故廬。", "後來窺甕牖，志士爲欷歔。"]'),
('b034a8e4-aa92-43dc-9e5b-72dc0183f8d3','袁府君挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','坦坦幽人履，恂恂長者言。',48,'全唐诗/poet.song.159000.json','["坦坦幽人履，恂恂長者言。", "憂時見顔色，樂道竟丘園。", "隠行推同氣，高賢萃一門。", "四明耆舊傳，他日數諸袁。"]'),
('2c4ea519-8fd1-46f9-8138-c214e7de9ea1','朱婺州挽詞','樓鑰','宋','宋诗','song-poetry','','[]','治行古循吏，風稜真諫官。',48,'全唐诗/poet.song.159000.json','["治行古循吏，風稜真諫官。", "鋤姦清遠徼，持重息羣讙。", "久弄趙堯印，重彈貢禹冠。", "去天才尺五，惜不見長安。"]'),
('6012a446-6f33-4045-8c27-a8ccd8fe722c','莫銅陵挽詞','樓鑰','宋','宋诗','song-poetry','','[]','經學高餘子，躬行慕古人。',48,'全唐诗/poet.song.159000.json','["經學高餘子，躬行慕古人。", "儒風三葉秀，和氣一門春。", "台嶺漸摩久，銅官撫字均。", "庠東亡二老，凝望倍沾巾。"]'),
('bf8ee279-0e08-4de5-af37-72ce00ea18d2','張泰州挽詞','樓鑰','宋','宋诗','song-poetry','','[]','燕趙多奇士，如公名不虛。',48,'全唐诗/poet.song.159000.json','["燕趙多奇士，如公名不虛。", "胸中九域志，筆底百家書。", "報國心尤壯，籌邊智有餘。", "功名竟齎恨，西望倍欷歔。"]'),
('3d12373b-53eb-42ed-aea3-c2f5f5470ff7','周路分挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','蚤負功名志，從戎豈素心。',48,'全唐诗/poet.song.159000.json','["蚤負功名志，從戎豈素心。", "治軍先肅靖，游藝亦精深。", "湖海開豪氣，雲天廓義襟。", "高門尚餘慶，蘭玉正森森。"]'),
('ec9e18e3-041d-4410-a8c2-8d4028b0cfb8','周路分挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','台嶺論交契，天街惜別離。',48,'全唐诗/poet.song.159000.json','["台嶺論交契，天街惜別離。", "飛書能幾到，埋璧遽成悲。", "舊識歸樵句，愁看結局詩。", "紫髯無復夢，空有淚交頤。"]'),
('43754b2c-b29d-41c5-95be-d0fd36c9236b','彭宜義挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','種德不在大，至誠天所親。',48,'全唐诗/poet.song.159000.json','["種德不在大，至誠天所親。", "但能存一念，何用活千人。", "經笥儒風遠，香山句法新。", "功名付兒輩，不必在吾身。"]'),
('60b895f1-38da-402e-81d3-fcc8ccf9021d','彭宜義挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','籍甚清湘守，脩名所在聞。',48,'全唐诗/poet.song.159000.json','["籍甚清湘守，脩名所在聞。", "宦途資畏友，家訓仰嚴君。", "歸路飛丹旐，長空慘白雲。", "生芻不成奠，揮涕想江濆。"]'),
('0b37f7ae-ecce-422d-8b4a-856ea083422c','沈朝奉挽詞','樓鑰','宋','宋诗','song-poetry','','[]','相業富青箱，丁年稔義方。',48,'全唐诗/poet.song.159000.json','["相業富青箱，丁年稔義方。", "生兒有如此，與世遂相忘。", "終老三牲養，凌晨一炷香。", "浮休了無恨，流慶尚深長。"]'),
('555b5b40-6b22-4b31-8842-9d3be89d350f','石通直挽詞','樓鑰','宋','宋诗','song-poetry','','[]','籍甚新昌族，真成萬石家。',48,'全唐诗/poet.song.159000.json','["籍甚新昌族，真成萬石家。", "源流端有自，悃愊更無華。", "奉職冰同潔，持身璧不瑕。", "慶門傳未艾，蘭玉茁新芽。"]'),
('048204aa-d63a-4acf-84f7-efe7f47e2430','王檢正挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','到處稱循吏，星軺復郡侯。',48,'全唐诗/poet.song.159000.json','["到處稱循吏，星軺復郡侯。", "威名致降虜，恩信感亡牛。", "省闥主公議，祠庭尋舊游。", "善人天不憗，愁絕峴湖秋。"]'),
('4246f2db-663b-4066-bab0-ffaf2b80bd0b','王檢正挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','客授蒙傾盖，朝參喜綴班。',48,'全唐诗/poet.song.159000.json','["客授蒙傾盖，朝參喜綴班。", "開藩才一水，去國遂千山。", "晚遇名方重，言歸鬢未斑。", "功名付諸子，含笑謝塵寰。"]'),
('fe8e621f-54ed-411f-b40c-2b9339cd5afe','張欽州挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','少誦東窗句，從君見典刑。',48,'全唐诗/poet.song.159000.json','["少誦東窗句，從君見典刑。", "義襟希竇十，才刃比庖丁。", "古鏡悲鸞偶，寒原愴脊令。", "恂恂守家法，蘭玉滿階庭。"]'),
('2c0f0727-65af-493a-80bd-ac95f057bd8e','張欽州挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','游宦二毛侵，欽山繼鬰林。',48,'全唐诗/poet.song.159000.json','["游宦二毛侵，欽山繼鬰林。", "精神雖滿腹，撫字亦勞心。", "膚使章交上，雌堂疾遽深。", "護喪嗟季子，又復喪清潯。"]'),
('6eaa0e82-4256-4781-ad6a-b3231fece6ee','張欽州挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','姻好自諸馮，東床取阿戎。',48,'全唐诗/poet.song.159000.json','["姻好自諸馮，東床取阿戎。", "平時深念我，晚歲忍銘公。", "書字今猶濕，心期誰與同。", "回頭三十載，灑涕向西風。"]'),
('7e6f191c-455a-4477-8261-6f1ee6ccd5eb','陸郎中挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','壯歲聯雙捷，衰年困百罹。',48,'全唐诗/poet.song.159000.json','["壯歲聯雙捷，衰年困百罹。", "肉身心佛子，霜髮貌嬰兒。", "萬事幾樽酒，百年千首詩。", "浮生成夢覺，吾道竟何之。"]'),
('b2ce7b46-029e-4672-947c-3c759bee584b','陸郎中挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','從弟忝東床，相從二十霜。',48,'全唐诗/poet.song.159000.json','["從弟忝東床，相從二十霜。", "人琴一何苦，冰玉兩俱傷。", "別久成今昔，歸來失老蒼。", "稽陰終反葬，西望倍淒涼。"]'),
('15670de5-1b0e-4247-951e-3b97058af2ea','齊國夫人曹氏挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','痛哭王孫去，南來萬里餘。',48,'全唐诗/poet.song.159000.json','["痛哭王孫去，南來萬里餘。", "解衣催艇子，扶杖擁籃輿。", "已矣空鸞鏡，誰歟得鴈書。", "辛勤立門戶，地下勿欷歔。"]'),
('421fd7c7-8a17-4053-a306-eb9780a1104c','齊國夫人曹氏挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','宗子今曾子，夫人古敬姜。',48,'全唐诗/poet.song.159000.json','["宗子今曾子，夫人古敬姜。", "邛郲承孝養，浯水刻恩章。", "湯沐封逾寵，芝蘭晚更芳。", "九齡天報遠，餘慶尚流光。"]'),
('4403474a-0fd8-4786-a8d5-bc273b487c8a','信國夫人秦氏挽詞','樓鑰','宋','宋诗','song-poetry','','[]','夫人富貴出懷綳，擇配和鳴得仲卿。',64,'全唐诗/poet.song.159000.json','["夫人富貴出懷綳，擇配和鳴得仲卿。", "鸞誥蚤能封大國，魚軒不及伴雙旌。", "肥家得法晚無倦，教子登科新有聲。", "難息南谿未成屋，鳳凰山下啟佳城。"]'),
('2091a76f-1377-4bac-a719-e74079638e88','王夫人挽詞','樓鑰','宋','宋诗','song-poetry','','[]','婦德勝賢士，嫠居成大家。',48,'全唐诗/poet.song.159000.json','["婦德勝賢士，嫠居成大家。", "陰功宜有後，餘慶尚無涯。", "楊惲出司馬，陶潜傳孟嘉。", "文昌紀遺範，外氏倍增華。"]'),
('135665b2-93d9-428b-8469-4660fffa327b','恭人强氏挽詞','樓鑰','宋','宋诗','song-poetry','','[]','祠部源流遠，來嬪曲阜孫。',48,'全唐诗/poet.song.159000.json','["祠部源流遠，來嬪曲阜孫。", "事夫終婦道，訓子大吾門。", "頒誥恩光渥，升堂笑語溫。", "相期送丹旐，馬鬣近周原。"]'),
('86ac1dd2-5fec-4cbd-bd38-73f3e6112aef','恭人董氏挽詞','樓鑰','宋','宋诗','song-poetry','','[]','敬饁尊夫子，升堂乳阿姑。',48,'全唐诗/poet.song.159000.json','["敬饁尊夫子，升堂乳阿姑。", "鄉評推至行，家慶展新圖。", "半世悲鸞舞，高年樂鳳雛。", "蜜章應未艾，卿月映階符。"]'),
('6dc15466-8974-4ee5-b0bf-26e0890b7d78','恭人胡氏挽詞','樓鑰','宋','宋诗','song-poetry','','[]','懿行表閨房，情親共衋傷。',48,'全唐诗/poet.song.159000.json','["懿行表閨房，情親共衋傷。", "繡衣來宅相，彤管著銘章。", "蘋澗誰供祀，藁砧空悼亡。", "芝蘭俱秀發，所恨失元方。"]'),
('49960d67-9801-44c2-9879-487f7e4c7c9c','趙司戶挽詞','樓鑰','宋','宋诗','song-poetry','','[]','奕奕佳公子，詞場早策勳。',48,'全唐诗/poet.song.159000.json','["奕奕佳公子，詞場早策勳。", "願爲新進士，終屈病參軍。", "舊事成清夢，高標想斷雲。", "傷心桑落酒，無復到孤墳。"]'),
('62ec332d-b3f2-416d-a7ce-ad6f6f2a22a9','王大卿挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','少壯節先著，年侵氣不衰。',48,'全唐诗/poet.song.159000.json','["少壯節先著，年侵氣不衰。", "忠雖由父教，清亦畏人知。", "處世無求合，安時竟數奇。", "甘泉人物會，一老漢空遺。"]'),
('92be81ff-3114-4f9a-ac13-4546b6c831a8','王大卿挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','麾節東南半，澄清冠一時。',48,'全唐诗/poet.song.159000.json','["麾節東南半，澄清冠一時。", "權輿周翰傳，頂踵阜陵知。", "自謂二宜去，人稱三不欺。", "卷懷終未盡，流慶稱家兒。"]'),
('ff928821-132e-4b90-8943-aa1432e291c3','王大卿挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','圖史但環堵，江湖幾問津。',48,'全唐诗/poet.song.159000.json','["圖史但環堵，江湖幾問津。", "雖多暮年樂，誰忍半生貧。", "海內清名滿，毫端秀句新。", "風流嗟頓盡，晉韵更何人。"]'),
('97d737f8-fa2e-45f0-8da2-04087232f68a','王大卿挽詞  其四','樓鑰','宋','宋诗','song-poetry','','[]','老去王摩詰，歸來道更全。',48,'全唐诗/poet.song.159000.json','["老去王摩詰，歸來道更全。", "賸添天美祿，真得地行仙。", "日欲增三徑，君胡欠百年。", "桃源不無路，重上慘風煙。"]'),
('bff10acd-1bae-4e25-bf1f-441a2fe229bb','王大卿挽詞  其五','樓鑰','宋','宋诗','song-poetry','','[]','上世總儒先，猶傳夢雪篇。',48,'全唐诗/poet.song.159000.json','["上世總儒先，猶傳夢雪篇。", "惟應佳壻選，可配老姑賢。", "父行偏知我，交情不問年。", "槁梧誰共語，愁斷伯牙絃。"]'),
('021a9911-d9bb-41ee-9466-cc02a74b0f8b','徐少卿挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','聖主一言寤，長淮千耦耕。',48,'全唐诗/poet.song.159000.json','["聖主一言寤，長淮千耦耕。", "山川皆在目，草木尚知名。", "盍被腰金寵，徒爲攬轡行。", "諸郎襲餘慶，定自不慙卿。"]'),
('1d800692-2143-46a3-9d0e-5b5c5a5956f9','徐少卿挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','所至多遺愛，丹丘最有聲。',48,'全唐诗/poet.song.159000.json','["所至多遺愛，丹丘最有聲。", "奉常千載久，攀戀一城傾。", "已恨數離別，寧知隔死生。", "湖邊舊門巷，一到一心驚。"]'),
('a70c7e6f-5789-4ec8-94f0-3a2bbe6f3e87','陸提刑挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','數馬謙恭甚，揮犀色笑溫。',48,'全唐诗/poet.song.159000.json','["數馬謙恭甚，揮犀色笑溫。", "風流士龍裔，文采左丞孫。", "晚幸成三徑，身胡遽九原。", "素欽仁者勇，大獄竟平反。"]'),
('630e3a57-5d38-4e36-be72-bd1f13e80e5a','陸提刑挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','早歲擅詞場，夷途列鴈行。',48,'全唐诗/poet.song.159000.json','["早歲擅詞場，夷途列鴈行。", "一麾分楚甸，雙節照江鄉。", "蓮社容寒晚，葭莩接老蒼。", "八旬俱已矣，回首倍淒涼。"]'),
('c492c557-d34d-431e-9c74-c3eee774af05','史敷文挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','八行諸孫盛，三公嗣子賢。',48,'全唐诗/poet.song.159000.json','["八行諸孫盛，三公嗣子賢。", "連收四鶚薦，祇欠一青氈。", "郎省刑章肅，侯邦政譽傳。", "平生憂國意，齎志入重泉。"]'),
('87e4f67a-d7f5-4bb0-a9f7-0819dd305b04','史敷文挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','學問源流遠，樂哉賢父兄。',48,'全唐诗/poet.song.159000.json','["學問源流遠，樂哉賢父兄。", "人琴亡舊曲，風木愴寒聲。", "深痛幾成毀，沉痾汔喪生。", "孝恭無可憾，猶得傍佳城。"]'),
('b5e9e955-60f4-49f5-943c-bd54d750d957','史敷文挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','少小相從久，自慙雌甲辰。',48,'全唐诗/poet.song.159000.json','["少小相從久，自慙雌甲辰。", "交情日加厚，姻好晚逾親。", "別去驚葭律，歸來見棘人。", "西莊行樂地，望斷爲沾巾。"]'),
('7133ddf7-4b21-450c-ae18-2dff6e4b3aa4','寧海劉君挽詞','樓鑰','宋','宋诗','song-poetry','','[]','不識紫芝眉，空傳有道碑。',48,'全唐诗/poet.song.159000.json','["不識紫芝眉，空傳有道碑。", "義方真可法，闇室肯容欺。", "未覺山川改，深明晝夜知。", "薤歌慙不稱，冢子素能詩。"]'),
('a0af0c62-2d09-4bab-8a79-3fa6b3506328','丁寺丞挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','家世傳經術，膠庠藹雋聲。',48,'全唐诗/poet.song.159000.json','["家世傳經術，膠庠藹雋聲。", "上方思舊學，公乃擅專城。", "滁上功尤著，潮陽政愈明。", "哀哉鍔流水，猶解不平鳴。"]'),
('5bf14060-5505-42fc-81d6-ca4d9277a227','丁寺丞挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','嚴冷不可向，其中實曠然。',48,'全唐诗/poet.song.159000.json','["嚴冷不可向，其中實曠然。", "行藏睽素志，燕樂了餘年。", "鶴化人何處，鸞孤影自憐。", "才高不盡用，流慶尚綿綿。"]'),
('ff788545-9130-4e91-afce-8668b91bc057','曹工部挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','箕潁文章士，儀同社稷功。',48,'全唐诗/poet.song.159000.json','["箕潁文章士，儀同社稷功。", "惟公承慶裔，有意振家風。", "祠祿真崇道，郎潜歎老馮。", "傷心循吏手，齎志九原中。"]'),
('37d3294f-78a5-426e-aca3-2186559de439','曹工部挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','宦達推公早，丁年備皂衣。',48,'全唐诗/poet.song.159000.json','["宦達推公早，丁年備皂衣。", "幾爲銅虎去，終向石橋歸。", "齊國世臣少，貞元朝士稀。", "松風談笑地，回首倍歔欷。"]'),
('b9399485-af44-4a25-bf99-fb8bdcb92e82','范致政挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','義俠久無迹，吾鄉見此翁。',48,'全唐诗/poet.song.159000.json','["義俠久無迹，吾鄉見此翁。", "紫微欣稅駕，飛將許同功。", "銀茜聯恩渥，金蘭藹義風。", "雖增嬴博恨，猶喜桂成叢。"]'),
('b0a8bd07-2ee4-4c91-958f-df2172f7f6f4','范致政挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','酒後昇平曲，閑中安樂窩。',48,'全唐诗/poet.song.159000.json','["酒後昇平曲，閑中安樂窩。", "千金曾累致，一醉竟無何。", "老驥志空在，孤鸞悲亦多。", "相望才歲許，託體共山阿。"]'),
('84147492-1679-45a7-82e7-d497f47cb72e','王觀國挽詞','樓鑰','宋','宋诗','song-poetry','','[]','晚識三珠樹，方知獨笑翁。',48,'全唐诗/poet.song.159000.json','["晚識三珠樹，方知獨笑翁。", "舊游虧半面，遺恨想高風。", "小楷墨猶濕，殘膏澤未窮。", "梅花縞寒夜，埋璧衆香中。"]'),
('91b7afef-7295-4d25-9846-ffc8bc671325','高端叔挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','百氏極旁搜，潜心老不休。',48,'全唐诗/poet.song.159000.json','["百氏極旁搜，潜心老不休。", "鄰光時自照，簞食孰堪憂。", "弟子多藍綬，先生竟白頭。", "淒涼數間屋，知我獨春秋。"]'),
('d5faba48-dc66-44bc-98a2-ecba92a0a57f','高端叔挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','鐵石賦梅花，閑情白玉瑕。',48,'全唐诗/poet.song.159000.json','["鐵石賦梅花，閑情白玉瑕。", "兩公終磊落，千載敢諠譁。", "清節成瑰偉，浮詞尚蘗芽。", "君看死生際，不見一毫差。"]'),
('81618f58-336f-4f41-a282-7c08f1ad4b27','高端叔挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','滿卷變離騷，歐公一素袍。',48,'全唐诗/poet.song.159000.json','["滿卷變離騷，歐公一素袍。", "豈惟將厚意，要使丐殘膏。", "宿草成千古，生芻爲一號。", "雖無韓子誄，貞曜本來高。"]'),
('c64a5232-a57c-4f7b-9d0b-bc59a6d12533','錢江陰挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','庾嶺梅花暖，賢侯惠愛深。',48,'全唐诗/poet.song.159000.json','["庾嶺梅花暖，賢侯惠愛深。", "精神雖滿腹，撫字亦勞心。", "九轉竟難遇，二毛何遽侵。", "傷哉東逝水，無復大江陰。"]'),
('886feeca-0cd7-4c01-93ed-086bc88ff444','錢江陰挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','客授向東歐，君爲郡督郵。',48,'全唐诗/poet.song.159000.json','["客授向東歐，君爲郡督郵。", "豈惟寮契篤，更喜吏才優。", "每嘆頻年別，俄驚一夢休。", "虞山渺何許，淚落不能收。"]'),
('5d6a9c39-723b-48d6-847e-94ff38f4111c','李刪定挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','積善務增厚，求名惟恐多。',48,'全唐诗/poet.song.159000.json','["積善務增厚，求名惟恐多。", "白圭寧有玷，古井竟無波。", "議法資修定，監州極撫摩。", "佳兒傳素業，留眼看巍科。"]'),
('c41d9235-1137-497d-9380-01f6cda1835e','李刪定挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','冰玉心相照，誰云內舉私。',48,'全唐诗/poet.song.159000.json','["冰玉心相照，誰云內舉私。", "深居無浪出，清節畏人知。", "尚憶紫芝宇，無慙有道碑。", "填空雨黄葉，西望不勝悲。"]'),
('da2618ad-4f1b-4e18-9ffb-99a5931c6953','趙左司挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','行誼高餘子，文章自一家。',48,'全唐诗/poet.song.159000.json','["行誼高餘子，文章自一家。", "嶽神均客禮，敵國歎才華。", "直節曾無苦，全瑜更不瑕。", "儒流有遺恨，不見草黄麻。"]'),
('b2bb29fc-b7bd-42b1-a5ec-f9fe9e7cb545','趙左司挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','淮甸爭錢幣，夔城辯戍兵。',48,'全唐诗/poet.song.159000.json','["淮甸爭錢幣，夔城辯戍兵。", "詔歸南郡近，公去北門輕。", "避寵若將浼，求閑竟不成。", "亦齊無適莫，一笑老于行。"]'),
('e2fcc840-c94f-460d-af12-efe28fead797','趙左司挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','許國終無撓，居家不願餘。',48,'全唐诗/poet.song.159000.json','["許國終無撓，居家不願餘。", "深蒙明主眷，未覺故人疎。", "高論三千牘，陰功四一書。", "佳兒承積慶，端可大門閭。"]'),
('1e514935-9970-4833-805b-b6cf137895dc','趙左司挽詞  其四','樓鑰','宋','宋诗','song-poetry','','[]','鄉貢蚤馳譽，郎潜方比肩。',48,'全唐诗/poet.song.159000.json','["鄉貢蚤馳譽，郎潜方比肩。", "求仙容我學，成佛歎君先。", "天癸年將暮，金丹語未圓。", "忽傳長別偈，天闊散雲煙。"]'),
('a1713757-ab2b-4f8f-a139-e9ed8b0e7be5','袁通判挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','大道知如路，一心長似齋。',48,'全唐诗/poet.song.159000.json','["大道知如路，一心長似齋。", "耄期稱不倦，胸次樂無涯。", "孝謹古難及，友恭人自懷。", "無瑕夜光璧，黄壤痛深埋。"]'),
('6950601c-5000-4cb5-ab3e-84efbce6694d','袁通判挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','盛德不容贊，多言可柰何。',48,'全唐诗/poet.song.159000.json','["盛德不容贊，多言可柰何。", "大圭元不琢，古井竟無波。", "前輩苦凋謝，後生誰琢磨。", "同庚適齋老，託體共山阿。"]'),
('8ce97563-5e31-456b-9bfa-512235775539','袁通判挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','僅有一區宅，曾無二頃田。',48,'全唐诗/poet.song.159000.json','["僅有一區宅，曾無二頃田。", "相過惟載酒，至老不言錢。", "幾得拜牀下，何堪哭道邊。", "門人多著籍，下馬向新阡。"]'),
('6a9cd13f-c743-4f9e-ac69-dd63f431bc4e','方興化挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','廟乏著靴鬼，夢中言更明。',48,'全唐诗/poet.song.159000.json','["廟乏著靴鬼，夢中言更明。", "起家尤感勵，爲吏極廉平。", "薦口聲名重，朝行去就輕。", "奏篇真確論，何日遂施行。"]'),
('8e1fbc13-18bf-4423-86b8-fb4a7db63ca0','方興化挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','鴈塔深論契，鵷班試著行。',48,'全唐诗/poet.song.159000.json','["鴈塔深論契，鵷班試著行。", "參亡聞易簀，越弔後除喪。", "支郡難留鄧，佳城久夢方。", "吁嗟德浮位，回施與諸郎。"]'),
('4563f9a4-e13e-4c69-bf25-e65d4f04cf39','寧海駱君挽詞','樓鑰','宋','宋诗','song-poetry','','[]','古易人皆學，惟君志益堅。',48,'全唐诗/poet.song.159000.json','["古易人皆學，惟君志益堅。", "研朱滴秋露，讀簡斷韋編。", "空谷甘無用，佳兒尚有傳。", "清風誰得似，竹滿卧牀前。"]'),
('10472430-b37c-473f-ab6a-6fd7c6c1046c','朱坡史居士挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','巖邑富人物，才惟史氏多。',48,'全唐诗/poet.song.159000.json','["巖邑富人物，才惟史氏多。", "流傳有丹桂，遺逸歎朱坡。", "學飽終難售，詩成祇自哦。", "空餘著書在，令子挹餘波。"]'),
('0205d761-02c9-46cd-8ece-ddfeaea352ab','朱坡史居士挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','交友俱名士，儀曹禮意周。',48,'全唐诗/poet.song.159000.json','["交友俱名士，儀曹禮意周。", "使華臨夏口，詩興共南樓。", "喜得江山助，還同汗漫游。", "更煩賢宅相，相與發潜幽。"]'),
('2805636b-f601-493d-a87b-090cd43eebc4','劉吏部挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','總角異羣兒，庭趨蚤學詩。',48,'全唐诗/poet.song.159000.json','["總角異羣兒，庭趨蚤學詩。", "一鳴登桂籍，百里靜潢池。", "所至清民瘼，平生號吏師。", "郎闈方進用，何乃棄明時。"]'),
('f5649b0a-7c76-4a4a-b6e8-90559f29e9e7','劉吏部挽詞  其二','樓鑰','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','剸劇最雲間，題輿上越山。',48,'全唐诗/poet.song.159000.json','["剸劇最雲間，題輿上越山。", "洞庭王澤遠，庾嶺使星還。", "中道趨臺治，名曹切近班。", "陰功多及物，陽報看循環。"]'),
('8899a69c-dc29-431d-a17e-01b51ac934c2','劉吏部挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','誰擾奚山衆，焚林獸已窮。',48,'全唐诗/poet.song.159000.json','["誰擾奚山衆，焚林獸已窮。", "徙薪能遠慮，下瀨得深攻。", "南嶠肩隨息，中朝論愈公。", "但知分謗喜，寧肯自論功。"]'),
('82a625af-05c7-4cc4-b17f-431c8644d224','劉吏部挽詞  其四','樓鑰','宋','宋诗','song-poetry','','[]','兄長與慈恩，相親色笑溫。',48,'全唐诗/poet.song.159000.json','["兄長與慈恩，相親色笑溫。", "公方持使節，余忝代王言。", "共約游三徑，俄悲作九原。", "佳城隔風浪，丹旐愴飛翻。"]'),
('4b25af54-f8d9-43c6-b870-0f198f2b9fc5','戴縣丞挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','小戴久僊去，何堪更哭君。',48,'全唐诗/poet.song.159000.json','["小戴久僊去，何堪更哭君。", "舊游驚昨夢，陳迹愴遺文。", "晚暮期相與，死生俄遽分。", "銘成媿潛德，揮涕望新墳。"]'),
('b3fd536d-ee52-4dad-8b10-ebd6dce381b9','戴縣丞挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','高士終爲簿，豈惟勾小稽。',48,'全唐诗/poet.song.159000.json','["高士終爲簿，豈惟勾小稽。", "鸞凰雖在棘，桃李自成蹊。", "官府資關決，儒流仰品題。", "定知餘慶遠，遺愛滿雙谿。"]'),
('372aa67e-f62e-4c8f-b3e0-ce65645a3b51','王提刑挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','廉白真家法，原由金紫賢。',48,'全唐诗/poet.song.159000.json','["廉白真家法，原由金紫賢。", "兄辭嶺南賻，弟却澧陽錢。", "築屋吾將老，藏書手自編。", "老成俄已矣，聞者爲潸然。"]'),
('f6097fb5-fbe8-44d5-b301-1e6475d23c3b','王提刑挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','籍甚青箱學，醇乎赤子心。',48,'全唐诗/poet.song.159000.json','["籍甚青箱學，醇乎赤子心。", "片言皆可復，一僞不容侵。", "處事幾游刃，論交欲斷金。", "諸郎傳素業，桂子看成林。"]'),
('a20a60da-7ec9-4129-85cb-c8ea5d6596cd','王提刑挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','二廣外臺首，威稜著一門。',48,'全唐诗/poet.song.159000.json','["二廣外臺首，威稜著一門。", "志期諸郡肅，忍見匹夫冤。", "奮繫猶鷹鷙，興讒有兔爰。", "投閒了無恨，此意與誰論。"]'),
('c932882b-db38-469f-b573-0809cac1b66f','王提刑挽詞  其四','樓鑰','宋','宋诗','song-poetry','','[]','伯仲三珠樹，優爲一世才。',48,'全唐诗/poet.song.159000.json','["伯仲三珠樹，優爲一世才。", "人琴先起恨，金玉遂俱摧。", "南阮方深痛，阿連尤可哀。", "桃花源上路，老眼更堪開。"]'),
('3fed2f1e-8f77-423c-a70b-3740c0234f77','鄭華文挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','蚤擅春秋學，賢關第一流。',48,'全唐诗/poet.song.159000.json','["蚤擅春秋學，賢關第一流。", "少公清澤國，贊府著神州。", "試邑人交薦，還朝譽更優。", "如何急流退，不使上瀛洲。"]'),
('8f0b77b3-af53-41f4-80fa-def97a346668','鄭華文挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','籍甚柯山政，兒童識貴溫。',48,'全唐诗/poet.song.159000.json','["籍甚柯山政，兒童識貴溫。", "歡謠聞魏闕，殊寵鎮吳門。", "就養家傳子，休官澤及孫。", "吾鄉耆舊傳，千載德彌尊。"]'),
('173ee83f-e594-4752-b1d6-13773860a20c','鄭華文挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','兄弟忝同登，論交最有情。',48,'全唐诗/poet.song.159000.json','["兄弟忝同登，論交最有情。", "頹波知勁節，徹底歎真清。", "正爾尋姻好，胡然喪老成。", "抱痾難執紼，揮涕望佳城。"]'),
('d090778f-7433-469f-bd3c-065d650f6814','姜鍾離挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','門戶期興起，交朋務琢磨。',48,'全唐诗/poet.song.159000.json','["門戶期興起，交朋務琢磨。", "反身求大學，決意取儒科。", "贊府聲尤著，鄰封惠亦多。", "傷心濠上路，無復聽弦歌。"]'),
('587ed55a-6bef-4712-80a4-b43c7d7e9fa2','姜鍾離挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','別去期三載，伻來痛一書。',48,'全唐诗/poet.song.159000.json','["別去期三載，伻來痛一書。", "死生誠大矣，力量果何如。", "平日真知我，遺言苦問予。", "作銘雖不媿，回首倍欷歔。"]'),
('d7f05ceb-ed37-4ec9-aad2-9729a562cf32','顧養直挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','萬頃東湖下，曾門起大家。',48,'全唐诗/poet.song.159000.json','["萬頃東湖下，曾門起大家。", "子孫昌世業，文字作生涯。", "堂後萱猶樹，庭中桂欲華。", "惜哉時不待，誰忍送悲笳。"]'),
('203db934-8ecc-458f-9ee3-b16909f46952','顧養直挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','舊向君家去，宜齋屢舉觴。',48,'全唐诗/poet.song.159000.json','["舊向君家去，宜齋屢舉觴。", "人哀誦諸顧，里不見他楊。", "身世驚春暮，湖山愴夕陽。", "園林未成趣，鷗鷺亦淒涼。"]'),
('fc957fda-aa81-4aee-a389-7a5a9066a1f8','孫子才挽詞','樓鑰','宋','宋诗','song-poetry','','[]','身後名何用，人亡意愈深。',48,'全唐诗/poet.song.159000.json','["身後名何用，人亡意愈深。", "盖棺悲昨夢，掛劍答初心。", "潜德仍能發，遺言尚可尋。", "悼元情更切，接隴柏森森。"]'),
('d1c834fd-3783-417f-8c94-f75ac54bd63b','俞通判挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','强仕賦歸去，頻年亦漫行。',48,'全唐诗/poet.song.159000.json','["强仕賦歸去，頻年亦漫行。", "宦情雖淡泊，官事極精明。", "贊畫王公幕，監州亞父城。", "佳兒守遺訓，清白勝金籯。"]'),
('d9d43f54-f9dd-4051-aef9-b85dcba47aec','俞通判挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','象邑推三俊，靈光頼此賢。',48,'全唐诗/poet.song.159000.json','["象邑推三俊，靈光頼此賢。", "老成俄已矣，遠邇爲潸然。", "孝敬心何極，公平錄尚傳。", "佳城隔風浪，忍賦薤歌篇。"]'),
('a8d08225-8504-47a0-8d27-f913f13681ac','求參議挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','累世朱陳舊，宦游多向鄞。',48,'全唐诗/poet.song.159000.json','["累世朱陳舊，宦游多向鄞。", "飛鳬觀政美，展驥愈情親。", "久草歸田賦，欣迎入幕賓。", "斯人忽千古，望斷剡溪濱。"]'),
('d94e917d-cc6b-4fb2-8a6d-47a15ceea72a','求參議挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','玉立期清貴，厖眉望壽齡。',48,'全唐诗/poet.song.159000.json','["玉立期清貴，厖眉望壽齡。", "父兄嗟奄忽，姑姊亦凋零。", "厚德今誰在，佳城慘欲扃。", "孫曾聞競爽，蘭玉在階庭。"]'),
('1dbf1a78-96d4-4958-ba94-efff87b5b914','魏郎中挽詞','樓鑰','宋','宋诗','song-poetry','','[]','相公鍾鼎蔽詩聲，鯉也聞詩蚤得名。',64,'全唐诗/poet.song.159000.json','["相公鍾鼎蔽詩聲，鯉也聞詩蚤得名。", "高隠碧谿心更遠，今游湘浦句尤清。", "握蘭未足酬吾志，攬轡寧知老此行。", "今日哭君誰最切，山房門下老門生。"]'),
('17978dc7-143e-4783-a665-aa200d2fa865','宋南雄挽詞','樓鑰','宋','宋诗','song-poetry','','[]','二宋久云遠，遺風君庶幾。',48,'全唐诗/poet.song.159000.json','["二宋久云遠，遺風君庶幾。", "才華試文戰，政譽藹王畿。", "梅嶺方騰最，雪谿俄賦歸。", "情親今已矣，老淚不勝揮。"]'),
('73968215-91a8-49ac-aa2c-52a3a032e1bd','莫子執挽詞','樓鑰','宋','宋诗','song-poetry','','[]','樂有父兄賢，談經絳帳前。',48,'全唐诗/poet.song.159000.json','["樂有父兄賢，談經絳帳前。", "桂林孤素志，芹泮老遺編。", "小阮情何切，童烏業未傳。", "槔閒最崇篤，口口話齊年。"]'),
('7084403d-5364-4635-8db3-662e7ec213a8','繆伯恭挽詞','樓鑰','宋','宋诗','song-poetry','','[]','我實由汪出，垂髫托外門。',48,'全唐诗/poet.song.159000.json','["我實由汪出，垂髫托外門。", "非惟拜先德，猶及見新婚。", "謹厚推鄉曲，恩慈篤弟昆。", "善人今已矣，餘慶在兒孫。"]'),
('b9e4bdf5-adab-40f9-ae2a-2e6ab48d0e0c','朱南劍挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','再世文章伯，三朝侍從臣。',48,'全唐诗/poet.song.159000.json','["再世文章伯，三朝侍從臣。", "傳家推篤學，游宦肯謀身。", "別駕歌章水，甘棠想劍津。", "虛堂兩遺像，誰不倍傷神。"]'),
('8c6429e9-1c33-4e2c-a870-668a1326e1d6','朱南劍挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','朔望第一客，巡寮意更親。',48,'全唐诗/poet.song.159000.json','["朔望第一客，巡寮意更親。", "有詩欣和韵，不飲喜娛賓。", "名帖藏中古，珍茶試早春。", "據鞍猶矍鑠，何遽迹成陳。"]'),
('c2e2688a-1ece-4d96-b211-4b26f00d8d01','朱南劍挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','棋戰久不對，詩盟亦寖寒。',48,'全唐诗/poet.song.159000.json','["棋戰久不對，詩盟亦寖寒。", "方期會真率，乃爾變悲歡。", "歲晚本無憾，情深那忍看。", "佳城何處是，東望涕汍瀾。"]'),
('c4a7a867-3a94-4dd7-b387-6b4e3fa7d21b','盛夫人挽詞','樓鑰','宋','宋诗','song-poetry','','[]','婉嬺閨中秀，清高林下風。',48,'全唐诗/poet.song.159000.json','["婉嬺閨中秀，清高林下風。", "相夫能盡禮，教子使移忠。", "邊郡官無曠，都城養得終。", "壼彜今具在，流慶復何窮。"]'),
('946fb870-4857-463b-bd31-4e71f920336a','宜人史氏挽詞','樓鑰','宋','宋诗','song-poetry','','[]','閥閲冠三朝，尊公兩珥貂。',48,'全唐诗/poet.song.159000.json','["閥閲冠三朝，尊公兩珥貂。", "夫賢能盡禮，家貴肯期驕。", "教子門風振，澄神性地超。", "悼亡無可憾，直筆付孫樵。"]'),
('20a2c78f-1735-4bed-83ad-1eeb1be8ee7c','太令人軒氏挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','緣斷身先隠，年侵鬢未華。',48,'全唐诗/poet.song.159000.json','["緣斷身先隠，年侵鬢未華。", "死生猶曉夢，富貴更空花。", "佛祖親提印，兒孫競起家。", "無因拜靈几，一奠趙州茶。"]'),
('021b384c-dba0-41f3-ab5f-2da327f240ac','太令人軒氏挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','舊說蘇無著，夫人亦正宗。',48,'全唐诗/poet.song.159000.json','["舊說蘇無著，夫人亦正宗。", "毒蛇橫在路，栗棘更無蹤。", "蕭散超塵界，扶持禮紺容。", "覺庵誰嗣法，別去德雲峰。"]'),
('58174fe3-fe10-4d54-b412-7d88bc3e8170','宜人聞人氏挽詞','樓鑰','宋','宋诗','song-poetry','','[]','四郡歌賢牧，魚軒從隼旟。',48,'全唐诗/poet.song.159000.json','["四郡歌賢牧，魚軒從隼旟。", "深閨無裏謁，色養謹安輿。", "故里稱家法，諸郎讀父書。", "美哉彤史筆，三誦爲欷歔。"]'),
('9ed313cc-a743-474e-b894-8978f47176f6','太孺人蔣氏挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','之死靡他志，天乎不諒人。',48,'全唐诗/poet.song.159000.json','["之死靡他志，天乎不諒人。", "嫠孤蓬在首，艱苦棘成薪。", "晚福容千指，心空滅六塵。", "平生貞烈意，終作坐忘身。"]'),
('9f6cc543-885a-453c-95ea-822fa41367e2','太孺人蔣氏挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','潤屋惟純儉，居然法度循。',48,'全唐诗/poet.song.159000.json','["潤屋惟純儉，居然法度循。", "松楸先壟下，風月舊湖濱。", "子婦皆知孝，孫曾亦可人。", "浦江如可贖，真欲百其身。"]'),
('36225ff5-3ca5-480a-b9a3-1c0fc9a397b1','百四從妹挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','姊妹二十四，凋零餘二人。',48,'全唐诗/poet.song.159000.json','["姊妹二十四，凋零餘二人。", "他鄉忽傳訃，老子倍傷神。", "已歎嫠居久，何堪逆境頻。", "佳城千里外，西望淚沾巾。"]'),
('60b79c56-168a-4362-b705-6d6236f20330','百四從妹挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','孝養全終始，真成乳阿姑。',48,'全唐诗/poet.song.159000.json','["孝養全終始，真成乳阿姑。", "衾禂幾年共，甘毳四時須。", "衆子俱傳業，諸孫足自娛。", "吾家女兄弟，似此亦幾無。"]'),
('a7578fd8-cac4-45c4-92c1-27b03121cf60','百四從妹挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','去歲桐川弟，新從姊處歸。',48,'全唐诗/poet.song.159000.json','["去歲桐川弟，新從姊處歸。", "備言家慶事，猶著嫁時衣。", "尚欲尋松社，寧堪哭素幃。", "人生真一夢，回首事皆非。"]'),
('ecb1d949-2ed8-4282-af31-591fad2f1f6a','蘇江陰挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','萬卷蟠胸次，千篇秀筆端。',48,'全唐诗/poet.song.159000.json','["萬卷蟠胸次，千篇秀筆端。", "朝行期奮迅，賢路竟艱難。", "雖號循良守，欠爲文字官。", "遺編幸無恙，留與後人看。"]'),
('a892f00c-c663-4863-b3d4-e5aaa7726535','蘇江陰挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','伊昔初傾盖，摛文已甚工。',48,'全唐诗/poet.song.159000.json','["伊昔初傾盖，摛文已甚工。", "親聞南澗語，謂有魏公風。", "既往言多驗，歸來道更窮。", "誨言非教佞，後裔報宜豐。"]'),
('914a5acb-39c6-4e7a-8505-20cc26d147d8','趙縣丞挽詞','樓鑰','宋','宋诗','song-poetry','','[]','玉立佳公子，哦松始戍瓜。',48,'全唐诗/poet.song.159000.json','["玉立佳公子，哦松始戍瓜。", "拳拳飭邊瑣，寸寸畫江沙。", "慷慨志憂國，清修僧在家。", "送行詩尚濕，身世遽空華。"]'),
('b0f5174f-9fe4-4225-8c12-ae830c66e7a9','鮑潮州挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','三試皆前列，一官何後時。',48,'全唐诗/poet.song.159000.json','["三試皆前列，一官何後時。", "低佪廣文舍，齟齬使君麾。", "遇事有如燭，衛生寧及葵。", "舊游成隔世，流涕讀新碑。"]'),
('45a495f7-5e40-423f-9353-5a4e896e48b1','鮑潮州挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','客授壬辰歲，巍科盛永嘉。',48,'全唐诗/poet.song.159000.json','["客授壬辰歲，巍科盛永嘉。", "芹宮屢揮麈，竹院幾烹茶。", "假守深交誼，清談及道家。", "猶懷郡齋晚，群雀噪簷蛇。"]'),
('21846c4c-8983-4c5c-adda-db6fffeccb32','張運使挽詞','樓鑰','宋','宋诗','song-poetry','','[]','惠周劍外與淮南，歸卧空山且避讒。',64,'全唐诗/poet.song.159000.json','["惠周劍外與淮南，歸卧空山且避讒。", "宴坐幾年期不死，臨行一著信非凡。", "不應杜乂束高閣，真使謝鯤居石巖。", "欲向西陵尋宿草，秋風何日送歸帆。"]'),
('39324b6a-144d-4d3d-b9c4-e3c20e25d42a','張工部挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','忠簡傳清白，家聲屬弟昆。',48,'全唐诗/poet.song.159000.json','["忠簡傳清白，家聲屬弟昆。", "惟公殿諸老，積善見多孫。", "兩桂昌書種，雙椿藹慶門。", "壽終無可憾，况有典刑存。"]'),
('6dbfe63c-fac7-418e-a884-51df842f7619','張工部挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','壯歲登郎省，旌麾歷五州。',48,'全唐诗/poet.song.159000.json','["壯歲登郎省，旌麾歷五州。", "仁聲號循吏，治行最諸侯。", "憂國言多切，籌邊慮更周。", "積薪無恨望，終老得夷猶。"]'),
('b2e51a18-c780-4ae6-a62f-029a418a6c67','張工部挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','敕局同寅舊，雌堂屢肯過。',48,'全唐诗/poet.song.159000.json','["敕局同寅舊，雌堂屢肯過。", "故人今有幾，朝士更無多。", "問信書猶濕，相望鬢已皤。", "忽聞埋璧痛，薤露不成歌。"]'),
('82d9f907-ed01-4a49-bd7c-82b698cec6ec','戴迪功挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','猶記天街會，同爲乳竇游。',48,'全唐诗/poet.song.159000.json','["猶記天街會，同爲乳竇游。", "姻家頻會聚，親意愈綢繆。", "吉德宜多壽，奇痾竟不瘳。", "無由見安道，汎雪悵回舟。"]'),
('36690885-5429-43f1-96f0-dc07d71d3481','戴迪功挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','好學數仍奇，躬行家遂肥。',48,'全唐诗/poet.song.159000.json','["好學數仍奇，躬行家遂肥。", "時將詩自樂，晚悟世俱非。", "教子惟黄卷，高門看綠衣。", "阿連悲未泯，無淚爲君揮。"]'),
('e8d939f4-f022-4a91-ab46-e1e5b44b14ff','宜人楊氏挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','里閈依楊氏，年家託鄭門。',48,'全唐诗/poet.song.159000.json','["里閈依楊氏，年家託鄭門。", "升堂從壯歲，擇壻得賢孫。", "婦德儀中壼，陰功燕後昆。", "尤憐吾女子，流涕說慈尊。"]'),
('e8352a45-c79b-4675-a68f-9d18464d52f8','宜人楊氏挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','夢入枌榆社，心游水竹灣。',48,'全唐诗/poet.song.159000.json','["夢入枌榆社，心游水竹灣。", "丐歸期拜壽，近侍望承顔。", "一昨聞微恙，寧知竟大還。", "佳城無路到，夫婦淚俱潸。"]'),
('51894c00-6fb8-4772-bbec-685be78622ab','孺人錢氏挽詞','樓鑰','宋','宋诗','song-poetry','','[]','家世戟如林，來嬪藹德音。',48,'全唐诗/poet.song.159000.json','["家世戟如林，來嬪藹德音。", "功容俱可度，疾疹遽相侵。", "已矣空蘋澗，誰歟助藁砧。", "佳兒隨玉折，尤切悼亡心。"]'),
('45f96f44-1707-4753-8243-a2fb9630f587','齊安郡夫人金氏挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','避地供湯餠，當筵接縞衣。',48,'全唐诗/poet.song.159000.json','["避地供湯餠，當筵接縞衣。", "倉皇奉神版，巖險遜征騑。", "遇事智尤敏，相夫家寖肥。", "考終無可憾，蝶夢遶芳菲。"]'),
('70881beb-dc17-486c-aff6-c19e85ef4d49','齊安郡夫人金氏挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','五子俱英發，尤知仲氏賢。',48,'全唐诗/poet.song.159000.json','["五子俱英發，尤知仲氏賢。", "勤明真世濟，廉儉信家傳。", "別乘徑爲郡，高城欲捍邊。", "版輿俄棄養，事業待他年。"]'),
('9f599467-d599-4a98-a377-e5275a4e4c9a','太令人趙氏挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','令德比鳲鳩，芳年誓柏舟。',48,'全唐诗/poet.song.159000.json','["令德比鳲鳩，芳年誓柏舟。", "承平猶有態，曠達了無憂。", "方奉平反笑，俄成汗漫游。", "哀榮誰得似，同穴樂哉丘。"]'),
('7c07bf9c-fe4d-4dbb-b2ce-5656ef1740da','太令人趙氏挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','節愍名驚代，浮光孝絕人。',48,'全唐诗/poet.song.159000.json','["節愍名驚代，浮光孝絕人。", "宜生克家子，頼有斷機親。", "勉使方張虜，終能不帝秦。", "一杯扶上馬，孰不爲沾巾。"]'),
('36d79ffd-1b30-4d5d-bfac-c3a6185ae126','太令人趙氏挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','姻婭託三槐，同朝得往來。',48,'全唐诗/poet.song.159000.json','["姻婭託三槐，同朝得往來。", "迎春煩設席，舉壽荷携杯。", "京尹俄遭難，都人亦助哀。", "琅琅垂絕語，烈婦信高哉。"]'),
('87a6d3db-be2f-4c53-b5b2-ee46d7883466','安恭皇后挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','天作周文合，禕褕禮可觀。',48,'全唐诗/poet.song.159000.json','["天作周文合，禕褕禮可觀。", "屢陪金輦幸，幾奉玉巵歡。", "吳女簪新柰，梁房掩舊蘭。", "春深蠶事起，誰復上桑壇。"]'),
('47a447aa-4735-4fa1-a607-0e7523d64765','安恭皇后挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','鬰鬰南山路，傷心鳳翣紅。',48,'全唐诗/poet.song.159000.json','["鬰鬰南山路，傷心鳳翣紅。", "哀歌凄薤露，秘殿掩椒風。", "故劍恩雖厚，中璫事已空。", "但餘彤史筆，內傳紀陰功。"]'),
('70a14da8-e263-4c5e-8289-2b2ad5b9c83f','安恭皇后挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','玉勝標祥兆，禕衣配至尊。',48,'全唐诗/poet.song.159000.json','["玉勝標祥兆，禕衣配至尊。", "柔儀高馬鄧，盛德邁娀嫄。", "鸞掖空陳迹，霓軒服厚恩。", "傷心臨七夕，素柰已花繁。"]'),
('e42b5743-e4b5-4e9c-9b06-ad24b75e5970','安恭皇后挽詞  其四','樓鑰','宋','宋诗','song-poetry','','[]','圖史懷規鑒，篇章妙剪裁。',48,'全唐诗/poet.song.159000.json','["圖史懷規鑒，篇章妙剪裁。", "承歡方祕殿，委化已泉臺。", "幽壤湖濱秀，清笳日暮哀。", "未央當月望，不見翟車來。"]'),
('a3e935f4-1ba8-4c72-bd92-b9bbd755bd45','楊武恭王挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','歷數中興將，誰爲第一功。',48,'全唐诗/poet.song.159000.json','["歷數中興將，誰爲第一功。", "兩朝忠衛上，四海雅推公。", "富貴無危溢，哀榮有始終。", "吾知尚遺恨，不見朔庭空。"]'),
('5d4e010b-e962-4e94-92ad-89389a0dcfae','楊武恭王挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','勇氣真虓虎，仁心劇放麑。',48,'全唐诗/poet.song.159000.json','["勇氣真虓虎，仁心劇放麑。", "推鋒多折馘，解縛屢招携。", "細柳門堅閉，長楊馬不嘶。", "夜深星忽墮，何處問撐犁。"]'),
('49d3642b-e256-43f1-962a-106534cb6285','楊武恭王挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','父祖成完節，丹心激懦夫。',48,'全唐诗/poet.song.159000.json','["父祖成完節，丹心激懦夫。", "枕戈梟逆虜，撫劍志伊吾。", "忠孝公何媿，哀榮世所無。", "從今紫荷橐，接武上亨衢。"]'),
('64b11f63-229e-414b-8c7d-5a7df544398e','楊武恭王挽詞  其四','樓鑰','宋','宋诗','song-poetry','','[]','王爵報元勳，臨危更致身。',48,'全唐诗/poet.song.159000.json','["王爵報元勳，臨危更致身。", "鯨波飛戰艦，狼子歎江神。", "木落淮南暮，塵清塞外春。", "功臣誰第一，圖畫在麒麟。"]'),
('62d4aaa3-9f4d-4242-ac78-469c8bb8c60c','陳文恭公挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','唐虞千載道重光，奕奕元臣任贊襄。',64,'全唐诗/poet.song.159000.json','["唐虞千載道重光，奕奕元臣任贊襄。", "謝傅風流冠江左，晉公威譽比汾陽。", "折衝曾不勞聲色，輔政惟先振紀綱。", "天意高高誰可問，坐令邦國歎云亡。"]'),
('fd73d324-3666-44ae-89af-e6a9ae158157','陳文恭公挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','德量汪汪萬頃陂，直將去就佩安危。',64,'全唐诗/poet.song.159000.json','["德量汪汪萬頃陂，直將去就佩安危。", "干戈雖在相尋日，休沐宛如無事時。", "奏罷未聞宮漏轉，歸來俄見哲人萎。", "哀榮終始誰能及，百世旌忠頌德碑。"]'),
('a9da4e88-917b-4d49-87ad-3109456f0545','陳文恭公挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','輔贊藏諸用，庸人自擾之。',48,'全唐诗/poet.song.159000.json','["輔贊藏諸用，庸人自擾之。", "惟公知好靜，與物盡忘私。", "德望儀群辟，威名憺遠夷。", "傷心白雞夢，梁木有餘悲。"]'),
('e14fd236-0dc3-43e4-9f33-ab0cc446805e','陳文恭公挽詞  其四','樓鑰','宋','宋诗','song-poetry','','[]','致主唐虞上，東山志不渝。',48,'全唐诗/poet.song.159000.json','["致主唐虞上，東山志不渝。", "衮衣重入覲，胡騎敢長驅。", "夢已商楹奠，朝猶漢殿趨。", "哀榮極終始，何止渡江無。"]'),
('c38d5cdc-f7a2-4a65-af5d-541c58a5d3da','何內翰挽詞','樓鑰','宋','宋诗','song-poetry','','[]','豪奪錦標天下聞，慨然有志整乾坤。',64,'全唐诗/poet.song.159000.json','["豪奪錦標天下聞，慨然有志整乾坤。", "諫坡論事言皆合，帝幄談經道益尊。", "千古高文在鼇禁，一時名士上龍門。", "經綸未究身先死，痛惜誰能作九原。"]'),
('cdea22e6-341b-4b46-ad29-c4d132c24f0c','姜祕監挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','文筆無勞巧剪裁，一時妙斲冠蘭臺。',64,'全唐诗/poet.song.159000.json','["文筆無勞巧剪裁，一時妙斲冠蘭臺。", "王楊仕宦曾相接，游夏淵源有自來。", "治獄心知有陰德，立朝人嘆有餘才。", "功名回施與孫子，公亦何爲不豫哉。"]'),
('96e205b7-f87d-4a02-b932-048ea9af33d6','姜祕監挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','久聞政績最淮淝，鄮嶺循良親見之。',64,'全唐诗/poet.song.159000.json','["久聞政績最淮淝，鄮嶺循良親見之。", "梓里尚遺前日愛，棠陰還長舊年枝。", "釣璜方兆非熊卜，曳杖俄興梁木悲。", "千里佳城空望斷，他時歸哭峴山碑。"]'),
('6725f511-12d8-4eee-a0e5-483961510635','許待制挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','吏事緣儒術，人材第一流。',48,'全唐诗/poet.song.159000.json','["吏事緣儒術，人材第一流。", "宦游幾五紀，遺愛滿諸州。", "叱馭無長阪，籌邊有舊樓。", "遺安陰德在，衮衮見公侯。"]'),
('ae11ca71-69b4-437d-8cc8-4356d0c23b36','許待制挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','蚤擅文章價，名公屢品題。',48,'全唐诗/poet.song.159000.json','["蚤擅文章價，名公屢品題。", "碑銘摹諫省，丘壑訪愚溪。", "得句追飛兔，摛毫走怒猊。", "遺編聞好在，後學仰筌蹄。"]'),
('b0b804e9-7c7e-4df7-841a-efa8b2133c69','許待制挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','十載更麾節，陽春萬里同。',48,'全唐诗/poet.song.159000.json','["十載更麾節，陽春萬里同。", "時時逢蜀士，一一話文翁。", "到處留遺愛，諸郎守教忠。", "慶源知未艾，往日有陰功。"]'),
('2edce95d-9bb9-4477-8661-6e8763efe0db','唐舍人挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','鴈塔名三世，螭蚴侍九重。',48,'全唐诗/poet.song.159000.json','["鴈塔名三世，螭蚴侍九重。", "循循儀學館，諤諤著囊封。", "至性悲三釜，高懷薄萬鍾。", "典刑傷不見，衰涕忽無從。"]'),
('3989e093-fde1-476c-a1c6-60a239649156','唐舍人挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','夷路方馳轡，甘泉喜問津。',48,'全唐诗/poet.song.159000.json','["夷路方馳轡，甘泉喜問津。", "廟廊平日志，露電百年身。", "搯掌雖多恨，爲箕自有人。", "發棠陰德在，陽報質蒼旻。"]'),
('56752df3-8f66-456b-b419-6d953cde8209','李公執挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','乃翁志欲卧煙霞，宅枕清江欲泛槎。',64,'全唐诗/poet.song.159000.json','["乃翁志欲卧煙霞，宅枕清江欲泛槎。", "心地共知容渤澥，夢魂曾不到京華。", "伯魚久已聞賢訓，魏子端能起外家。", "瀰望三江梁下水，隴西德澤信無涯。"]'),
('d6d5ceba-492a-49b1-b77f-ed0d3a38404a','李公執挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','未甘辛苦去朝天，故作逍遥陸地仙。',64,'全唐诗/poet.song.159000.json','["未甘辛苦去朝天，故作逍遥陸地仙。", "老子平生萬事足，人間五福一身全。", "厭看日月同奔驥，擺脫塵煩等蛻蟬。", "重到江頭人不見，曉風吹淚忽潸然。"]'),
('5a584ed6-660b-4652-829c-02d261f606c0','呂崇德挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','剸劇推才刃，臨機妙斲輪。',48,'全唐诗/poet.song.159000.json','["剸劇推才刃，臨機妙斲輪。", "傳家得清白，滿腹是精神。", "未上金閨籍，空留花縣春。", "善人陽報在，蘭玉正詵詵。"]'),
('ab831a53-71e2-4451-a77f-6b8fc3d781a4','呂崇德挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','回首情親處，相過瀨水陽。',48,'全唐诗/poet.song.159000.json','["回首情親處，相過瀨水陽。", "十年能幾見，一疾痛云亡。", "縣郭山空秀，家園橘自霜。", "主人今已矣，鷗鷺亦淒涼。"]'),
('74d8f1dd-514d-4304-8c33-330333fe6d20','王縣尉挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','幹蠱恢才刃，誰能貨殖私。',48,'全唐诗/poet.song.159000.json','["幹蠱恢才刃，誰能貨殖私。", "人皆競毫髮，我獨破藩籬。", "風雨空殘夢，池臺愴昔時。", "板輿臨穴處，行道亦興悲。"]'),
('2f1db788-eb18-4dba-8da9-e89037f2acc9','王縣尉挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','潤屋公餘事，能爲人所難。',48,'全唐诗/poet.song.159000.json','["潤屋公餘事，能爲人所難。", "蓼莪遺恨在，夜雨舊盟寒。", "家有書堪讀，囊無錢爲看。", "情親悲不那，望絕旐飛丹。"]'),
('54b98dc6-c50d-4512-927d-1100096afbb5','潘大卿挽詞','樓鑰','宋','宋诗','song-poetry','','[]','直上青雲不作難，壯年何事掛衣冠。',64,'全唐诗/poet.song.159000.json','["直上青雲不作難，壯年何事掛衣冠。", "功名已矣乖時望，風節翹然見歲寒。", "鴻去冥冥矰不到，蝶飛栩栩夢驚殘。", "傷心耆老今無有，留得遺編向後看。"]'),
('beadbcf6-4db5-4b7c-a9c9-73d292427efa','樊運使挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','妙齡便有老成風，孝友丹心天與通。',64,'全唐诗/poet.song.159000.json','["妙齡便有老成風，孝友丹心天與通。", "師友淵源得西洛，文章聲價冠南宮。", "固知夫子才難用，猶喜先生道不窮。", "他日鳳泉山下路，幾人下馬拜塋中。"]'),
('8fa39ab0-2ea0-4bdb-9de7-e5466d8a602a','樊運使挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','樊侯勳德佐中興，百世兒孫尚典刑。',64,'全唐诗/poet.song.159000.json','["樊侯勳德佐中興，百世兒孫尚典刑。", "闔境民蘇御史雨，列城人仰使君星。", "憲臺嚴冷獨峩豸，道院清閑誰掣鈴。", "謠頌洋洋在人耳，不須樂石更刊銘。"]'),
('de44fc8d-fd31-4a06-b6f4-2d821c4f722e','樊運使挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','科目公餘事，南宮第一人。',48,'全唐诗/poet.song.159000.json','["科目公餘事，南宮第一人。", "七閩新使節，三署舊儒臣。", "倦拜方辭餽，哀良莫贖身。", "家聲知有繼，仙桂兩枝春。"]'),
('d6d2f1f8-966b-4b50-8886-11ed22954fa3','樊運使挽詞  其四','樓鑰','宋','宋诗','song-poetry','','[]','橫浦云亡後，斯文付此賢。',48,'全唐诗/poet.song.159000.json','["橫浦云亡後，斯文付此賢。", "命其隨道喪，學又絕心傳。", "河洛湮來派，西州憶舊緣。", "傷心耆老盡，揮淚對霜天。"]'),
('76be006a-29b1-4b82-a9cb-33e103c32b5f','莫將仕挽詞','樓鑰','宋','宋诗','song-poetry','','[]','自歎清才久陸沉，晚從內典用工深。',64,'全唐诗/poet.song.159000.json','["自歎清才久陸沉，晚從內典用工深。", "諦觀烱烱死生際，寧復紛紛利祿心。", "載酒今誰問奇字，遺經古亦勝黄金。", "十年契闊遽如許，老淚臨風自不禁。"]'),
('d5b93d7a-7f46-43e2-88ca-5d777a3a0005','伍主簿挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','好賢元不減緇衣，客到公家如所歸。',64,'全唐诗/poet.song.159000.json','["好賢元不減緇衣，客到公家如所歸。", "二浙聲名三鶚薦，四山風物一翬飛。", "桑榆冉冉身先蛻，蘭玉森森家正肥。", "人有百身寧可贖，發棠誰復濟齊饑。"]'),
('79492f3d-fd77-4d1d-a50e-ed58f1960348','伍主簿挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','由來風誼獨穹然，坐享家肥不計年。',64,'全唐诗/poet.song.159000.json','["由來風誼獨穹然，坐享家肥不計年。", "墮幘何妨分百萬，指囷寧復問三千。", "靈椿老去仁宜壽，玉樹種成身已仙。", "衮衮公侯殊未已，正應含笑入重泉。"]'),
('ab1ff16d-a6da-42ad-9c51-511e39c553c3','伍主簿挽詞  其三','樓鑰','宋','宋诗','song-poetry','','[]','晚年朋舊益彫零，歎絕斯人奠兩楹。',64,'全唐诗/poet.song.159000.json','["晚年朋舊益彫零，歎絕斯人奠兩楹。", "不忍銜悲讀佳傳，可堪回首念平生。", "交情君獨全終始，人物誰能繼老成。", "清些楚魂招不得，朔風淒切淚縱橫。"]'),
('7c83b55a-21c6-477f-a619-97f6c27acce4','梁審計挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','壯歲嶄頭角，夷塗試著鞭。',48,'全唐诗/poet.song.159000.json','["壯歲嶄頭角，夷塗試著鞭。", "羣公爭倒屣，諸老亦忘年。", "論議傾朝譽，功名短世緣。", "神傷賢伯仲，風雨夜無眠。"]'),
('90f0fa0c-6ddd-4cd3-9d9b-527cfc45c1cb','梁審計挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','壽夭固難問，吁嗟不忍言。',48,'全唐诗/poet.song.159000.json','["壽夭固難問，吁嗟不忍言。", "嬰啼摧玉樹，衰淚灑芳萱。", "事契深羣從，英才愴九原。", "悲吟慙楚些，無地與招魂。"]'),
('aec7b4fc-6b62-460a-8439-c998cf2fb761','太淑人管氏挽詞','樓鑰','宋','宋诗','song-poetry','','[]','彤史久不作，誰能有婦功。',48,'全唐诗/poet.song.159000.json','["彤史久不作，誰能有婦功。", "寧知貴家子，乃有昔人風。", "鈿軸恩何渥，芝庭澤不窮。", "死生無可憾，况已悟真空。"]'),
('ca8c0b47-ed0f-4fa0-afd6-6a49eab37a64','陳夫人挽詞','樓鑰','宋','宋诗','song-poetry','','[]','作配知名士，周旋內則篇。',48,'全唐诗/poet.song.159000.json','["作配知名士，周旋內則篇。", "宜家兼四德，訓子見三遷。", "就養榮方逮，歸寧病忽纏。", "慶源流未已，佳兆得牛眠。"]'),
('2cc4929c-140e-4597-907c-1c2a777febb3','陸參議挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','中外衣冠盛，流傳識後凋。',48,'全唐诗/poet.song.159000.json','["中外衣冠盛，流傳識後凋。", "聲名三語掾，身世半僧寮。", "寶晉書尤逸，坡仙隠可招。", "梅溪殘月墮，蕪沒舊風標。"]'),
('15dc7b71-0aee-49b1-b17b-7be294142bb7','陸參議挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','飾吏先儒雅，低徊五十霜。',48,'全唐诗/poet.song.159000.json','["飾吏先儒雅，低徊五十霜。", "萑蒲掃韶石，桑柘滿黄岡。", "知己平津老，傳家刪定郎。", "八龍無半在，風雨夜侵床。"]'),
('b3128998-6dca-4751-b6d1-0c60597b699d','李堯卿挽詞','樓鑰','宋','宋诗','song-poetry','','[]','里社久相從，知君陰有功。',48,'全唐诗/poet.song.159000.json','["里社久相從，知君陰有功。", "救人多藥喜，持論耻雷同。", "素業諸郎在，浮生一夢空。", "淒涼宋清傳，健筆媿河東。"]'),
('fe8ffabb-8561-47ce-92ac-c55fd1a173f7','周左司挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','從政心無媿，敢言人所難。',48,'全唐诗/poet.song.159000.json','["從政心無媿，敢言人所難。", "精忠憂世切，清節照人寒。", "交臂失持橐，乞身終考槃。", "老成今已矣，西望涕汍瀾。"]'),
('1957197a-672f-4f72-ab6d-02e592c5c800','周左司挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','乙丑慈恩會，今幾六十霜。',48,'全唐诗/poet.song.159000.json','["乙丑慈恩會，今幾六十霜。", "軺車來握節，相府記傳觴。", "詩藪懷高隠，郵筒見短章。", "不堪千里隔，丹旐想飛揚。"]'),
('96c79457-7fff-4bec-a7ec-f549fc34c02b','王夷仲夫人挽詞','樓鑰','宋','宋诗','song-poetry','','[]','彤史無人續，誰能識壼彜。',48,'全唐诗/poet.song.159000.json','["彤史無人續，誰能識壼彜。", "蘋蘩奉先祖，詩禮付佳兒。", "未見魚軒樂，俄興鸞鏡悲。", "藁砧方得路，腸斷悼亡詩。"]'),
('1efed311-1f6f-49a6-9469-a22fe7e7f2c9','陳夫人挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','族姓甲休陽，夫人懿範彰。',48,'全唐诗/poet.song.159000.json','["族姓甲休陽，夫人懿範彰。", "奇男已南省，快婿更東床。", "珍錫人加嘆，佳城神所藏。", "平生陰德在，餘慶尚難量。"]'),
('98729afa-b677-4103-a9dc-ddaa5b0f2667','陳夫人挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','雅有幽閒操，來嬪清白家。',48,'全唐诗/poet.song.159000.json','["雅有幽閒操，來嬪清白家。", "相夫全禮敬，見子致清華。", "方享乘軒樂，俄興陟屺嗟。", "誰將彤史紀，大筆爲雄誇。"]'),
('5059f271-1878-48c3-808d-66f7821bbbcb','茅夫人挽詞','樓鑰','宋','宋诗','song-poetry','','[]','清心玉映許誰同，更有飄飄林下風。',64,'全唐诗/poet.song.159000.json','["清心玉映許誰同，更有飄飄林下風。", "政爾高情協宗老，故宜嘉遯樂龐公。", "遠謀蚤識身爲重，晚境還知性亦空。", "已擬張林碑婦德，合歸彤史巨編中。"]'),
('10add161-e826-496f-a782-6e4bcb37e5aa','張夫人挽詞','樓鑰','宋','宋诗','song-poetry','','[]','婦德天然備，肥家五十年。',48,'全唐诗/poet.song.159000.json','["婦德天然備，肥家五十年。", "平生勤內則，晚歲識真詮。", "倒廩非徼福，翻經亦應緣。", "于門有孫子，佳氣藹新阡。"]'),
('c0ba9b01-e245-46ad-bd54-5065b0e915e4','王修撰挽詞  其一','樓鑰','宋','宋诗','song-poetry','','[]','十載頻褰刺史帷，名卿風裁映紳緌。',64,'全唐诗/poet.song.159000.json','["十載頻褰刺史帷，名卿風裁映紳緌。", "慶門共仰聯三鳳，禁路咸嗟欠一夔。", "神武衣冠終遂志，平泉花木總成詩。", "傷心積翠樓前月，斜入欄干欲向誰。"]'),
('ae8f22f5-b002-4b91-81ab-70e6c68005e3','王修撰挽詞  其二','樓鑰','宋','宋诗','song-poetry','','[]','賤子何能直一錢，夫君於我獨知憐。',64,'全唐诗/poet.song.159000.json','["賤子何能直一錢，夫君於我獨知憐。", "樽罍談笑幾侵夜，琴劍周旋不計年。", "此去空懸徐孺榻，重來無復孝廉船。", "百身願贖嗟何及，衰涕滿襟如迸泉。"]'),
('8095c1a2-74d4-4aac-b5dd-480ed159486d','雙峰二偈  其一','樓鑰','宋','宋诗','song-poetry','','[]','莫把資深兩處尋，此心心外更無心。',32,'全唐诗/poet.song.159000.json','["莫把資深兩處尋，此心心外更無心。", "道人欲問資深話，自得元無古與今。"]'),
('24218f11-217a-4627-a2b1-436fa977d7ef','雙峰二偈  其二','樓鑰','宋','宋诗','song-poetry','','[]','道非身外亦非中，左右逢原作麽逢。',32,'全唐诗/poet.song.159000.json','["道非身外亦非中，左右逢原作麽逢。", "遶寺尋山無好處，不知門外有雙峰。"]'),
('13422179-7eb1-4bdd-ae0b-4c5d3adcdd84','新昌石佛','樓鑰','宋','宋诗','song-poetry','','[]','費盡三生心與力，造成石像一百尺。',64,'全唐诗/poet.song.159000.json','["費盡三生心與力，造成石像一百尺。", "相好端嚴具足尊，五彩黄金妙裝飾。", "道不是佛却不得，若道便是也不得。", "上盡層樓却下來，何曾見得真彌勒。"]'),
('237c4e03-039e-4de2-9a55-0d991721828b','遊金焦兩山以雨而輟','樓鑰','宋','宋诗','song-poetry','','[]','金山寺裹山，焦山山裹寺。',24,'全唐诗/poet.song.159000.json','["金山寺裹山，焦山山裹寺。", "風雨勸我歸，也省兩頭事。"]'),
('fb0fc130-79ec-44e5-af05-5deebf457ab7','跋惠峰詢老所編類海','樓鑰','宋','宋诗','song-poetry','','[]','古德手段決裂，剝地破{絕/方}地折。',60,'全唐诗/poet.song.159000.json','["古德手段決裂，剝地破{絕/方}地折。", "說道不立文字，未免橫說豎說。", "草庵文字太多，只爲老婆心切。", "若不作恁麽看，將謂多口饒舌。"]'),
('2a420905-3659-4556-972e-3a9c2689472e','題老融畫彌勒','樓鑰','宋','宋诗','song-poetry','','[]','乘風欲去東南，回頭此意誰參。',28,'全唐诗/poet.song.159000.json','["乘風欲去東南，回頭此意誰參。", "當時蹉過足庵，却來攻媿同龕。"]'),
('eaaeaf8b-2aa1-4bf0-b610-17d005c07dbf','西山僅老失牛求一言於邑宰數語代書','樓鑰','宋','宋诗','song-poetry','','[]','一介扣門，尺書在手。',138,'全唐诗/poet.song.159000.json','["一介扣門，尺書在手。", "不是長鬚饋鯉，乃知中夜忘牛。", "拽杷牽犁，能耕百畝。", "披毛戴角，方得五春。", "是何西山之餓夫，輒挽桃林之處士。", "拽轉鼻孔，不解一鳴。", "剖破藩籬，已行十里。", "莫走溈山舊話，重修雪竇新圖。", "解若庖丁，恐遭游刃。", "鄔如謝大，且自煖心。", "見角便知，必有伶俐衲子。", "幪頭徑取，更煩明正官司。"]'),
('f329f337-fefb-4a11-8758-b50020cb5b66','戲贈怡雲平老','樓鑰','宋','宋诗','song-poetry','','[]','深山中拔出閑身，閙市裏尋得靜處。',64,'全唐诗/poet.song.159000.json','["深山中拔出閑身，閙市裏尋得靜處。", "相逢了白話三通，那箇是末後一句。", "不因聞所聞而來，不爲見所見而去。", "嶺上白雲君自怡，何時許得同龕住。"]'),
('06421e08-cf37-4c92-b31a-3da82bef33b5','送清道者住投子山','樓鑰','宋','宋诗','song-poetry','','[]','一鉢一衲，一丘一壑。',36,'全唐诗/poet.song.159000.json','["一鉢一衲，一丘一壑。", "非去非住，無相無作。", "一脚踏著投子機，不被傍人輕摸索。"]'),
('55790772-5af2-4ff6-bf0b-4f2c6766a1ed','戲題珪老借菴  其一','樓鑰','宋','宋诗','song-poetry','','[]','莫道菴子是借底，只你也是借將來。',32,'全唐诗/poet.song.159000.json','["莫道菴子是借底，只你也是借將來。", "勸君莫作來生債，盡底還他亦快哉。"]'),
('51c07038-315e-4f1a-966c-b9a9eef69cc5','戲題珪老借菴  其二','樓鑰','宋','宋诗','song-poetry','','[]','不知當初問誰借，至今久假而不歸。',32,'全唐诗/poet.song.159000.json','["不知當初問誰借，至今久假而不歸。", "畢竟還了方是了，却須還我未生時。"]'),
('60059d1c-91a3-4b6c-9269-e7e8ce2a00d9','次仲舅韵寄拙菴  其一','樓鑰','宋','宋诗','song-poetry','','[]','涵秋古澗落珠旒，幾欲相將作勝遊。',32,'全唐诗/poet.song.159000.json','["涵秋古澗落珠旒，幾欲相將作勝遊。", "芒屩未穿心已懶，不如莫莫且休休。"]'),
('81b885bd-7a86-47ed-9c56-accdf51ca9d4','次仲舅韵寄拙菴  其二','樓鑰','宋','宋诗','song-poetry','','[]','明月堂前玉几山，倦游雙徑却來還。',32,'全唐诗/poet.song.159000.json','["明月堂前玉几山，倦游雙徑却來還。", "舅甥相與成三隠，城郭山林等是閑。"]'),
('5ae67f8d-0d53-4323-a638-3e74b9f90100','次仲舅韵寄拙菴  其三','樓鑰','宋','宋诗','song-poetry','','[]','公居山外我城中，不見成疎見亦空。',32,'全唐诗/poet.song.159000.json','["公居山外我城中，不見成疎見亦空。", "要是歸來當一見，待携藜杖訪支公。"]'),
('0e544fdd-8ccf-4679-8b33-0a2c13b4909e','次仲舅韵寄拙菴  其四','樓鑰','宋','宋诗','song-poetry','','[]','莫把坐忘成坐馳，歸來須是識真歸。',32,'全唐诗/poet.song.159000.json','["莫把坐忘成坐馳，歸來須是識真歸。", "壺籌投盡無人拾，澹坐藤牀風掩扉。"]'),
('a839bd0b-335e-4dd1-942b-889eae722e82','送雪竇璧老住雪峰','樓鑰','宋','宋诗','song-poetry','','[]','雪竇移將住雪峰，兩山雪色本皆同。',32,'全唐诗/poet.song.159000.json','["雪竇移將住雪峰，兩山雪色本皆同。", "莫言此去人千里，明月往來含太空。"]'),
('d2af725c-b5f2-454c-aef7-c09eb15d49d2','游雪竇雙塔登雲簷有懷海印雲老','樓鑰','宋','宋诗','song-poetry','','[]','來禮二師遺像，小立雲簷一餉。',28,'全唐诗/poet.song.159000.json','["來禮二師遺像，小立雲簷一餉。", "欲見德雲比丘，却在別峰頂上。"]'),
('a1fc80d4-1504-4c3a-ab6b-0798cfde9de0','金峨本老領優婆塞衆求寫選僧堂三大字示以數語','樓鑰','宋','宋诗','song-poetry','','[]','行者堂中選僧，衆僧堂中選佛。',97,'全唐诗/poet.song.159000.json','["行者堂中選僧，衆僧堂中選佛。", "人道是，我却不。", "不如莫待僧伽梨，便與豎起脊梁骨。", "大丈夫，休汩沒。", "一粒爆起冷灰豆，十分鈍似遼天鶻。", "赤脚踏透祖師關，神錐擊碎精靈窟。", "君不見盧能只在碓坊前，解道本來無一物。"]'),
('0c4e9145-feab-40d8-ad66-62f239a722da','題壽居仁獨說圖','樓鑰','宋','宋诗','song-poetry','','[]','向來八萬四千偈，舌端辯才若翻水。',64,'全唐诗/poet.song.159000.json','["向來八萬四千偈，舌端辯才若翻水。", "山空月落說向誰，不如出口入吾耳。", "當時受者亡是公，烏有先生子虛子。", "我却曾見語錄來，祇有空空數張紙。"]'),
('0c0376e9-f0de-4ae5-8d6c-82b2e4ca83c3','題壁老笑菴','樓鑰','宋','宋诗','song-poetry','','[]','笑甚底，笑甚底，若要笑時笑殺你。',60,'全唐诗/poet.song.159000.json','["笑甚底，笑甚底，若要笑時笑殺你。", "說夢夢中，洗泥泥裏。", "頭上安頭，以水濟水。", "箇箇一般，滔滔皆是。", "我也要笑來，終不欲開唇露齒。"]'),
('b4c801a0-a94f-460e-94ca-25ea15cb4325','題宏老空谷','樓鑰','宋','宋诗','song-poetry','','[]','君看空谷自然空，聲有洪纖應則同。',32,'全唐诗/poet.song.159000.json','["君看空谷自然空，聲有洪纖應則同。", "正爲中虛聲自應，莫將應處做神通。"]'),
('58e7e7f9-c0e2-4dba-9f47-cae241e5f1cc','昕老自號鑑堂來住蘆山山中先有鑑堂','樓鑰','宋','宋诗','song-poetry','','[]','鑑堂來住鑑堂中，兩鑑相磨只一同。',32,'全唐诗/poet.song.159000.json','["鑑堂來住鑑堂中，兩鑑相磨只一同。", "要是非臺亦非鑑，但見寂照含虛空。"]'),
('8baa59b2-fad0-48fe-b04c-5b6948c651ba','跋塗毒與惠老偈','樓鑰','宋','宋诗','song-poetry','','[]','我銘師塔，而不識面。',40,'全唐诗/poet.song.159000.json','["我銘師塔，而不識面。", "一瞻頂相，爛爛巖電。", "橫說豎說，不待饒舌。", "塗毒一聲，百獸腦裂。"]'),
('ae17e052-efb1-4263-95eb-cece4b88ea8d','次韵伯父與心聞偈','樓鑰','宋','宋诗','song-poetry','','[]','法器何妨待晚成，一朝點鐵便成金。',64,'全唐诗/poet.song.159000.json','["法器何妨待晚成，一朝點鐵便成金。", "拽開鼻孔力無限，坐斷舌頭功更深。", "揚子江頭言在耳，靈山會上笑傳心。", "自憐鈍置無香氣，四十年來只似今。"]'),
('fb5c00a0-0ab0-4af0-9af6-dbc3b49bed4a','汪耐翁以最首座十玄談見示','樓鑰','宋','宋诗','song-poetry','','[]','十首玄談已贅疣，勞君頭上更安頭。',32,'全唐诗/poet.song.159000.json','["十首玄談已贅疣，勞君頭上更安頭。", "若還又有九百漢，葛藤相纏幾時休。"]'),
('8b26ecd8-f425-428a-ab3c-5966d93b5c91','題龍眠畫西域聖僧','樓鑰','宋','宋诗','song-poetry','','[]','放兩不借疊雙足，自在在心機在目。',32,'全唐诗/poet.song.159000.json','["放兩不借疊雙足，自在在心機在目。", "默然深入不二門，不知師唱誰家曲。"]'),
('09a3fed2-386c-4029-98cb-efc00887de11','戲答益老寄方竹杖','樓鑰','宋','宋诗','song-poetry','','[]','家家竹杖只圓光，此竹如何得許方。',43,'全唐诗/poet.song.159000.json','["家家竹杖只圓光，此竹如何得許方。", "削得團欒無可笑，驀然奪去亦何妨。", "咄哉，得力處不在這箇。"]'),
('12edf245-ef88-4f76-96bd-bc4c6e414b65','答東山一老二偈  其一','樓鑰','宋','宋诗','song-poetry','','[]','即心是佛本無難，挫却絲毫隔萬山。',32,'全唐诗/poet.song.159000.json','["即心是佛本無難，挫却絲毫隔萬山。", "知有毗盧五千卷，誰能分寸費躋攀。"]'),
('8285ed0e-426f-481b-a44f-fb9d8be7ae48','答東山一老二偈  其二','樓鑰','宋','宋诗','song-poetry','','[]','閉門深坐日知味，無限好山都懶游。',32,'全唐诗/poet.song.159000.json','["閉門深坐日知味，無限好山都懶游。", "城裏山中俱是隠，江湖不若兩忘休。"]'),
('67d76be2-1c0d-41c2-b301-1c8298cc8782','送一老住廬山歸宗  其一','樓鑰','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','久向東山捲藏經，鬼神推出舉軍驚。',32,'全唐诗/poet.song.159000.json','["久向東山捲藏經，鬼神推出舉軍驚。", "從來要去廬山住，好就山中過此生。"]'),
('242fd144-ebbd-4ab3-98cc-058442d31816','送一老住廬山歸宗  其二','樓鑰','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','啐啄同時不偶然，史君提起正當年。',32,'全唐诗/poet.song.159000.json','["啐啄同時不偶然，史君提起正當年。", "向來閙市難行道，今日人天聽說禪。"]'),
('ce71331a-c6ca-47f1-b0ec-430f29ac9e69','送一老住廬山歸宗  其三','樓鑰','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','千古名山大道場，止因賦重遂荒涼。',32,'全唐诗/poet.song.159000.json','["千古名山大道場，止因賦重遂荒涼。", "後之君子誰能弛，試向山前問老蒼。"]'),
('fee572f9-bfae-4347-a1ee-104242b04099','送一老住廬山歸宗  其四','樓鑰','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','歸宗法窟寖湮微，拭眼餘風靡孑遺。',32,'全唐诗/poet.song.159000.json','["歸宗法窟寖湮微，拭眼餘風靡孑遺。", "法鼓一聲精彩變，要如光弼用軍時。"]'),
('4d385ab1-4944-4060-99c7-a0caec4537c2','送一老住廬山歸宗  其五','樓鑰','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山面目非難識，橫嶺側峰皆是真。',32,'全唐诗/poet.song.159000.json','["廬山面目非難識，橫嶺側峰皆是真。", "若待出來方識破，不知何用箇中人。"]'),
('e8a52ec4-b59a-4bda-8add-d1fe5fa48472','題庠老頤菴','樓鑰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','下震上艮，下動上止。',102,'全唐诗/poet.song.159000.json','["下震上艮，下動上止。", "分明兩片口脣，包著許多牙齒。", "禍自此出，故以言語爲戒。", "病自此入，故以飲食爲忌。", "庠者養也，頤者養也。", "名庠而住頤菴，知他養箇甚底。", "直待吞却栗棘蓬，更與吸盡西江水。", "莫問這邊那邊，都是一箇道理。"]'),
('69fe822e-44d0-46c3-ac19-466895baeab5','題慈溪張氏坐化頌','樓鑰','宋','宋诗','song-poetry','','[]','苦是自苦，有誰縛汝。',36,'全唐诗/poet.song.159000.json','["苦是自苦，有誰縛汝。", "礙是自礙，非身爲害。", "既知一物本來無，何待行時方自在。"]'),
('d7a23132-3e02-45cb-98d1-823f6e993176','書全無用語錄','樓鑰','宋','宋诗','song-poetry','','[]','全公無用，無用之用。',85,'全唐诗/poet.song.159000.json','["全公無用，無用之用。", "生前已自無用，死後葛藤何用。", "雖然如是，善用者必自有用，不善用者不如勿用。", "試問大衆，如何則爲善用。", "有時拈起一枝草作丈六金身，有時把丈六金身却作一枝草用。"]'),
('ff3927de-c954-45a3-8196-c0430c467529','跋正法眼藏','樓鑰','宋','宋诗','song-poetry','','[]','正法眼藏當時滅却，那得許多落落索索。',80,'全唐诗/poet.song.159000.json','["正法眼藏當時滅却，那得許多落落索索。", "問著則差，答著則錯。", "喝也喝不住，棒也打不著。", "妙喜更得工夫，時與下箇注脚。", "休休休，莫莫莫。", "若要拈花微笑底事，不二法門也低一著。"]'),
('4e4ea4a0-3f75-43f6-bca5-430f71c47f5a','殘月如新月詩','樓鑰','宋','宋诗','song-poetry','','[]','近晦月猶在，蕭騷夜向晨。',72,'全唐诗/poet.song.159000.json','["近晦月猶在，蕭騷夜向晨。", "已殘幾欲盡，忽見恍如新。", "老桂沈清影，餘輝釦半輪。", "纖纖兩頭玉，皎皎一鈎銀。", "明似哉生際，光疑太逼真。", "粧樓誰起早，深拜誤佳人。"]'),
('7d701e00-ac77-4972-9c78-484697bf5957','炙背俯晴軒詩','樓鑰','宋','宋诗','song-poetry','','[]','炙背情方適，融霜日正暾。',72,'全唐诗/poet.song.159000.json','["炙背情方適，融霜日正暾。", "何妨憑曲几，相與俯晴軒。", "愛景欣亭午，閑身得負暄。", "映簷成白醉，挾纊謝奇溫。", "豈止寬寒色，猶思奉至尊。", "桃花滿肌骨，佳句憶王孫。"]'),
('91140faa-184a-4874-ad31-613c6139385d','置酒沛宮詩','樓鑰','宋','宋诗','song-poetry','','[]','漢祖功成後，時因過沛宮。',72,'全唐诗/poet.song.159000.json','["漢祖功成後，時因過沛宮。", "還鄉上心喜，置酒故人同。", "高會延遺老，酣歌和衆童。", "窮歡新笑樂，起舞舊英雄。", "慷慨悲游子，軒昂賦大風。", "永爲湯沐邑，何用築新豐。"]'),
('80dcf4f8-b990-4671-ad9a-51992ceaa63c','天寒割蜜房詩','樓鑰','宋','宋诗','song-poetry','','[]','場圃功初畢，天寒樂歲穰。',72,'全唐诗/poet.song.159000.json','["場圃功初畢，天寒樂歲穰。", "山居收蜜課，簷外割蜂房。", "弱羽依晴日，纖腰怯曉霜。", "鉛刀開戶牖，棘匕薦甘香。", "作室何時再，趨衙未用忙。", "百花辛苦處，今日爲君嘗。"]'),
('702061a1-2b71-425a-be41-447e03ffda7b','黄知橘柚來詩','樓鑰','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u6d1e\u5ead\u6e56"]','一舸放長江，遥林底處黄。',72,'全唐诗/poet.song.159000.json','["一舸放長江，遥林底處黄。", "自知來橘柚，先已照滄浪。", "綠葉凝烟密，金苞射日光。", "相迎蒼縣雨，暗識洞庭霜。", "味詫江陵種，庭垂禹廟荒。", "何如船上看，數里更飛香。"]'),
('7041b96e-5d0d-48a1-ac42-af286dae0f49','背水陣詩','樓鑰','宋','宋诗','song-poetry','','[]','十里當勍敵，臨機事寖危。',72,'全唐诗/poet.song.159000.json','["十里當勍敵，臨機事寖危。", "萆山兵已遣，背水陣尤奇。", "前澤書誠有，行權我獨知。", "正須投死地，何用恤羣疑。", "拔幟終如約，傳餐亦應期。", "孫吳非紙上，方略要從宜。"]'),
('f1bf2c4e-cf63-42b8-845b-2c173b6977f3','鯤化爲鵬詩','樓鑰','宋','宋诗','song-poetry','','[]','鯤大幾千里，揚鬐氣日增。',72,'全唐诗/poet.song.159000.json','["鯤大幾千里，揚鬐氣日增。", "一時俄化羽，萬古記爲鵬。", "鱗族疇能比，龍門不足登。", "天池將轉徙，雲翼快飛騰。", "怪矣齊諧志，壯哉莊叟稱。", "鳶飛與魚躍，曾不事誇矜。"]'),
('7ce7fd30-a99e-41a0-889a-b77fb36fe580','一月三捷詩','樓鑰','宋','宋诗','song-poetry','','[]','勇甚鷹揚將，身從虎穴探。',72,'全唐诗/poet.song.159000.json','["勇甚鷹揚將，身從虎穴探。", "六師心不二，一月捷凡三。", "戎卒時非久，邊庭戰已酣。", "神戈窮逐北，露布屢馳南。", "貔旅彌思奮，狼心敢肆貪。", "七旬有苗格，較德可無慙。"]'),
('683c60b5-a41c-4608-a833-9028ece8c35d','清泉潔塵襟詩','樓鑰','宋','宋诗','song-poetry','','[]','騷客事幽尋，清泉一派深。',72,'全唐诗/poet.song.159000.json','["騷客事幽尋，清泉一派深。", "居然浮爽氣，聊用潔塵襟。", "徹底明蒼石，澄波漾碧岑。", "應添山澤趣，盡滌市朝心。", "洗耳何妨聽，吟詩更喜臨。", "至哉天下樂，穩坐讀書林。"]'),
('08bd80a1-57a8-40e3-a029-da4706fb7366','復見官軍詩','樓鑰','宋','宋诗','song-poetry','','[]','元帥平京邑，歡聲夾道聞。',72,'全唐诗/poet.song.159000.json','["元帥平京邑，歡聲夾道聞。", "不圖當此日，復得見官軍。", "將鉞來何莫，壺漿意已勤。", "重瞻貔虎士，盡掃犬羊羣。", "王旅方馳電，民心極望雲。", "長安十萬戶，拭目待吾君。"]'),
('356a70e6-4cf2-4d16-99c0-8926715c8abb','物色訪嚴光詩','樓鑰','宋','宋诗','song-poetry','','[]','肥遯推嚴子，招賢仰漢光。',72,'全唐诗/poet.song.159000.json','["肥遯推嚴子，招賢仰漢光。", "營求思舊學，物色訪羣方。", "聘問期終得，形容尚未忘。", "羊裘方審識，蒲乘遂搜揚。", "不羨雲臺繪，還歸釣瀨傍。", "高風今尚在，江水與俱長。"]'),
('40ed8514-3516-4bf5-9a6c-a3a044eacf8a','冀北馬羣空詩','樓鑰','宋','宋诗','song-poetry','','[]','冀北雖多馬，知惟伯樂工。',72,'全唐诗/poet.song.159000.json','["冀北雖多馬，知惟伯樂工。", "祇因良種去，便覺舉羣空。", "過視千蹄衆，先收八駿雄。", "謾聞餘布野，無復見追風。", "騏驥方奔逸，駑駘豈混同。", "儻非承一顧，鳴意孰能通。"]'),
('2f24a1b4-f1fe-4fb6-8dcb-71c610f69738','習馬長楊詩','樓鑰','宋','宋诗','song-poetry','','[]','强漢承平後，兢兢武不忘。',72,'全唐诗/poet.song.159000.json','["强漢承平後，兢兢武不忘。", "整師臨五柞，習馬向長楊。", "冀野來騏驥，天閑出驌驦。", "驤騰射熊館，馳驟華山陽。", "輦路千蹄穩，瑶池八駿良。", "上方勤閲武，願賦翰林章。"]'),
('eff25fdc-0f40-48dd-9bb6-0763ddd01360','飛泉漱鳴玉詩','樓鑰','宋','宋诗','song-poetry','','[]','翠巘幽深處，飛泉觸石鳴。',72,'全唐诗/poet.song.159000.json','["翠巘幽深處，飛泉觸石鳴。", "跳珠不勝亂，漱玉有餘清。", "水落千尋險，風傳萬壑聲。", "玲瓏鏗璧韵，激濺破瓊英。", "漢水思遺珮，滄浪想濯纓。", "何須韓吏部，聯句賦琮琤。"]'),
('60dda4ac-93dd-4028-a44f-aefeded3c5c6','適齋慕香山之高續達哉行集香山詩句次韵','樓鑰','宋','宋诗','song-poetry','','[]','脫衣典酒曲江邊，不作閑游即醉眠。',224,'全唐诗/poet.song.159000.json','["脫衣典酒曲江邊，不作閑游即醉眠。", "大抵浮榮何足道，生理何曾得自全。", "朝廷雇我作閑人，髣髴緡錢二三千。", "一種共君官職冷，收得身來已五年。", "五年炎涼凡十變，老後誰能惜酒錢。", "塵纓世網重重縛，七十八十百病纏。", "千萬人中無一人，自喜天教我少緣。", "六十三翁頭雪白，貧家强健亦天憐。", "每媿尚書情眷眷，與君一醉一陶然。", "其間氣味都相似，猶在病羸昏耄前。", "月夜徐行石橋上，累累棟宇相連延。", "歲種薄田一頃餘，薄産處置有後先。", "更無俗物當人眼，遊鱼鱍鱍蓮田田。", "爲君舉酒歌短歌，不妨兼有散花天。"]'),
('2f71e70b-e735-42f4-a708-a08c0969a59e','適齋示池水大篇效元白體相答','樓鑰','宋','宋诗','song-poetry','','[]','適齋一片心，它人難與比。',288,'全唐诗/poet.song.159000.json','["適齋一片心，它人難與比。", "少時發此念，樂施到莫齒。", "婚姻成者衆，葬埋不知幾。", "義氣追古人，仁風動桑梓。", "利益及物物，方便形事事。", "先正有此言，源流固有自。", "外家有大池，清波照叢桂。", "來者不問誰，小大聽盈器。", "及其旱將涸，一雨復清泚。", "我舅爲欣然，作詩自言志。", "平生欲濟人，往往多割己。", "向來俸可分，掛冠踰一紀。", "心勤力不逮，不得盡如意。", "安得有貲財，如此池中水。", "來求則應之，吾心斯足矣。", "長篇筆餘力，亹亹遂滿紙。", "病足正僵卧，三誦爲之起。", "韵險不容次，愚言不能止。", "公曰汝答我，只用元白體。", "公心與天通，言合孟軻氏。", "菽粟如水火，此意豈不美。", "黄金土同價，但恐無此理。", "求水易足用，近止及鄰里。", "上不過飲食，下亦止濯洗。"]'),
('a90556e4-b4f6-4998-a4a5-5b5213cf7799','約同社往來無事形迹次韵','樓鑰','宋','宋诗','song-poetry','','[]','家舅年益高，何止七十稀。',216,'全唐诗/poet.song.159000.json','["家舅年益高，何止七十稀。", "神明曾未衰，髮黄齒如兒。", "義槩同古人，閭里咸歸依。", "度量海深闊，仁愛佛慈悲。", "居然三達尊，後生願影隨。", "爲作真率集，率以月爲期。", "平生持謙柄，自牧何太卑。", "善學柳下惠，不欲慕伯夷。", "一鄉有善士，收拾略不遺。", "以此娛我老，今是勝昨非。", "何必汗漫游，據龜食蛤蜊。", "但欲客長滿，痛飲真吾師。", "鄉黨既恂恂，朋友亦偲偲。", "凡我同盟人，共當惜此時。", "間或造竹所，寧容掩朱扉。", "耆英古有約，不勸亦不辭。", "此意豈不美，謹當守蕭規。", "達哉杜陵客，從它人見嗤。"]'),
('ca37f02f-5173-4097-bd23-8b4974291a7c','表兄陳安行遷右司仲兄遷大理丞余遷太府丞寄詩爲賀次韵  其一','樓鑰','宋','宋诗','song-poetry','','[]','東塾談經歲月輕，外家生長復何營。',64,'全唐诗/poet.song.159000.json','["東塾談經歲月輕，外家生長復何營。", "王生此舅若無有，楊惲一書安得成。", "首寄新詩欽厚意，却思往事念平生。", "當時更荷外祖母，幼惠尤憐盛氏甥。"]'),
('7a4d1671-04de-429e-acf6-216d512e2eef','表兄陳安行遷右司仲兄遷大理丞余遷太府丞寄詩爲賀次韵  其二','樓鑰','宋','宋诗','song-poetry','','[]','爲親敢說宦情輕，公退委蛇懶自營。',64,'全唐诗/poet.song.159000.json','["爲親敢說宦情輕，公退委蛇懶自營。", "朝路一時偕寸進，適齋新句已先成。", "圉師况復今同里，武子非惟愛外生。", "舊日阿重今欲冠，此恩更欲到彌甥。"]'),
('b06037be-a86b-438a-ab59-6e6d8393b025','適齋掛冠次韵  其一','樓鑰','宋','宋诗','song-poetry','','[]','致仕吾非不待年，禮經自合許求田。',64,'全唐诗/poet.song.159000.json','["致仕吾非不待年，禮經自合許求田。", "祇圖徑取衣冠掛，不願更尋香火緣。", "富貴鼎來先瞥地，是非衮處獨翩然。", "鄮峰相對兩真隠，共仰元台與大天。"]'),
('d9b493b5-63e4-41f2-874c-b11c4a6c19ac','適齋掛冠次韵  其二','樓鑰','宋','宋诗','song-poetry','','[]','世事相牽無了期，平生待足是何時。',64,'全唐诗/poet.song.159000.json','["世事相牽無了期，平生待足是何時。", "拋官不作九閽夢，納祿尚餘三徑資。", "紫綬金章寧復戀，黄冠野服自相宜。", "耳根贏得長清浄，理亂從今不用知。"]'),
('9a34dac6-c71d-45e2-8bdc-547ecf8b21d0','余初除西掖適齋惠詩以二甥相繼縯綸爲喜安行表兄貽書喜溢于辭謹次二篇爲謝末章以屬安行  其一','樓鑰','宋','宋诗','song-poetry','','[]','漕臺生處寢之床，叢桂還分一葉芳。',64,'全唐诗/poet.song.159000.json','["漕臺生處寢之床，叢桂還分一葉芳。", "紅藥階邊懷老謝，桃花觀裏憶劉郎。", "首煩賢舅書增喜，想見慈親色更康。", "無忌安能真酷似，願從外氏借餘光。"]'),
('78fc3deb-0fd2-4be6-8776-a62306c083b4','余初除西掖適齋惠詩以二甥相繼縯綸爲喜安行表兄貽書喜溢于辭謹次二篇爲謝末章以屬安行  其二','樓鑰','宋','宋诗','song-poetry','','[]','敢謂封倫據此床，幸從科級紹餘芳。',64,'全唐诗/poet.song.159000.json','["敢謂封倫據此床，幸從科級紹餘芳。", "紫薇繼直中書省，叢桂猶爲同舍郎。", "太史書傳得楊惲，渭陽情厚爲秦康。", "外家宅相君餘事，魚目何堪比夜光。"]'),
('6e3275ba-2035-47e3-a04a-a7915a923a1c','余丐郡得婺以詩相迎次韵','樓鑰','宋','宋诗','song-poetry','','[]','風際端宜鷁退飛，青雲高處有危機。',64,'全唐诗/poet.song.159000.json','["風際端宜鷁退飛，青雲高處有危機。", "屢遮西日成何事，幾向東風詠式微。", "塞馬云何真是福，鱸魚正不爲知幾。", "休論五馬人生貴，且奉潘輿得賦歸。"]'),
('de73152a-df7e-4cc9-a369-ef3b8cd0ce9f','約訪王卿已而中輟次韵','樓鑰','宋','宋诗','song-poetry','','[]','歸來親戚話通情，準擬流花得再行。',64,'全唐诗/poet.song.159000.json','["歸來親戚話通情，準擬流花得再行。", "已荷適齋容接武，敢從酌古遽渝盟。", "烏衣門巷人非遠，綠野樽罍計未成。", "官已得閑身未暇，因仍恐或過清明。"]'),
('1a53310e-95bb-49c8-aac6-e22f680919b5','謝太守送雪次韵','樓鑰','宋','宋诗','song-poetry','','[]','一冬祇見曉霜寒，未得飛霙萬里看。',64,'全唐诗/poet.song.159000.json','["一冬祇見曉霜寒，未得飛霙萬里看。", "多謝黄堂贈圭璧，欲從乳竇倚欄干。", "簷高安有冰成柱，坐久空餘水在盤。", "歲晚願呈三白瑞，要觀積玉滿林端。"]'),
('ac96fcb5-50f9-47ab-a102-eaecf79c4791','清高閣觀雪次韵','樓鑰','宋','宋诗','song-poetry','','[]','衝雪上層閣，真成清且高。',48,'全唐诗/poet.song.159000.json','["衝雪上層閣，真成清且高。", "主人風節峻，坐客笑談豪。", "泛剡訪安道，賦梅思水曹。", "好因窗映夜，痛飲讀離騷。"]'),
('eb9c2c5f-42b1-4a1c-9ede-523d255cd1f9','真率會次韵','樓鑰','宋','宋诗','song-poetry','','[]','喜奉潘輿得退身，烏衣相會總情親。',64,'全唐诗/poet.song.159000.json','["喜奉潘輿得退身，烏衣相會總情親。", "樽前正好醉千日，林下何妨見兩人。", "閑暇止應開口笑，談諧尤稱掇皮真。", "夜歸更作驚人語，舅氏從來筆有神。"]'),
('283caa32-ac3e-4a35-bfbe-0a4dc8b9e183','楊聖可棋集余方歸自桃源不及預次韵','樓鑰','宋','宋诗','song-poetry','','[]','屏處尤便野性慵，故人何幸總相逢。',64,'全唐诗/poet.song.159000.json','["屏處尤便野性慵，故人何幸總相逢。", "賦歸敢慕陶彭澤，自免猶睎邴曼容。", "棋酒交歡情正洽，江山得助景方濃。", "嗟余誤入桃源去，歸路滿城聞晚鐘。"]'),
('82f81bd5-2354-4a28-be6f-3b3dafc93c3f','汪達可招游臧園次韵  其一','樓鑰','宋','宋诗','song-poetry','','[]','城下名園稱老懷，乳鶑飛燕共低徊。',64,'全唐诗/poet.song.159000.json','["城下名園稱老懷，乳鶑飛燕共低徊。", "寒梅送臘曾先到，嫩綠留春喜再來。", "眼底芳時能幾許，樓頭衙鼓謾相催。", "主人好事不嫌客，素壁揮毫又一回。"]'),
('83ee6b49-6558-4851-9a9a-3dbd0234cffd','汪達可招游臧園次韵  其二','樓鑰','宋','宋诗','song-poetry','','[]','滿架酴醾愜雅懷，更添林下紫徘徊。',64,'全唐诗/poet.song.159000.json','["滿架酴醾愜雅懷，更添林下紫徘徊。", "平湖不怕重門阻，勝賞何妨後日來。", "酒興已隨斜照遠，詩情無待片雲催。", "黄昏鼓棹欲歸去，望望煙林首重回。"]'),
('5ea4f829-7ad6-4d2f-a17c-7da3f8bd80be','士穎弟作真率會次韵','樓鑰','宋','宋诗','song-poetry','','[]','何羨祖希情好隆，朱陳累世意交通。',64,'全唐诗/poet.song.159000.json','["何羨祖希情好隆，朱陳累世意交通。", "舅甥巾屨頻相接，兄弟樽罍喜更同。", "參坐幸容攻媿子，主盟全頼適齋翁。", "日來愈得清閑趣，斗酒不妨時一中。"]'),
('b7f7387a-b9f6-49da-ae76-267c1134e724','吊王卿之喪次韵','樓鑰','宋','宋诗','song-poetry','','[]','去歲同登百尺樓，相期春晚更重游。',64,'全唐诗/poet.song.159000.json','["去歲同登百尺樓，相期春晚更重游。", "舟藏大壑夜俄去，橋跨清溪花自流。", "五紀情親真是夢，四山風物總成愁。", "一朝千古尚何及，空使文皇歎薛收。"]'),
('710786ed-c9b0-4ad2-85c4-3df45af71ee2','喜雨次韵併呈郡守吳居父  其一','樓鑰','宋','宋诗','song-poetry','','[]','一旱禱而雨，此心天與通。',48,'全唐诗/poet.song.159000.json','["一旱禱而雨，此心天與通。", "爲霖三日足，起舞萬家同。", "破塊朝方爽，翻盆夜正中。", "隨車真響應，巫覡又何功。"]'),
('89ff1e7d-d07d-4a9d-8edc-d2370ab757dc','喜雨次韵併呈郡守吳居父  其二','樓鑰','宋','宋诗','song-poetry','','[]','洗印日無幾，載芟春已祈。',48,'全唐诗/poet.song.159000.json','["洗印日無幾，載芟春已祈。", "龍神來鄮嶺，香炷爇流眉。", "自笑受廛許，堪爲學稼遲。", "洋洋添野水，已足樂吾饑。"]'),
('b54d613c-80b1-42bd-b65b-a056fa0459f4','喜雨次韵併呈郡守吳居父  其三','樓鑰','宋','宋诗','song-poetry','','[]','雨師爭自效，風伯尚何施。',48,'全唐诗/poet.song.159000.json','["雨師爭自效，風伯尚何施。", "膏澤由分閫，空餐媿奉祠。", "農功今可濟，水利更毋隳。", "喜雨無煩記，行人口似碑。"]'),
('829eab6c-0e49-49d3-84ad-309341ab7581','安行表兄除華文閣直學士奉祠次韵爲賀','樓鑰','宋','宋诗','song-poetry','','[]','屢報銀臺給事中，忽聞喚渡浙江東。',64,'全唐诗/poet.song.159000.json','["屢報銀臺給事中，忽聞喚渡浙江東。", "長安幸免手遮日，圓嶠莫嗟船引風。", "廩繼真祠身暫逸，班聯內閣眷方隆。", "且歸同伴適齋老，便看鋒車召此翁。"]'),
('33e93ac8-c3a4-4ff8-9857-cf67cce5ea1a','送安行表兄葬次韵','樓鑰','宋','宋诗','song-poetry','','[]','深沈仙洞鎖神清，萬壑松聲不似晴。',64,'全唐诗/poet.song.159000.json','["深沈仙洞鎖神清，萬壑松聲不似晴。", "宿草它年空悵望，生芻今日寓精誠。", "山川氣象渾如舊，劍佩風姿儼若生。", "猶記玉音稱酷似，始知無忌乃其甥。"]'),
('783094b8-a2d9-4a0e-b93a-f416d7859044','尋春次韵  其一','樓鑰','宋','宋诗','song-poetry','','[]','一自東皇天上來，坐看芽蘗起枯荄。',64,'全唐诗/poet.song.159000.json','["一自東皇天上來，坐看芽蘗起枯荄。", "化工潜有洪鈞轉，春事何勞疊鼓催。", "晚景鬢凋寧再綠，去年花謝又重開。", "賞花携酒那容緩，走遍郊原莫便回。"]'),
('63531fa0-6d8f-42ab-a1bd-bb905acb2139','尋春次韵  其二','樓鑰','宋','宋诗','song-poetry','','[]','曉來陌上雨斑斑，同社相將便出關。',64,'全唐诗/poet.song.159000.json','["曉來陌上雨斑斑，同社相將便出關。", "席地亦堪尋酒所，得園徑與坐花間。", "從教多病須行樂，任是清貧也破慳。", "門外紅塵深幾許，誰人能得此身閑。"]'),
('c3687b42-b14c-4a92-aaaa-1d61ae801fa3','次韵十絕 休官','樓鑰','宋','宋诗','song-poetry','','[]','人生寧問草堂資，乞得閑身且徑歸。',32,'全唐诗/poet.song.159000.json','["人生寧問草堂資，乞得閑身且徑歸。", "慙媿舅甥俱就隠，澹然相對兩忘機。"]'),
('7dd688f6-7808-4fde-accc-013c6d144836','次韵十絕 發書','樓鑰','宋','宋诗','song-poetry','','[]','故人惟頼幾行書，今日誰能更訪吾。',32,'全唐诗/poet.song.159000.json','["故人惟頼幾行書，今日誰能更訪吾。", "舊日熱心今就冷，向來已自得揶揄。"]'),
('f58c1d9a-e97b-4fdb-9afc-31bf4219081f','次韵十絕 見客','樓鑰','宋','宋诗','song-poetry','','[]','客至何妨送與迎，門前羅爵亦人情。',32,'全唐诗/poet.song.159000.json','["客至何妨送與迎，門前羅爵亦人情。", "可憐寒士猶相望，時有饑來柳絮輕。"]'),
('b796a2a3-6718-4dfc-924f-2141b7dc7783','次韵十絕 出謁','樓鑰','宋','宋诗','song-poetry','','[]','杜門却掃寖多時，間傍人門亦漫爲。',32,'全唐诗/poet.song.159000.json','["杜門却掃寖多時，間傍人門亦漫爲。", "茶竈筆床煙浪去，自疑身是老天隨。"]'),
('c2aac899-6a30-48a1-b080-7c9095235988','次韵十絕 赴會','樓鑰','宋','宋诗','song-poetry','','[]','幸身未老已先閑，到處時時盡醉還。',32,'全唐诗/poet.song.159000.json','["幸身未老已先閑，到處時時盡醉還。", "更欲相邀蓮社客，共尋精舍上孱顔。"]'),
('9335f1b3-6362-44ab-9483-2811c548ff2e','次韵十絕 病起','樓鑰','宋','宋诗','song-poetry','','[]','老去情懷百不宜，上樓腰脚覺舒遲。',32,'全唐诗/poet.song.159000.json','["老去情懷百不宜，上樓腰脚覺舒遲。", "適齋異稟人難及，病起精神略不衰。"]'),
('99477228-2730-4e84-9086-8d6175bc5413','次韵十絕 安心','樓鑰','宋','宋诗','song-poetry','','[]','但使心如水在槃，坐令四體自然胖。',32,'全唐诗/poet.song.159000.json','["但使心如水在槃，坐令四體自然胖。", "有人來問安心法，將汝心來與汝安。"]'),
('88a717be-c5b3-475e-bed8-74fd7352ea3f','次韵十絕 讀書','樓鑰','宋','宋诗','song-poetry','','[]','佚老無如大字書，聊將遮眼度三餘。',32,'全唐诗/poet.song.159000.json','["佚老無如大字書，聊將遮眼度三餘。", "有時忠義忽相激，間遇包胥與子胥。"]'),
('deac044d-8d20-4cda-9dc3-d0e0f869ac2c','次韵十絕 染鬚','樓鑰','宋','宋诗','song-poetry','','[]','染鬚欲學少年時，笑殺當年榮啟期。',32,'全唐诗/poet.song.159000.json','["染鬚欲學少年時，笑殺當年榮啟期。", "公道世間惟此耳，年來猶幸不相欺。"]'),
('304de660-4ab1-4d45-bd9d-33f3bceaabc3','次韵十絕 修養','樓鑰','宋','宋诗','song-poetry','','[]','聞道壺中別有天，能將俄頃比千年。',32,'全唐诗/poet.song.159000.json','["聞道壺中別有天，能將俄頃比千年。", "千年俄頃俱成夢，只任天真却晏然。"]'),
('d4aba7e7-9362-40a9-9fab-14145c09b667','同年鄭貴溫寺丞直華文閣致仕次韵爲賀  其一','樓鑰','宋','宋诗','song-poetry','','[]','先生久矣愛吾廬，絕勝揚雄宅一區。',64,'全唐诗/poet.song.159000.json','["先生久矣愛吾廬，絕勝揚雄宅一區。", "賸有珠宮來海石，不妨茅屋繞畦蔬。", "來書已許尋前諾，同社方將約並驅。", "更欲相邀預真率，車公豈可坐間無。"]'),
('434c1428-1176-4abb-8191-997826ad7a8a','同年鄭貴溫寺丞直華文閣致仕次韵爲賀  其二','樓鑰','宋','宋诗','song-poetry','','[]','倦游歸騎自吳門，尋上封章叩帝閽。',64,'全唐诗/poet.song.159000.json','["倦游歸騎自吳門，尋上封章叩帝閽。", "俞旨肆頒旌素節，華文進直示優恩。", "淵明妙句群賢和，疎傅佳名萬古存。", "加我數年祈謝事，此心難與俗人論。"]'),
('165a6670-eb7c-4e8f-9dbe-a9a2a61bc7ff','次韵四絕 初得曾孫女','樓鑰','宋','宋诗','song-poetry','','[]','外子惟知媿可攻，羨公八十未衰癃。',32,'全唐诗/poet.song.159000.json','["外子惟知媿可攻，羨公八十未衰癃。", "曾孫喜見親文褓，尚想當年擲鏡翁。"]'),
('45a7523a-7502-4f41-b362-a94ae7a34f19','次韵四絕 末莉花','樓鑰','宋','宋诗','song-poetry','','[]','江南創見喜孤芳，見說閩花徧海鄉。',32,'全唐诗/poet.song.159000.json','["江南創見喜孤芳，見說閩花徧海鄉。", "安得一居香盛處，帳中巧作寶毬粧。"]'),
('bdb0bb9b-4e0d-400a-ade1-12120152b128','次韵四絕 從子澡滌築屋荷池上','樓鑰','宋','宋诗','song-poetry','','[]','樓臺牆宇家家月，楊柳荷花處處風。',32,'全唐诗/poet.song.159000.json','["樓臺牆宇家家月，楊柳荷花處處風。", "最喜兩涯相映带，一時倒影入池中。"]'),
('55f8cbf6-9567-48cf-a9c2-3090ed80f9b0','次韵四絕 山亭納凉','樓鑰','宋','宋诗','song-poetry','','[]','不嫌西照與朝曦，城郭誰知住翠微。',32,'全唐诗/poet.song.159000.json','["不嫌西照與朝曦，城郭誰知住翠微。", "天幸外門才咫尺，欲陪杖屨夜忘歸。"]'),
('50754142-0cd7-415d-b7be-bc9033cab55e','次韵五詩 山行野老問年','樓鑰','宋','宋诗','song-poetry','','[]','田夫笑把褐衣牽，爭問壺中別有天。',64,'全唐诗/poet.song.159000.json','["田夫笑把褐衣牽，爭問壺中別有天。", "齒髮雖衰渾未覺，精神愈勝果何緣。", "公言已老偶能爾，我本無心只自然。", "再禱百分才及一，定應椿壽八千年。"]'),
('0b7233a6-2926-4ac9-871c-bf79b0d3ccfe','次韵五詩 堅鄭貴溫棋社','樓鑰','宋','宋诗','song-poetry','','[]','二公休致我來歸，儘可同裁隠士衣。',64,'全唐诗/poet.song.159000.json','["二公休致我來歸，儘可同裁隠士衣。", "此已屢謀登竹所，君其無吝造城扉。", "人間厭見手翻覆，樂處但當頤指揮。", "涼氣一新宜近酒，盍簪莫似向來稀。"]'),
('8d558f60-39c3-4e12-b70d-96534bae83af','次韵五詩 秋凉有感','樓鑰','宋','宋诗','song-poetry','','[]','公看魚躍與鳶飛，鶴脛雖長斷則悲。',64,'全唐诗/poet.song.159000.json','["公看魚躍與鳶飛，鶴脛雖長斷則悲。", "世事不容人苦較，秋風自有葉先知。", "青奴難免交新絕，素扇寧須手自持。", "宋玉賦篇終未達，不如老子笑成詩。"]'),
('f4d2c2b1-b580-4b46-b4ae-4e608b4dadc4','次韵五詩 諭悲秋者','樓鑰','宋','宋诗','song-poetry','','[]','黄雲萬頃一時收，喜見高空風露秋。',64,'全唐诗/poet.song.159000.json','["黄雲萬頃一時收，喜見高空風露秋。", "歲事及今將告畢，人生到老盍歸休。", "固知景物能興感，亦有癡人苦過憂。", "胸次果然無一累，豈容秋月使人愁。"]'),
('e099fc37-e5eb-457f-8ddb-afb86314e9be','次韵五詩 舅甥賡酬之樂','樓鑰','宋','宋诗','song-poetry','','[]','神明未覺晉公衰，老母尤欣兄弟怡。',64,'全唐诗/poet.song.159000.json','["神明未覺晉公衰，老母尤欣兄弟怡。", "范寧王枕無許壽，牢之無忌不聞詩。", "秋風對酒勸酬處，夜月乘橋來往時。", "但要兩家同此適，不須更遣外間知。"]'),
('fbcd9364-085a-4914-9798-2775375d63bf','八月十四日携家泛月次韵  其一','樓鑰','宋','宋诗','song-poetry','','[]','月到平湖金作波，一城惟此占秋多。',32,'全唐诗/poet.song.159000.json','["月到平湖金作波，一城惟此占秋多。", "水晶宮裏清無比，何用重登漢馺娑。"]'),
('9bbf650e-153b-40c0-832a-c2a16cf703f8','八月十四日携家泛月次韵  其二','樓鑰','宋','宋诗','song-poetry','','[]','九秋風月正分平，盛滿金晶分外明。',32,'全唐诗/poet.song.159000.json','["九秋風月正分平，盛滿金晶分外明。", "老子此行端不惡，夜深幾得聖之清。"]'),
('96b90cd9-44d3-4604-8993-f6bcc64e98e0','八月十四日携家泛月次韵  其三','樓鑰','宋','宋诗','song-poetry','','[]','稍先一日我中秋，行徧芙蓉與菊洲。',32,'全唐诗/poet.song.159000.json','["稍先一日我中秋，行徧芙蓉與菊洲。", "作意安排却非適，不如乘興徑行舟。"]'),
('f2dc05cb-faea-413e-a4ad-8d5718e6e74c','八月十四日携家泛月次韵  其四','樓鑰','宋','宋诗','song-poetry','','[]','猶記年時看水嬉，不如此夜月相宜。',32,'全唐诗/poet.song.159000.json','["猶記年時看水嬉，不如此夜月相宜。", "仙翁一醉非塵世，爲問姮娥知未知。"]'),
('9d232186-2ab5-4bf3-93d9-1e37d3649116','八月十四日携家泛月次韵  其五','樓鑰','宋','宋诗','song-poetry','','[]','草草真成一段奇，比鄰非不借餘輝。',32,'全唐诗/poet.song.159000.json','["草草真成一段奇，比鄰非不借餘輝。", "板輿何敢侵風露，略望簷間且勸歸。"]'),
('21c843cb-3189-4da0-a6a0-a5ad8cc8501b','次韵十詩  其一','樓鑰','宋','宋诗','song-poetry','','[]','懶學仙家煉大還，但欣晚節在林間。',64,'全唐诗/poet.song.159000.json','["懶學仙家煉大還，但欣晚節在林間。", "鴛行免奏三千牘，駑駕難參十二閑。", "短艇有時浮淥水，輕輿到處賞佳山。", "莫言冷淡爲生活，冷淡終然無後艱。"]'),
('b4d66f6f-b7b4-4d65-8abe-55ba7ba1fca6','次韵十詩  其二','樓鑰','宋','宋诗','song-poetry','','[]','秋來病體費支吾，深閉柴門卧草廬。',64,'全唐诗/poet.song.159000.json','["秋來病體費支吾，深閉柴門卧草廬。", "藥裹多尋醫者問，酒樽寖與故人疎。", "時須勉强陪來客，未免辛勤答遠書。", "此外儒生真氣習，簡編猶欲趁三餘。"]'),
('74b6e714-b0e7-4fb2-a9fa-a0558b6ac588','次韵十詩  其三','樓鑰','宋','宋诗','song-poetry','','[]','大率舟行岸自移，機緘何必更深思。',64,'全唐诗/poet.song.159000.json','["大率舟行岸自移，機緘何必更深思。", "雨餘坐見水三尺，雲浄喜看天四垂。", "荷沼已殘霜後蓋，桂林初綻月邊枝。", "閑中氣味深長甚，問却西風總不知。"]'),
('c4cfa9ed-5a7c-4cda-918e-1904a9cda1bc','次韵十詩  其四','樓鑰','宋','宋诗','song-poetry','','[]','幸堪擊壤樂清時，衰病情懷百不宜。',64,'全唐诗/poet.song.159000.json','["幸堪擊壤樂清時，衰病情懷百不宜。", "祇好灌畦陪漢叟，更欣學圃慕樊遲。", "逢人草草須傾酒，得韵匆匆且和詩。", "琴意高低尤自適，高山流水久心知。"]'),
('61e2886d-6665-479d-988d-c36183514128','次韵十詩  其五','樓鑰','宋','宋诗','song-poetry','','[]','甥舅相尋向酒邊，相忘情話更怡然。',64,'全唐诗/poet.song.159000.json','["甥舅相尋向酒邊，相忘情話更怡然。", "人言難遇雙延閣，自媿叨聯兩大天。", "只覺光陰詩裏過，何妨枕簟醉時眠。", "此中別有真消息，莫爲人間醒者傳。"]'),
('bcc22ef8-8ebb-4dc0-a9db-f1014871f706','次韵十詩  其六','樓鑰','宋','宋诗','song-poetry','','[]','從來憂道不憂貧，晚向閑中得此身。',64,'全唐诗/poet.song.159000.json','["從來憂道不憂貧，晚向閑中得此身。", "直把宦途如夢過，任他世事似棋新。", "坐間可說舊時話，眼底幸多同社人。", "賡唱本求閑燕樂，莫夸末路費精神。"]'),
('b5252dd1-9ca1-40d6-8463-20829d7e768b','次韵十詩  其七','樓鑰','宋','宋诗','song-poetry','','[]','自憐鶴髮奉慈親，家舅還欣託寶鄰。',64,'全唐诗/poet.song.159000.json','["自憐鶴髮奉慈親，家舅還欣託寶鄰。", "已向雲間收倦翼，甘從波底作潜鱗。", "幸然松菊連三徑，誰謂神僊隔一塵。", "野服相從成二叟，不須更現宰官身。"]'),
('88db82c3-448a-4206-b867-ef0524a25f3d','次韵十詩  其八','樓鑰','宋','宋诗','song-poetry','','[]','笑它咄咄向空書，既老投閑計未疎。',64,'全唐诗/poet.song.159000.json','["笑它咄咄向空書，既老投閑計未疎。", "釜裏有魚長自足，門前無爵是吾居。", "休論仙子生塵襪，莫問高軒織翠裾。", "百念已如灰樣冷，更無驕色與人鋤。"]'),
('1dbfc698-1eee-4247-9682-5a673740edae','次韵十詩  其九','樓鑰','宋','宋诗','song-poetry','','[]','秋宵坐到玉繩低，歷歷明蟾數桂枝。',64,'全唐诗/poet.song.159000.json','["秋宵坐到玉繩低，歷歷明蟾數桂枝。", "重露半翻蕉葉徑，好風時颭豆花籬。", "不妨起舞弄清影，何用撞鍾夸小詩。", "濁酒困人垂欲睡，更揩病眼一揚眉。"]'),
('eede74aa-ab6a-4b86-beff-387f3d48da0f','次韵十詩  其一○','樓鑰','宋','宋诗','song-poetry','','[]','秋到先生舊草堂，涼飈林葉已飄黄。',64,'全唐诗/poet.song.159000.json','["秋到先生舊草堂，涼飈林葉已飄黄。", "漸看天宇清霜肅，更覺人家白晝長。", "歷世既經三折臂，坐愁何必九回腸。", "世間萬事消磨盡，祇有詩情未遽忘。"]'),
('f714ddac-bb8b-46d3-a60f-a4b40feb5a7d','客目中次韵  其一','樓鑰','宋','宋诗','song-poetry','','[]','三年此月綺筵開，盛意勤拳不待催。',64,'全唐诗/poet.song.159000.json','["三年此月綺筵開，盛意勤拳不待催。", "預約行人須已集，先欣數客肯俱來。", "詩筒才到先賡韵，酒興方濃莫算盃。", "更欲秋深窮勝踐，鄒枚後乘可容陪。"]'),
('b3fb2332-4664-4bd0-b27f-2dd460f0308d','客目中次韵  其二','樓鑰','宋','宋诗','song-poetry','','[]','花若開時定自開，芳心深靚不容催。',64,'全唐诗/poet.song.159000.json','["花若開時定自開，芳心深靚不容催。", "主人又有新詩出，佳客應尋舊雨來。", "樓上已聞香撲鼻，堂前儘放酒盈盃。", "高燒銀燭照花睡，更到更深亦願陪。"]'),
('b1d8b1d7-28c7-4347-8d25-8331f2a8d978','次病足韵','樓鑰','宋','宋诗','song-poetry','','[]','定數無過偶與奇，達人處順更安時。',64,'全唐诗/poet.song.159000.json','["定數無過偶與奇，達人處順更安時。", "不於椿菌量長短，豈爲彭殤較疾遲。", "雖是一時身有疾，行開九秩壽無期。", "外生六十頭先白，杖屨相從最得宜。"]'),
('08521b93-b9f8-4b36-83f9-8989de9451de','戲和三絕 脫索','樓鑰','宋','宋诗','song-poetry','','[]','纏縛千遭趁酒巡，環觀巧手競稱神。',32,'全唐诗/poet.song.159000.json','["纏縛千遭趁酒巡，環觀巧手競稱神。", "莫言名利如韁鎖，猛烈抽身亦在人。"]'),
('9e51df94-0825-4e28-94c6-389db35e19c7','戲和三絕 藏擫','樓鑰','宋','宋诗','song-poetry','','[]','儘教逞技儘多般，畢竟甘心受面謾。',32,'全唐诗/poet.song.159000.json','["儘教逞技儘多般，畢竟甘心受面謾。", "解把人間等嬉戲，不妨笑與大家看。"]'),
('5ee6a793-f080-45dd-ac78-70db09807f21','戲和三絕 傀儡','樓鑰','宋','宋诗','song-poetry','','[]','假合陰陽有此身，使形全在氣和神。',32,'全唐诗/poet.song.159000.json','["假合陰陽有此身，使形全在氣和神。", "王家幻戲猶堅固，線索休時尚木人。"]'),
('5df4da3f-616d-40c1-bf1e-6a8211f23a16','晝寢正酣以二十韵詩來亟爲次韵','樓鑰','宋','宋诗','song-poetry','','[]','老氏正求知我希，吾今老矣更何之。',320,'全唐诗/poet.song.159000.json','["老氏正求知我希，吾今老矣更何之。", "極知仕宦皆由命，縱有功名已過時。", "覽鏡形容寧復我，還鄉交友定從誰。", "慈親多幸方難老，家舅尤欣未覺衰。", "教誨至今仍似舊，襟期暗合自相知。", "新詩必使篇篇和，勝地還容處處隨。", "晝永劇談俱喜聽，夜深清坐更忘疲。", "素欽行己初無玷，願學持心不自欺。", "紫橐清班叨預列，黄金橫带忝同垂。", "六旬顧我猶加懶，八秩如公尚自持。", "但仰三尊知共慶，孰云十拗敢輕嗤。", "無情到此方爲達，省病從它不用治。", "世事只將同蝶夢，人生幾得見雞皮。", "觀書自適非求解，杖策徐行莫厭遲。", "儉素何妨貧勝富，優游真是樂忘饑。", "雖然調樂無千指，儘喜當歌有十眉。", "報謁要須親自到，赴筵直以散爲期。", "醉翁雅意非謀醉，棋社清歡豈爲棋。", "白髮只宜甘散誕，紅塵任彼自奔馳。", "安輿來往長陪侍，此意終身誓不移。"]'),
('5ea35c1e-feed-46f1-8f0c-916397276c31','次贈少微兄韵','樓鑰','宋','宋诗','song-poetry','','[]','汪樓比屋古城隅，彼此清貧不願餘。',64,'全唐诗/poet.song.159000.json','["汪樓比屋古城隅，彼此清貧不願餘。", "南阮諸賢今有幾，東床佳壻竟誰如。", "歸鄉年亦非全老，對酒情猶未覺疎。", "來往兩家無倦色，此身端合老犂鋤。"]'),
('f499c753-66b4-4d53-8d1a-fabd5e4c1395','桂花方開約客次韵','樓鑰','宋','宋诗','song-poetry','','[]','久疑巖桂儘遲開，留待生朝伴舉杯。',64,'全唐诗/poet.song.159000.json','["久疑巖桂儘遲開，留待生朝伴舉杯。", "老去欲尋千日醉，客來同引百花醅。", "况臨高閣枝枝秀，好判閑身日日陪。", "家釀盡傾君不惜，莫教瓶罄恥爲罍。"]'),
('c993393e-d09a-4a04-9dd3-161582a80d84','蔣德尚棋會展日次韵','樓鑰','宋','宋诗','song-poetry','','[]','棋社經年能幾回，身閑深幸屢參陪。',64,'全唐诗/poet.song.159000.json','["棋社經年能幾回，身閑深幸屢參陪。", "一旬又見朋簪集，三徑還因聽履開。", "休苦索居徒面壁，何如相遇且銜盃。", "雖由藥裹寬初約，不礙重尋舊雨來。"]'),
('6bef12ae-f7d9-461e-bdba-b4f0ab05470b','太上皇帝聖體清康老母進封信安郡太夫人適齋除敷文閣學士有詩爲賀次韵  其一','樓鑰','宋','宋诗','song-poetry','','[]','清朝孝治古無倫，通籍推恩總及親。',64,'全唐诗/poet.song.159000.json','["清朝孝治古無倫，通籍推恩總及親。", "八秩升班惟二老，九齡拜命更何人。", "春初慶席歡猶在，歲晚宸綸喜共新。", "須信長年多富貴，祇因同見會昌春。"]'),
('293598ea-e0a6-4251-b750-dbe6ad5b9482','太上皇帝聖體清康老母進封信安郡太夫人適齋除敷文閣學士有詩爲賀次韵  其二','樓鑰','宋','宋诗','song-poetry','','[]','吾母年高絕等倫，癡兒何幸得榮親。',64,'全唐诗/poet.song.159000.json','["吾母年高絕等倫，癡兒何幸得榮親。", "九重錫類真千載，八座承恩只一人。", "共仰外門流慶遠，喜同介弟寵光新。", "兩家盛事人爭賀，和氣薰爲臘裏春。"]'),
('2813fc3e-f904-4471-a1f0-34b20425ed2b','次題曉上人閑靜軒韵','樓鑰','宋','宋诗','song-poetry','','[]','我居城郭子居山，兩地相望數里間。',64,'全唐诗/poet.song.159000.json','["我居城郭子居山，兩地相望數里間。", "我已得閑猶未靜，子雖處靜少曾閑。", "莫將花與夢相似，之用心如石樣頑。", "要識箇中真信息，孤雲僧事兩相關。"]'),
('f4417894-67e3-410a-8c81-c2da09fdb5f5','次韵十詩 棋會','樓鑰','宋','宋诗','song-poetry','','[]','歸來鄉曲大家閑，同社仍欣取友端。',64,'全唐诗/poet.song.159000.json','["歸來鄉曲大家閑，同社仍欣取友端。", "無事銜盃何不可，有時會面亦良難。", "少曾環坐坐長滿，頼有主盟盟未寒。", "琴弈相尋詩間作，笑談終日有餘歡。"]'),
('b6e3176b-c9fe-4a19-8534-d5cc1f983009','次韵十詩 老態','樓鑰','宋','宋诗','song-poetry','','[]','舅甥身退不爲遲，肥遯猶當未老時。',64,'全唐诗/poet.song.159000.json','["舅甥身退不爲遲，肥遯猶當未老時。", "東晉雖慙古元亮，晚唐知慕老天隨。", "公開九秩身方健，我甫六旬心已疲。", "不敢自言成酷似，腹心惟喜兩相知。"]'),
('dc71391d-cc09-4558-95c0-5977fabf0eb0','次韵十詩 晨朝懶起','樓鑰','宋','宋诗','song-poetry','','[]','坐見一翁雙鬢皤，只贏曉夢到無何。',64,'全唐诗/poet.song.159000.json','["坐見一翁雙鬢皤，只贏曉夢到無何。", "窗涼風透真成適，日出事生還更多。", "足弱已難堪蠟屐，齒摇初不爲鄰梭。", "回思螭陛班心處，日日奔趨向馺娑。"]'),
('d9ce3ebc-036b-4711-a4bb-712c8779cca5','次韵十詩 見客','樓鑰','宋','宋诗','song-poetry','','[]','車轍長多長者臨，相過肯笑席門深。',64,'全唐诗/poet.song.159000.json','["車轍長多長者臨，相過肯笑席門深。", "寒暄固有三分話，臭味還傾一寸心。", "客至自應閑不厭，年來寖覺老難禁。", "應酬既了無餘事，面壁何妨學少林。"]'),
('bddabed1-215d-4be2-9208-f3f390aba5c5','次韵十詩 晝寢','樓鑰','宋','宋诗','song-poetry','','[]','才盡甘爲世所捐，不如高卧了餘年。',64,'全唐诗/poet.song.159000.json','["才盡甘爲世所捐，不如高卧了餘年。", "時逢毀譽心無諍，間有詩文手自編。", "老去已知身是夢，閑來更得酒中天。", "簾深午寂渾無念，只與白鷗相對眠。"]'),
('ae1f16f8-99c4-4630-b04c-dd7470e1234b','次韵十詩 喜閑 其一','樓鑰','宋','宋诗','song-poetry','','[]','投閑時以醉爲鄉，人既相忘我亦忘。',64,'全唐诗/poet.song.159000.json','["投閑時以醉爲鄉，人既相忘我亦忘。", "雨足已期南畝熟，風清更愛北窗涼。", "晝觀碧落雲千疊，夜看中庭月一方。", "時援素琴聊自遣，誰能更作鳳求皇。"]'),
('99468f02-b9d9-4bc2-b00b-ddc4d3b18e9c','次韵十詩 喜閑 其二','樓鑰','宋','宋诗','song-poetry','','[]','杜陵鄭老共襟期，門外紅塵弗與知。',64,'全唐诗/poet.song.159000.json','["杜陵鄭老共襟期，門外紅塵弗與知。", "近日頗荒攻媿課，多時不見適齋詩。", "竹深荷浄相留處，月白風清偶會時。", "地僻衣裳俱自懶，黄冠野服澹相宜。"]'),
('3af2c71a-ffb8-4311-a1d2-ed57bc541179','次韵十詩 讀香山詩','樓鑰','宋','宋诗','song-poetry','','[]','詩到香山不計篇，想逢佳處輒欣然。',64,'全唐诗/poet.song.159000.json','["詩到香山不計篇，想逢佳處輒欣然。", "明知無子可傳業，每遇爲文自入編。", "舉世慕名多諷誦，惟公著句得純全。", "胸中相似詩方似，一等不爲名利牽。"]'),
('3484061e-0f5c-42cd-b3dd-09c289d41778','次韵十詩 即事','樓鑰','宋','宋诗','song-poetry','','[]','旋插杉枝蔽曉曦，緩摇輕箑自融怡。',64,'全唐诗/poet.song.159000.json','["旋插杉枝蔽曉曦，緩摇輕箑自融怡。", "調琴不用求成曲，得句何須湊作詩。", "無復趨炎同褦襶，但能尋睡學希夷。", "太倉日食五升米，老矣不嫌人更嗤。"]'),
('4a3efd01-7483-4e49-8ce9-3021dfb6c81e','次韵十詩 西山','樓鑰','宋','宋诗','song-poetry','','[]','兩岸杉松翠蔭長，輕輿連日得彷徉。',64,'全唐诗/poet.song.159000.json','["兩岸杉松翠蔭長，輕輿連日得彷徉。", "絕憐林下朝還莫，不問人間炎與涼。", "睡起閑情方自樂，齋餘歸路未須忙。", "何時更向月溪去，願著青鞋走侍旁。"]'),
('2d85d602-3426-4c26-8d01-4ebd322107a9','次韵十詩 燕居','樓鑰','宋','宋诗','song-poetry','','[]','大老今居東海濱，燕居晚歲更申申。',64,'全唐诗/poet.song.159000.json','["大老今居東海濱，燕居晚歲更申申。", "外生但喜長依教，一笑相從莫問貧。", "閑裏只將詩作活，酒邊猶有筆如神。", "乞言授几俱休論，且作羲皇以上人。"]'),
('168aaad6-9354-4463-a016-a1737f298150','子成兄年八十六史子久八十二舅氏八十一會于適齋次韵二絕  其一','樓鑰','宋','宋诗','song-poetry','','[]','堂中三壽喜同時，黄髮相逢齒更兒。',32,'全唐诗/poet.song.159000.json','["堂中三壽喜同時，黄髮相逢齒更兒。", "參坐共談宣政舊，風流不許後生知。"]'),
('99ada186-d0f4-4b27-9a54-813c8769a869','子成兄年八十六史子久八十二舅氏八十一會于適齋次韵二絕  其二','樓鑰','宋','宋诗','song-poetry','','[]','閭里舊游能幾人，適齋猶有筆如神。',32,'全唐诗/poet.song.159000.json','["閭里舊游能幾人，適齋猶有筆如神。", "莫言二老升沈異，各現宰官居士身。"]'),
('fdf12628-5e15-41a8-97b7-d159c8ade6c5','竹','樓鑰','宋','宋诗','song-poetry','','[]','蟄宮驚起兩龍角，蛟室未呈雙水犀。',32,'全唐诗/poet.song.159000.json','["蟄宮驚起兩龍角，蛟室未呈雙水犀。", "同本君爲分魯衛，清風應不愧夷齊。"]'),
('4bd50bd9-3e03-492c-ba17-f83fcf535ca3','半月軒','樓鑰','宋','宋诗','song-poetry','','[]','莫要作圓月，纔圓却又虧。',24,'全唐诗/poet.song.159000.json','["莫要作圓月，纔圓却又虧。", "不如作一半，猶有向圓時。"]'),
('4271ef6b-2a82-4ad0-b3b4-c284ece72243','壽戴君','樓鑰','宋','宋诗','song-poetry','','[]','人日過，四日中，蓬壺此際誕仙翁。',64,'全唐诗/poet.song.159000.json','["人日過，四日中，蓬壺此際誕仙翁。", "香飄寶篆纖餘碧，酒泛金樽瀲灧紅。", "安道家聲知有許，于公陰德自無窮。", "祝君壽算將何似，千仞螺山聳碧空。"]'),
('f38c99c2-6fec-4bd1-bf50-cec90c5fca5c','郭熙秋山平遠用東坡韵','樓鑰','宋','宋诗','song-poetry','','[]','槐花忙過舉子閒，舊遊憶在夷門山。',128,'全唐诗/poet.song.159000.json','["槐花忙過舉子閒，舊遊憶在夷門山。", "玉堂會見郭熙畫，拂拭縑素塵埃間。", "楚天極目江天遠，楓林渡頭秋思晚。", "煙中一葉認扁舟，雨外數峰橫翠巘。", "誰安客宦踰三霜，雲夢澤連襄漢陽。", "平生獨不見寫本，慣飲山綠餐湖光。", "老來思歸真日月，夢想林泉對華髮。", "丹青安得此一流，畫我橫筇水中石。"]'),
('8821fa96-5310-4050-a28e-5de2e3d8bcab','次曾子固韵','樓鑰','宋','宋诗','song-poetry','','[]','驚見銀河空外翻，奔湍千丈有餘寒。',32,'全唐诗/poet.song.159000.json','["驚見銀河空外翻，奔湍千丈有餘寒。", "下流不用長勞望，祇向懸崖頂上看。"]'),
('a74edb69-07bc-4378-b510-33ca0e2d792b','句','樓鑰','宋','宋诗','song-poetry','','[]','門前莫約頻來客，坐上同觀未見書。',16,'全唐诗/poet.song.159000.json','["門前莫約頻來客，坐上同觀未見書。"]'),
('603803e0-4507-475e-84fc-b9b2630c1939','第一山','王信','宋','宋诗','song-poetry','','[]','禺迹茫茫萬里天，望中皆我舊山川。',32,'全唐诗/poet.song.159000.json','["禺迹茫茫萬里天，望中皆我舊山川。", "誰將淮水分南北，直到幽燕始是邊。"]'),
('81348367-649b-4770-a159-b67afd448d5e','題椿桂堂','王信','宋','宋诗','song-poetry','','[]','鄉與子直游膠庠，是時子明居侍旁。',240,'全唐诗/poet.song.159000.json','["鄉與子直游膠庠，是時子明居侍旁。", "友于學問相激昂，聲華日馳翰墨場。", "仲氏一第如探囊，伯氏隨即淩雲翔。", "已快雁塔書雁行，君家餘慶未易量。", "二龍三鳳同呈祥，一門競爽如圭璋。", "前後繼踵名相望，夥爲十佛經中光。", "聯翩不羨金華堂，會稽何獨誇諸黄。", "世言燕山竇十郎，一枝椿老五桂芳。", "君今取此名其堂，薦紳榮之富篇章。", "幾與竇氏爭頡頏，吾家亦頗推吾鄉。", "自從仲父闓天荒，五登科第于太常。", "枝分派別各一房，敢與君家相比方。", "夫人更喜壽且康，歲時羅列稱壽觴。", "綵衣青紫交焜煌，人生至樂見未嘗。", "源深允矣流必長，孫枝更接秋風香。"]'),
('63a58509-0e76-4d17-a5c6-f5ae08ce768b','題石洞書院','王信','宋','宋诗','song-poetry','','[]','不到茲山又十秋，欲題名字記重遊。',64,'全唐诗/poet.song.159000.json','["不到茲山又十秋，欲題名字記重遊。", "轉頭前日夢相似，拭目諸公墨尚留。", "俗裏塵埃隨酒却，淡中生活爲詩愁。", "晚來得趣無人解，一鳥不鳴山更幽。"]'),
('1e2d96c6-e143-40be-bd35-c238620c1b47','飛瀑','王信','宋','宋诗','song-poetry','','[]','聞道東陽水樂亭，一經坡句萬年聲。',64,'全唐诗/poet.song.159000.json','["聞道東陽水樂亭，一經坡句萬年聲。", "我來石洞得飛瀑，誰賦新詩留美名。", "平地有雷鳴不斷，半天無雨勢如傾。", "欲知山水醉翁意，且請主人遲酒行。"]'),
('af98fda0-92ef-437b-8b78-01ac568af33e','詠揚州后土祠瓊花','王信','宋','宋诗','song-poetry','','[]','愛奇造物剪瓊瑰，爲鎮靈祠特地栽。',64,'全唐诗/poet.song.159000.json','["愛奇造物剪瓊瑰，爲鎮靈祠特地栽。", "事紀揚州千古勝，名傳天下萬花魁。", "何人斫却依然在，是處移將不肯開。", "謾說八仙模樣似，八仙那得有香來。"]'),
('06a7138c-af56-472c-bc2d-0e34cdb68ade','句','王信','宋','宋诗','song-poetry','','[]','托名庾公何區區，天造地設非關渠。',16,'全唐诗/poet.song.159000.json','["托名庾公何區區，天造地設非關渠。"]'),
('69dbef07-b9d4-46fb-90c0-01b775582dd8','視旱田賦呈上元簿楊明卿','王信','宋','宋诗','song-poetry','','[]','輪蹄旦旦風塵表，入眼群山青未了。',192,'全唐诗/poet.song.159000.json','["輪蹄旦旦風塵表，入眼群山青未了。", "刺藤迎日子先紅，蕎麥得霜花漸老。", "叢祠詭怪畫村疃，古寺騫騰出林杪。", "征衫多次逐飛鳶，下擔有時隨宿鳥。", "初晴得去恨遲遲，獨夜不眠憂悄悄。", "公如老驥暫伏櫪，我類游鱗終屈沼。", "一朝王事有期會，百里民情同探討。", "詳於禹貢辨等級，明似離婁燭幽眇。", "高依丘壠或微收，低近陂塘翻盡槁。", "凶荒有數合均一，報應於中又分曉。", "不能究實害非淺，儻使從寬恩豈小。", "茲行到處欲春風，批放莫教分數少。"]'),
('45c2519d-836a-4f60-9c8e-ea79d493c7a3','雪窗','王信','宋','宋诗','song-poetry','','[]','先生原是山中客，僅能揚雄一區宅。',128,'全唐诗/poet.song.159000.json','["先生原是山中客，僅能揚雄一區宅。", "窮冬十日不出門，群玉峯前看三白。", "誰將名字落人間，丹陛入對天開顔。", "江城作牧多暇日，猶有餘力窮躋攀。", "膏肓不除泉石念，勝處何如眼中見。", "四明風月豈無情，要是歲寒心不變。", "晴簷初晃雲母光，庭中已休雁鶩行。", "玲瓏元不礙達觀，下視萬物俱清凉。"]'),
('59c84de5-169c-48ca-b046-01414a7f6958','哭宣教郎趙壘之','王信','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江天險失，鐵騎逼金陵。',48,'全唐诗/poet.song.159000.json','["長江天險失，鐵騎逼金陵。", "拒敵無留守，捐軀有縣丞。", "戈揮天日皎，血灑陣雲騰。", "蔣尉英靈在，千秋配食能。"]'),
('e627932e-4d68-492b-8458-28fc9e14a019','徐鳬島','王時會','宋','宋诗','song-poetry','','[]','絕壑攙空雲與平，橫飛寒瀑萬年聲。',32,'全唐诗/poet.song.159000.json','["絕壑攙空雲與平，橫飛寒瀑萬年聲。", "杖藜平過人間險，獨向千山頂上行。"]'),
('bee59b6d-041f-48ba-bbb6-8749647cb744','摘椒頌','釋浄全','宋','宋诗','song-poetry','','[]','含烟带露已經秋，顆顆通紅氣味周。',32,'全唐诗/poet.song.159000.json','["含烟带露已經秋，顆顆通紅氣味周。", "突出眼睛開口笑，這回不戀舊枝頭。"]'),
('f6ebbbdf-6521-410e-a27c-6fa50ea0e720','答松源和尚舉竹篦話頌','釋浄全','宋','宋诗','song-poetry','','[]','黑漆竹篦握起，迅雷不及掩耳。',28,'全唐诗/poet.song.159000.json','["黑漆竹篦握起，迅雷不及掩耳。", "德山臨濟茫然，懵底如何插嘴。"]'),
('8a646ba9-ac54-4a14-bb27-57b4e967cd77','答大慧舉靈雲悟桃花頌','釋浄全','宋','宋诗','song-poetry','','[]','靈雲一見兩眉橫，引得漁翁良計生。',32,'全唐诗/poet.song.159000.json','["靈雲一見兩眉橫，引得漁翁良計生。", "白浪起時拋一釣，任教魚鼈競頭爭。"]'),
('30b67e2f-7236-480b-b3f7-9c8007b34411','自贊','釋浄全','宋','宋诗','song-poetry','','[]','匙挑不上箇村夫，文墨胸中一點無。',32,'全唐诗/poet.song.159000.json','["匙挑不上箇村夫，文墨胸中一點無。", "曾把虛空揣出骨，惡聲贏得滿江湖。"]'),
('185f7ae7-e55f-42d4-8030-79a85a69d034','頌古三首  其一','釋浄全','宋','宋诗','song-poetry','','[]','此老從來謾自誇，無端病眼見空華。',32,'全唐诗/poet.song.159000.json','["此老從來謾自誇，無端病眼見空華。", "直教當下超三際，檢點將來未到家。"]'),
('59a1f6e7-dc68-4a71-9336-f9b9cdb26422','頌古三首  其二','釋浄全','宋','宋诗','song-poetry','','[]','是見受時眼著屑，見如不受事猶乖。',32,'全唐诗/poet.song.159000.json','["是見受時眼著屑，見如不受事猶乖。", "賊身已露徒囘首，鬼面神頭一處埋。"]'),
('ca4934b3-36e2-4883-8728-216ee6561c61','頌古三首  其三','釋浄全','宋','宋诗','song-poetry','','[]','毗耶城裏老維摩，一默無言詭詐多。',32,'全唐诗/poet.song.159000.json','["毗耶城裏老維摩，一默無言詭詐多。", "三萬二千師子座，一時掀倒看如何。"]'),
('886a6c94-0a22-4b15-8af1-47b1cde6721b','竹','易元矩','宋','宋诗','song-poetry','','[]','一別虞妃去未還，愁雲空鎖九疑山。',32,'全唐诗/poet.song.159000.json','["一別虞妃去未還，愁雲空鎖九疑山。", "世間多少相思淚，洒遍修篁染不斑。"]'),
('27e7f9e5-76fa-4c0b-90da-9b3a79876a79','高宗皇帝挽詞  其一','黄倫','宋','宋诗','song-poetry','','[]','大業由身濟，中興邁百王。',48,'全唐诗/poet.song.159000.json','["大業由身濟，中興邁百王。", "憂勤三紀治，壽考九齡長。", "棄屣遺天下，乘雲返帝鄉。", "典謨應不泯，奎畫煥堯章。"]'),
('ecb896e8-7d9c-4414-a6e6-e2f2a2b29bfa','高宗皇帝挽詞  其二','黄倫','宋','宋诗','song-poetry','','[]','湖鼎丹成日，中天瑞鶴迎。',48,'全唐诗/poet.song.159000.json','["湖鼎丹成日，中天瑞鶴迎。", "愁雲迷帝幄，淚雨洒都城。", "黼翣增摧割，龍輴忽啟行。", "千官陪素仗，九殞欲無聲。"]'),
('7884f291-a082-44e7-bf90-53a7a657d6d8','句','胡有開','宋','宋诗','song-poetry','','[]','一百八景蟠繞，三十六峰囘環。',14,'全唐诗/poet.song.159000.json','["一百八景蟠繞，三十六峰囘環。"]'),
('e56c59e1-0b51-4a4c-91f2-f3a05476e340','上樓參政','邵經國','宋','宋诗','song-poetry','','[]','聞道先生欲挂冠，先生幾日出長安。',64,'全唐诗/poet.song.159000.json','["聞道先生欲挂冠，先生幾日出長安。", "去時莫待淋頭雨，歸日須防徹骨寒。", "已遂平生多少志，莫令末路去留難。", "二疏畢竟成何事，留取他年作畫看。"]'),
('65b7e4f9-fcbb-433a-bbcf-be4939c6a0ef','句','周良臣','宋','宋诗','song-poetry','','[]','却從谷口問歸樵。',8,'全唐诗/poet.song.159000.json','["却從谷口問歸樵。"]'),
('ee29e227-b40c-47cd-84a6-90cca0322809','七日發嶽麓道中尋梅不獲至十日遇雪賦此','林用中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','昨日來時萬里林，長江雪厚侵猶深。',32,'全唐诗/poet.song.159000.json','["昨日來時萬里林，長江雪厚侵猶深。", "蒼茫不見梅花意，重對晴天豁晚襟。"]'),
('d350ac14-4311-43d6-985f-0c552c3dda39','十三晨起雪晴前言果驗用定王臺韵賦詩','林用中','宋','宋诗','song-poetry','','[]','今朝風日好，抱病起登臺。',48,'全唐诗/poet.song.159000.json','["今朝風日好，抱病起登臺。", "山色愁無盡，江波去不回。", "客懷無老草，節物又疎梅。", "且莫催歸騎，憑欄更一杯。"]'),
('7d54137a-66de-455d-a71e-0928450890b1','敬夫用定王臺韵賦詩因復次韵','林用中','宋','宋诗','song-poetry','','[]','寂寞番君後，光華帝子來。',48,'全唐诗/poet.song.159000.json','["寂寞番君後，光華帝子來。", "千年遺故國，萬事只空臺。", "日月東西見，湖山表裏開。", "從知爽鳩樂，莫做雍門哀。"]'),
('260b2e54-5ccf-479d-838a-fb5ee9a3255c','至上封','林用中','宋','宋诗','song-poetry','','[]','嶽背三冬雪，真同不夜城。',48,'全唐诗/poet.song.159000.json','["嶽背三冬雪，真同不夜城。", "野烟何晃蕩，澗水助空明。", "行橐多新句，青山有舊盟。", "堂堂身世事，渠漫說三生。"]'),
('8bc7fa8b-8e17-4f2d-8015-e9151eccdb3e','後洞山口晚賦','林用中','宋','宋诗','song-poetry','','[]','西嶺更西路，雲嵐最窈深。',48,'全唐诗/poet.song.159000.json','["西嶺更西路，雲嵐最窈深。", "水流千澗底，樹合四時陰。", "更得尋幽侶，何妨擁鼻吟。", "笑看雲出岫，誰似此無心。"]'),
('4738eb61-6228-43f7-ab02-c341f0f71528','馬上口占次敬夫韵','林用中','宋','宋诗','song-poetry','','[]','寒雪飄飄白晝昏，征驄曉發向孤村。',32,'全唐诗/poet.song.159000.json','["寒雪飄飄白晝昏，征驄曉發向孤村。", "途中風物來時異，吟罷新詩擊酒尊。"]'),
('e4c71c2f-1fff-4bac-8cdd-c9787a139adb','馬上舉韓退之話口占','林用中','宋','宋诗','song-poetry','','[]','天寒愁思正茫茫，匹馬周行野樹蒼。',32,'全唐诗/poet.song.159000.json','["天寒愁思正茫茫，匹馬周行野樹蒼。", "遥想韓公昔年事，聲名留得後來香。"]'),
('4a5deec5-ebb0-4326-ad5a-5d7114948e49','雪消溪漲見山色可喜口占','林用中','宋','宋诗','song-poetry','','[]','雪消山色自青青，水漲溪流拍小汀。',32,'全唐诗/poet.song.159000.json','["雪消山色自青青，水漲溪流拍小汀。", "行客悠悠心目快，漫題新句在空屏。"]'),
('f595f075-b0e7-4342-bf52-13652e603e43','登山有作次敬夫韵','林用中','宋','宋诗','song-poetry','','[]','壁立崔嵬不計尋，千峰羅列獻奇深。',32,'全唐诗/poet.song.159000.json','["壁立崔嵬不計尋，千峰羅列獻奇深。", "等閑佇立遥觀徧，流水高山萬古心。"]'),
('8e8b7f40-8cfc-48a4-9eec-814246087919','馬跡橋','林用中','宋','宋诗','song-poetry','','[]','此日驅車馬跡橋，遠從師友步青霄。',32,'全唐诗/poet.song.159000.json','["此日驅車馬跡橋，遠從師友步青霄。", "登臨不用還歧想，爲愛山翁喜見招。"]'),
('e405ffc9-3371-4080-8ff3-bbb6e2cfe7f8','方廣道中半嶺少憩次敬夫韵','林用中','宋','宋诗','song-poetry','','[]','嶺峻山高且息肩，芒鞋踏破野雲烟。',32,'全唐诗/poet.song.159000.json','["嶺峻山高且息肩，芒鞋踏破野雲烟。", "須臾直入上方去，又是乾坤一洞天。"]'),
('b8cd2363-71ec-4e71-8fcc-23f8fffe1324','道中景物甚勝吟賞不暇敬夫有詩因次其韵','林用中','宋','宋诗','song-poetry','','[]','天外雲端磬有聲，道中景物信增新。',32,'全唐诗/poet.song.159000.json','["天外雲端磬有聲，道中景物信增新。", "徘徊吟賞天將暮，好向平原問主人。"]'),
('d2386421-8691-45ad-be9d-8f9facb5c67f','崖邊積雪取食清甚次敬夫韵','林用中','宋','宋诗','song-poetry','','[]','崖邊瓊玖吐清光，偶到山間得味嘗。',32,'全唐诗/poet.song.159000.json','["崖邊瓊玖吐清光，偶到山間得味嘗。", "一段奇香今已會，冰牙冷齒裂人腸。"]'),
('a80d6d81-5897-4448-9348-4fce7b0d4b1d','後洞雪壓竹枝橫道','林用中','宋','宋诗','song-poetry','','[]','山中景物自新奇，乘興幽人寫小詩。',32,'全唐诗/poet.song.159000.json','["山中景物自新奇，乘興幽人寫小詩。", "洞里竹枝遭雪壓，何人扶起向明時。"]'),
('37865842-750b-4943-992c-7654f8f63caf','方廣聖燈次敬夫韵','林用中','宋','宋诗','song-poetry','','[]','燈長三世火長明，千里遺蹤子細尋。',32,'全唐诗/poet.song.159000.json','["燈長三世火長明，千里遺蹤子細尋。", "自是神光能永夜，不妨金偈更降心。"]'),
('3089f2cf-4f5a-4d8e-809a-7e3827d155f9','壁間古畫精絕未聞有賞音者賦此','林用中','宋','宋诗','song-poetry','','[]','老樹參橫傍古陰，濃煙淡月試追尋。',32,'全唐诗/poet.song.159000.json','["老樹參橫傍古陰，濃煙淡月試追尋。", "自來無會丹青意，可惜良工苦片心。"]'),
('d8a4fc0a-2059-4bb9-98a0-26970881c8e1','方廣奉懷定叟','林用中','宋','宋诗','song-poetry','','[]','相從偶到招提寺，獨對西風憶羽人。',32,'全唐诗/poet.song.159000.json','["相從偶到招提寺，獨對西風憶羽人。", "澹泊煙霞深處卧，百年衣鉢此生身。"]'),
('0d639dba-c630-448c-bd1f-7506a42b9c88','賦羅漢果','林用中','宋','宋诗','song-poetry','','[]','團團碩果自流黄，羅漢芳名托上方。',32,'全唐诗/poet.song.159000.json','["團團碩果自流黄，羅漢芳名托上方。", "寄語山僧留待客，多些滋味煮成湯。"]'),
('6ce8cb2e-ce06-4c5e-a682-a17b6276351f','方廣版屋','林用中','宋','宋诗','song-poetry','','[]','上方古棟宇，年久自參差。',24,'全唐诗/poet.song.159000.json','["上方古棟宇，年久自參差。", "動我行人想，相看各賦詩。"]'),
('3df797c6-8a5e-4ed8-b23f-13b04ef4ea41','泉聲','林用中','宋','宋诗','song-poetry','','[]','穿雲絡日苦悲吟，澗底潺潺覓好音。',32,'全唐诗/poet.song.159000.json','["穿雲絡日苦悲吟，澗底潺潺覓好音。", "絃管笙簧寒碎玉，源頭深處細追尋。"]'),
('fc8487cf-ce78-46e6-9d59-f737b62a6199','霜月','林用中','宋','宋诗','song-poetry','','[]','雪霽雲收月滿天，冰輪碾轉浄無煙。',32,'全唐诗/poet.song.159000.json','["雪霽雲收月滿天，冰輪碾轉浄無煙。", "幾迴寒色侵人冷，底信清光永夜娟。"]'),
('a439ba54-dcea-47ae-b8b2-3eaf8be64415','枯木','林用中','宋','宋诗','song-poetry','','[]','數年抱葉不萌芽，終歲淹淹絕蘚花。',32,'全唐诗/poet.song.159000.json','["數年抱葉不萌芽，終歲淹淹絕蘚花。", "廊廟大材工舍用，何須把節向人誇。"]'),
('641e873a-87c7-4c79-a984-e8ee682eef1a','夜宿方廣聞長老守榮化去敬夫感而賦詩次韵','林用中','宋','宋诗','song-poetry','','[]','上方長老已尋真，禪室空存錫杖新。',32,'全唐诗/poet.song.159000.json','["上方長老已尋真，禪室空存錫杖新。", "自是屋梁留夜月，可憐飄泊係留身。"]'),
('c4227328-efc4-4dfe-87a5-a4bab9157843','蓮花峰次敬夫韵','林用中','宋','宋诗','song-poetry','','[]','十丈花開自白蓮，峰頭花色更鮮妍。',32,'全唐诗/poet.song.159000.json','["十丈花開自白蓮，峰頭花色更鮮妍。", "分明會得濂溪趣，强作新詩續古篇。"]'),
('dfcb4251-ac76-4fac-a012-6d6015faf78a','殘雪未消','林用中','宋','宋诗','song-poetry','','[]','凍壓林巢欲墮鴉，素花飄落結煙霞。',32,'全唐诗/poet.song.159000.json','["凍壓林巢欲墮鴉，素花飄落結煙霞。", "陰風慘淡青山老，不辨梅花與雪花。"]'),
('be17d6a4-b779-4b62-b54e-595c4c166843','行林間幾三十里寒甚道旁有殘火溫酒舉白方覺有暖意次敬夫韵','林用中','宋','宋诗','song-poetry','','[]','高山絕頂雪千堆，凜裂冰膚這幾回。',32,'全唐诗/poet.song.159000.json','["高山絕頂雪千堆，凜裂冰膚這幾回。", "行到林間得殘火，借它燃燼暖寒杯。"]'),
('c4778fed-f6a6-4d21-aefb-b2c38cf69780','福巖寺回望嶽市','林用中','宋','宋诗','song-poetry','','[]','福巖寶地幾千年，宮殿朦朧鎖暮煙。',32,'全唐诗/poet.song.159000.json','["福巖寶地幾千年，宮殿朦朧鎖暮煙。", "遊客回頭懷想望，自知身在寂寥天。"]'),
('eefbc70d-d6f2-4b43-8780-339eaadf3ff0','福巖寺讀張南湖舊詩','林用中','宋','宋诗','song-poetry','','[]','名公有意著新書，翰墨精神碧玉姿。',32,'全唐诗/poet.song.159000.json','["名公有意著新書，翰墨精神碧玉姿。", "今日山中纔讀罷，經行已續少陵詩。"]'),
('55868ca5-06c0-4e27-8065-0cac28f47656','登祝融口占','林用中','宋','宋诗','song-poetry','','[]','托身天際外，寄足在雲端。',48,'全唐诗/poet.song.159000.json','["托身天際外，寄足在雲端。", "俯仰心猶壯，登臨眼盡寬。", "乾坤真景界，風雪倍朝寒。", "忽起煙霞想，相從結大還。"]'),
('775fd681-b6a4-45c2-8bfd-2f49d3d85211','晚霞','林用中','宋','宋诗','song-poetry','','[]','晚霞掩映祝融峰，衡嶽高低爛熳紅。',32,'全唐诗/poet.song.159000.json','["晚霞掩映祝融峰，衡嶽高低爛熳紅。", "願學陵陽修煉術，朝餐一片趁天風。"]'),
('199ba95b-3d0b-4c28-bdfa-0b45ec709a1f','贈上封諸老','林用中','宋','宋诗','song-poetry','','[]','上封臺觀靜，夕霽景偏清。',48,'全唐诗/poet.song.159000.json','["上封臺觀靜，夕霽景偏清。", "月下聞禪語，風中有磬聲。", "龍池留古蹟，雁塔寄餘情。", "借問房前樹，東窗忽偃生。"]'),
('b3ada42f-a859-4290-b974-4657c2efde42','醉下祝融峰','林用中','宋','宋诗','song-poetry','','[]','祝融高處怯寒風，浩蕩飄凌震我胸。',32,'全唐诗/poet.song.159000.json','["祝融高處怯寒風，浩蕩飄凌震我胸。", "今日與君同飲罷，願狂酩酊下遥峰。"]'),
('7c031c3b-f575-4f4b-ad4c-0f01aa69572a','林間殘雪時落鏘然有聲賦此','林用中','宋','宋诗','song-poetry','','[]','天花亂落類瓊瑶，遊賞行人覺路遥。',32,'全唐诗/poet.song.159000.json','["天花亂落類瓊瑶，遊賞行人覺路遥。", "林畔殘枝猶被壓，數聲佩玉遍青霄。"]'),
('633dfdff-4eec-4b88-9ca7-51c1e8890ea7','石廩峰次敬夫韵','林用中','宋','宋诗','song-poetry','','[]','石廩峰高直插天，芳名耿耿舊流傳。',32,'全唐诗/poet.song.159000.json','["石廩峰高直插天，芳名耿耿舊流傳。", "好推佳惠敷寰宇，始信人間大有年。"]'),
('b5db3ff5-9324-4cea-a3fe-47d57374aa80','自西園登山宿方廣寺','林用中','宋','宋诗','song-poetry','','[]','登山極目望，梵宇自鮮明。',48,'全唐诗/poet.song.159000.json','["登山極目望，梵宇自鮮明。", "風度閑花落，雲低野樹清。", "夜長人不寐，地僻月初生。", "明發又歸去，何能已此情。"]'),
('d621a116-7850-4ce5-acb2-89a4e6a49a8d','十五日再登祝融峰用臺字韵','林用中','宋','宋诗','song-poetry','','[]','惆悵獨徘徊，晴嵐遶古臺。',48,'全唐诗/poet.song.159000.json','["惆悵獨徘徊，晴嵐遶古臺。", "日從東海上，人自北山回。", "峰老曾經雪，天寒不放梅。", "野僧憐我倦，相觀酒盈杯。"]'),
('a106a118-c079-41a2-b16d-78985934abab','方廣寺睡覺次敬夫韵','林用中','宋','宋诗','song-poetry','','[]','寒溜山房太慘情，夜長枕畔聽泉聲。',32,'全唐诗/poet.song.159000.json','["寒溜山房太慘情，夜長枕畔聽泉聲。", "起來獨自渾無語，牢落凄涼澹泊清。"]'),
('6fcc381d-0ed2-4d05-a5d6-0ea8bdee48bc','渡興樂江望祝融','林用中','宋','宋诗','song-poetry','','[]','今日溪雲迷小槎，層層錦浪映晴霞。',32,'全唐诗/poet.song.159000.json','["今日溪雲迷小槎，層層錦浪映晴霞。", "須臾直至前村去，遥望羣峰真可誇。"]'),
('dfae0523-8117-4663-addf-728cb739f283','嶽後步月','林用中','宋','宋诗','song-poetry','','[]','轉缺霜輪出海邊，故人千里共嬋娟。',32,'全唐诗/poet.song.159000.json','["轉缺霜輪出海邊，故人千里共嬋娟。", "山陰此夜明如練，月白風清人未眠。"]'),
('08908d4e-c52a-4e1c-aba6-913ff7a034ec','過高臺獲信老詩集','林用中','宋','宋诗','song-poetry','','[]','今朝移步野雲端，幸得新詩讀夜闌。',32,'全唐诗/poet.song.159000.json','["今朝移步野雲端，幸得新詩讀夜闌。", "識破中間真隠訣，月明風雪道休寒。"]'),
('dee2b589-ffe7-4909-9872-dab2c4704a1e','自上封下福巖道旁訪李鄴侯書堂山路榛合不可往矣遂賦此','林用中','宋','宋诗','song-poetry','','[]','百年古路已成荒，今日人稱相國堂。',32,'全唐诗/poet.song.159000.json','["百年古路已成荒，今日人稱相國堂。", "麟鳳已歸天上去，空留遺像在斜陽。"]'),
('7e39c310-755b-434c-82b7-667dcd1ca06a','夜得嶽後菴僧家園新茶甚不多輒分數碗奉伯承','林用中','宋','宋诗','song-poetry','','[]','芽吐金英風味長，我于僧舍得先嘗。',32,'全唐诗/poet.song.159000.json','["芽吐金英風味長，我于僧舍得先嘗。", "飲時各盡盧仝量，去膩除繁有遠香。"]'),
('795b34e3-6317-4ceb-acff-03e83234f3c5','自方廣過高臺賦此','林用中','宋','宋诗','song-poetry','','[]','山雲迷古寺，曙色照孤城。',48,'全唐诗/poet.song.159000.json','["山雲迷古寺，曙色照孤城。", "禪境風偏好，空門眼倍明。", "逢僧敘舊話，對客結新盟。", "□□□□□，□□□□生。"]'),
('1d92864a-b9f2-4237-bd1c-2dc0e3aa9b8c','胡文廣仲與范伯崇自嶽市來同登絕頂舉酒極談得聞比日講論之樂','林用中','宋','宋诗','song-poetry','','[]','自得中峰住，憐君冒雪來。',48,'全唐诗/poet.song.159000.json','["自得中峰住，憐君冒雪來。", "共登福岩寺，齊上古層臺。", "斗酒酬佳興，詩懷喜獨開。", "飄然塵世隔，談論轉堪哀。"]'),
('c416cf38-a6c3-41c8-b547-4785527c31a8','題福巖寺','林用中','宋','宋诗','song-poetry','','[]','久慕雲間寺，相從此日來。',48,'全唐诗/poet.song.159000.json','["久慕雲間寺，相從此日來。", "山僧留客坐，野老把松栽。", "地拱千尋險，天遮四面開。", "殷勤方外望，塵事不勝哀。"]'),
('f9145085-d52b-457b-94eb-820853df41f5','題福巖寺 題南臺','林用中','宋','宋诗','song-poetry','','[]','山高聳樓觀，天際有瑶臺。',48,'全唐诗/poet.song.159000.json','["山高聳樓觀，天際有瑶臺。", "地僻煙霞靜，門空雲霧開。", "輿圖真絕域，形勝實崔巍。", "久以平生慕，今年始得來。"]'),
('5343a3bf-ec29-451c-8075-85d98a61e043','同遊嶽麓道遇大雪馬上次敬夫韵','林用中','宋','宋诗','song-poetry','','[]','遥瞻衡嶽頂，雲盡碧參差。',144,'全唐诗/poet.song.159000.json','["遥瞻衡嶽頂，雲盡碧參差。", "人從南方至，雪墜西崖垂。", "談玄問老子，鳴佩邀神妃。", "飛花舞瓊瑶，青壁比珠璣。", "平生山水興，行止只自知。", "飄颻凌浩蕩，猶恐太白低。", "松持歲寒操，梅放冰雪姿。", "迢遞崑崙顛，俯仰動遐思。", "茲峰名天下，突兀真絕奇。", "行行將易晚，去去尚追隨。", "我愛君飲酒，君愛我賦詩。", "相看各惆悵，勉旃在明時。"]'),
('a9cd9a36-6156-4836-bd85-2ff14a29944b','遊南嶽風雪未已决策登山用敬夫春風樓韵','林用中','宋','宋诗','song-poetry','','["\u8861\u5c71"]','人言南山顛，煙霞聳樓觀。',96,'全唐诗/poet.song.159000.json','["人言南山顛，煙霞聳樓觀。", "俯瞰了坤倪，仰攀接天漢。", "勇往愧未能，長吟湘水畔。", "茲來渺遐思，風雪豈中斷。", "行行重行行，敢起自晝嘆。", "我聞精神交，石裂冰可泮。", "陰沴驅層霄，杲日麗旭旦。", "决策君勿疑，此理或通貫。"]'),
('94c14b72-744f-4f6f-b2bd-564e3ceac180','將下山有作','林用中','宋','宋诗','song-poetry','','[]','昔日乘輿住此山，愛山五日住山間。',32,'全唐诗/poet.song.159000.json','["昔日乘輿住此山，愛山五日住山間。", "今朝忽動思歸興，得伴先生杖屨還。"]'),
('a43e8f7b-81d8-4707-875d-09ccc921fa05','十六日下山各賦二篇以紀時事云','林用中','宋','宋诗','song-poetry','','[]','匹馬返歸程，天寒雪眼明。',48,'全唐诗/poet.song.159000.json','["匹馬返歸程，天寒雪眼明。", "無窮身外事，難了世間情。", "客向天邊去，風含玉佩聲。", "別離與僧約，明歲再來迎。"]'),
('ca925be7-e26c-43e3-b2b8-8b87552b173e','又和敬夫韵','林用中','宋','宋诗','song-poetry','','[]','青山不老千年在，白髮如絲兩鬢新。',32,'全唐诗/poet.song.159000.json','["青山不老千年在，白髮如絲兩鬢新。", "歷盡高山數萬里，未知何路是爲真。"]'),
('6dae3a1b-3457-4418-9f26-ed8291623d4a','登山回','林用中','宋','宋诗','song-poetry','','[]','勝概峰頭寺，尋幽客自來。',48,'全唐诗/poet.song.159000.json','["勝概峰頭寺，尋幽客自來。", "泉聲澗分細，山色翠成堆。", "踏破千崖雪，還聞一夜雷。", "東林期擬結，卧石夢忘回。"]'),
('7bb4e44b-fb4b-416d-85de-b8c93943fe0a','于尉以書室新成惠詩次韻','舒邦佐','宋','宋诗','song-poetry','','[]','無數雲山簇眼前，又聽風葉響琤然。',64,'全唐诗/poet.song.159000.json','["無數雲山簇眼前，又聽風葉響琤然。", "近于此處開三徑，準擬歸來受一廛。", "終日看山忘坐卧，有時扃戶鎖風烟。", "尋花問柳如乘興，且莫輕回訪戴船。"]'),
('8b5c5000-ebf2-458b-be33-1894b7640418','于尉惠詩有流落之歎次韻招飲','舒邦佐','宋','宋诗','song-poetry','','[]','一紙西風書客愁，愁來如瀉滿汀洲。',64,'全唐诗/poet.song.159000.json','["一紙西風書客愁，愁來如瀉滿汀洲。", "從他夢鹿還爭鹿，休問封侯與不侯。", "百歲光陰草頭露，一年好景菊花秋。", "人生能著幾緉屐，且爲重陽一醉不。"]'),
('8809bd60-fac2-40f0-b4cf-49544a88e86d','書堂前植竹今日移梅於其間','舒邦佐','宋','宋诗','song-poetry','','[]','三徑向來孤竹弟，一枝今日伴梅兄。',32,'全唐诗/poet.song.159000.json','["三徑向來孤竹弟，一枝今日伴梅兄。", "歲寒圖上曾相識，一笑相看自有情。"]'),
('611b5bf6-b0cf-4a74-aced-763dadc1e7ae','戴氏樓名折桂來覓詩賦二十八字','舒邦佐','宋','宋诗','song-poetry','','[]','秋入高樓風露凉，疑從月裏送清香。',32,'全唐诗/poet.song.159000.json','["秋入高樓風露凉，疑從月裏送清香。", "五枝高折非難事，問取燕山竇十郎。"]'),
('e17660ea-28b0-4def-9a4d-54fcb6101f3c','偶書','舒邦佐','宋','宋诗','song-poetry','','[]','酒盡瓶乾一再添，朔風吹葉響階前。',32,'全唐诗/poet.song.159000.json','["酒盡瓶乾一再添，朔風吹葉響階前。", "起來水墨圖中望，正是江南欲雪天。"]'),
('486151e2-0dfd-4c81-bd6a-b01e132db198','和許宰于尉間字韻詩後一首送其子赴太學  其一','舒邦佐','宋','宋诗','song-poetry','','[]','連珠疊璧照窗間，得句須知出等閒。',64,'全唐诗/poet.song.159000.json','["連珠疊璧照窗間，得句須知出等閒。", "有似弟兄花萼集，更如大小淮南山。", "言詩自愧知來賜，聞十如何敢望顔。", "一夜不眠追險韻，起來疏髮有詩斑。"]'),
('2db2919d-1704-436d-bf2f-004e84534f9a','和許宰于尉間字韻詩後一首送其子赴太學  其二','舒邦佐','宋','宋诗','song-poetry','','[]','籋雲追電笑談間，爭看驊騮出帝閑。',64,'全唐诗/poet.song.159000.json','["籋雲追電笑談間，爭看驊騮出帝閑。", "暫借短檠賒眼力，莫因遠別夢眉山。", "詩聞庭下頻趨鯉，易在牀頭久鑄顔。", "趁取雙親皆未老，綠衣歸換綵衣斑。"]'),
('c2c8127a-0592-4c24-96d2-577d3a07b152','和懶窩嚴上人紙被詩','舒邦佐','宋','宋诗','song-poetry','','[]','身清不受人間辱，只倩溪翁搗冰縠。',64,'全唐诗/poet.song.159000.json','["身清不受人間辱，只倩溪翁搗冰縠。", "素濤照眼絕針痕，暖玉遮頭無臉粟。", "參寥已似絮沾泥，天女雖來暖非肉。", "華鯨吼吼不成眠，蝴蝶蘧蘧猶未足。"]'),
('07a67960-3e82-4319-b13f-6238fec279da','雨後書懷','舒邦佐','宋','宋诗','song-poetry','','[]','策策西風兩鬢秋，瘦藤獨倚思悠悠。',64,'全唐诗/poet.song.159000.json','["策策西風兩鬢秋，瘦藤獨倚思悠悠。", "送凉小雨勾牽睡，潑面新醅斷送愁。", "涉世已經三折臂，浮生空白一分頭。", "流行坎止隨天意，且著烟簑上釣舟。"]'),
('059dfaf2-45fb-499f-adf5-3c3e0747fb1f','和于湖集茶韻三首  其一','舒邦佐','宋','宋诗','song-poetry','','[]','倒牀鼻息欲鳴雷，須仗靈芽一喚回。',32,'全唐诗/poet.song.159000.json','["倒牀鼻息欲鳴雷，須仗靈芽一喚回。", "此味直教真性在，切防勾賊用鹽梅。"]'),
('b59154ce-1339-4dc9-ba63-3e4e160326a0','和于湖集茶韻三首  其二','舒邦佐','宋','宋诗','song-poetry','','[]','金沙泉下喊春雷，貢茗先隨造化回。',32,'全唐诗/poet.song.159000.json','["金沙泉下喊春雷，貢茗先隨造化回。", "欲望頭綱分八餠，恨無筆力繼歐梅。"]'),
('0a4d9918-65f1-4a9c-ae39-5ec106e1d7a3','和于湖集茶韻三首  其三','舒邦佐','宋','宋诗','song-poetry','','[]','氣味相投陳與雷，有時煎點兩三回。',32,'全唐诗/poet.song.159000.json','["氣味相投陳與雷，有時煎點兩三回。", "午窗睡著呼湯急，止渴還應似望梅。"]'),
('1c61032a-ea92-4b70-b752-cef4bf23dbfb','曉起','舒邦佐','宋','宋诗','song-poetry','','[]','風葉下宿雨，菰蒲作秋聲。',48,'全唐诗/poet.song.159000.json','["風葉下宿雨，菰蒲作秋聲。", "起頭望天宇，凉意翛翛生。", "欲挽天河水，一洗塵土纓。", "誰人插兩翼，送我上太清。"]'),
('9b3046a3-a5aa-4058-8ffb-bb6eb53f8083','晚出','舒邦佐','宋','宋诗','song-poetry','','[]','晚徑收霜滑，青鞋踏淺沙。',48,'全唐诗/poet.song.159000.json','["晚徑收霜滑，青鞋踏淺沙。", "看雲閒活計，臨水淡生涯。", "籬菊猶存葉，江梅欲破花。", "楓林凋落盡，露出兩三家。"]'),
('5856b5e9-d305-42dc-aae0-3752a16c8e05','夜坐','舒邦佐','宋','宋诗','song-poetry','','[]','霜蟾照戶鼓三更，獨坐蒲團一盞燈。',32,'全唐诗/poet.song.159000.json','["霜蟾照戶鼓三更，獨坐蒲團一盞燈。", "名利此時都踏破，分明一箇在家僧。"]'),
('099e1a41-b280-4560-84f5-1d0ea088623b','天寒偶成','舒邦佐','宋','宋诗','song-poetry','','[]','雲凍長空鋪水墨，風鳴破屋響琅玕。',64,'全唐诗/poet.song.159000.json','["雲凍長空鋪水墨，風鳴破屋響琅玕。", "憶梅探梅春已露，欲雪不雪天正寒。", "呵筆豈能詩句好，擁爐偏怕酒瓶乾。", "太平宰相非吾望，煨芋何須問懶殘。"]'),
('23917978-3be4-4e31-bd0c-99e674957200','喜雪二首  其一','舒邦佐','宋','宋诗','song-poetry','','[]','光入疎櫺曉色添，開門猶認蝶飛簾。',64,'全唐诗/poet.song.159000.json','["光入疎櫺曉色添，開門猶認蝶飛簾。", "千山陡失青絲障，萬戶橫拖白玉簷。", "壓竹重時疑綠折，著花輕處露紅尖。", "自慚對景無佳句，空笑當時絮與鹽。"]'),
('b8b22e00-f945-4244-8a1b-1c83a0ccc6ab','喜雪二首  其二','舒邦佐','宋','宋诗','song-poetry','','[]','未問街頭酒價添，迎光先捲讀書簾。',64,'全唐诗/poet.song.159000.json','["未問街頭酒價添，迎光先捲讀書簾。", "送寒作片頻窺戶，著暖先融半溜簷。", "莫作檜花添項强，且隨梅點閙眉尖。", "叮嚀勿壓南枝折，商鼎調羹待作鹽。"]'),
('d49538cc-5fd3-4e3c-98fb-b5b58d4b7529','余本不能棋因病又止酒','舒邦佐','宋','宋诗','song-poetry','','[]','圍棋賭別墅，斗酒博涼州。',60,'全唐诗/poet.song.159000.json','["圍棋賭別墅，斗酒博涼州。", "驅之奪名利，誰信可銷愁。", "不如陶靖節，客至空持甌。", "不如蘇東坡，勝敗兩忘憂。", "此心無外累，雲浄一天秋。"]'),
('9662de72-0118-4b32-96b5-e0d859c8a4e9','詠蒲團','舒邦佐','宋','宋诗','song-poetry','','[]','細觀才滿一輪月，靜坐能銷萬古心。',32,'全唐诗/poet.song.159000.json','["細觀才滿一輪月，靜坐能銷萬古心。", "莫向洪爐烘醉客，只宜清夜定禪林。"]'),
('f86cbe4a-90fb-429b-80c5-0486575a1f79','讀子厚乞巧文','舒邦佐','宋','宋诗','song-poetry','','[]','不見牛郎不秉鈞，一時雖拙有清芬。',32,'全唐诗/poet.song.159000.json','["不見牛郎不秉鈞，一時雖拙有清芬。", "附棋待詔皆因巧，何用翻成乞巧文。"]'),
('5ffafc18-e0bf-4864-a93c-25aac19d7afa','著存亭','舒邦佐','宋','宋诗','song-poetry','','[]','事亡如存死如生，以誠則著著乃形。',208,'全唐诗/poet.song.159000.json','["事亡如存死如生，以誠則著著乃形。", "二字貌出孝子誠，曉然如見親在庭。", "有人念母愁思凝，終日如癡呼不醒。", "自云所見政如此，觸物有感皆分明。", "山形作我枕扇清，風葉舞我萊衫輕。", "江蘆千株白皎皎，尚想鶴髮垂星星。", "入戶宛然聞愾息，恍惚欲下來舉觥。", "始知至孝無間斷，聖人所以見牆羹。", "譬如忠信純熟者，立則參前坐倚衡。", "然而存著亦非真，能于吾母用吾情。", "所見皆從所念得，初非刻木外經營。", "雖然銘鏤在中扃，何待扁榜垂丹青。", "要令目擊助心想，不然安得名吾亭。"]'),
('7e2403d7-e5c3-4681-8bd9-2747f992daee','挽黄助教四首  其一','舒邦佐','宋','宋诗','song-poetry','','[]','金鎞刮膜妙通靈，從此昏花不再生。',32,'全唐诗/poet.song.159000.json','["金鎞刮膜妙通靈，從此昏花不再生。", "聞道向來昏醉眼，而今黑白儘分明。"]'),
('3fb06ce5-5c28-42ed-9e1a-484c74beda3a','挽黄助教四首  其二','舒邦佐','宋','宋诗','song-poetry','','[]','有客携來幼婦碑，細看一字是褒辭。',32,'全唐诗/poet.song.159000.json','["有客携來幼婦碑，細看一字是褒辭。", "觸蠻索戰吾無此，方信黄家萬頃陂。"]'),
('9f05eb90-2fd3-4fa1-9400-647615ef3b25','挽黄助教四首  其三','舒邦佐','宋','宋诗','song-poetry','','[]','楊枝一放任西東，已把浮生比夢中。',32,'全唐诗/poet.song.159000.json','["楊枝一放任西東，已把浮生比夢中。", "今日算來真是夢，翩翩丹旐引春風。"]'),
('ed641144-a4dc-4ab3-97b1-8e048a1cb237','挽黄助教四首  其四','舒邦佐','宋','宋诗','song-poetry','','[]','春歸平日館池中，想是園花三四紅。',32,'全唐诗/poet.song.159000.json','["春歸平日館池中，想是園花三四紅。", "還有舊時王謝燕，喃喃來弔主人翁。"]'),
('0f65cdd2-f3b2-4add-8616-afbef3754fd7','于尉燈夜招飲酒酣援筆成詩繼韻','舒邦佐','宋','宋诗','song-poetry','','[]','低唱雖無金步蓮，公來處處已聞絃。',64,'全唐诗/poet.song.159000.json','["低唱雖無金步蓮，公來處處已聞絃。", "滿街燈火作元夕，此段風光勝去年。", "紙上飛雲驚落筆，盤中走彈喜詩圓。", "便宜歸侍傳柑宴，滿泛錢塘藥玉船。"]'),
('1129a1b3-3664-4e2c-a8f2-96b2eac9dba6','和洪龜父歲暮韻','舒邦佐','宋','宋诗','song-poetry','','[]','兩鬢點秋霜，黑白交相互。',60,'全唐诗/poet.song.159000.json','["兩鬢點秋霜，黑白交相互。", "倒指數行年，如日斜歲暮。", "始汙千佛經，頗歎儒冠誤。", "夜聲喧爆竹，曉炬驚鴉樹。", "又是一年新，三百六十度。"]'),
('00392b7a-83ce-485b-906b-c5a509cf64ed','睡起二首  其一','舒邦佐','宋','宋诗','song-poetry','','[]','雙雙燕語落簷牙，驚破春屏夢到家。',32,'全唐诗/poet.song.159000.json','["雙雙燕語落簷牙，驚破春屏夢到家。", "睡起拈書無意緒，開窗隠几看桃花。"]'),
('62979db5-9362-4be0-bdb1-ede67626c9eb','睡起二首  其二','舒邦佐','宋','宋诗','song-poetry','','[]','蝶夢驚回思尚迷，起煎蟹眼試新旗。',32,'全唐诗/poet.song.159000.json','["蝶夢驚回思尚迷，起煎蟹眼試新旗。", "桃花貼地楊花起，正是江南二月時。"]'),
('59adfa2d-76af-47d2-bbee-d36c2827d282','慕容簿送題寶峰石刻并中秋詞以詩謝之  其一','舒邦佐','宋','宋诗','song-poetry','','[]','步屧尋僧到日西，亂山深處見新碑。',32,'全唐诗/poet.song.159000.json','["步屧尋僧到日西，亂山深處見新碑。", "却驚天上披風手，亦卷波瀾入小詩。"]'),
('99fb6061-fc54-4261-bd8c-14c576e20b8e','慕容簿送題寶峰石刻并中秋詞以詩謝之  其二','舒邦佐','宋','宋诗','song-poetry','','[]','月入中秋色滿林，摹將好景寄清音。',32,'全唐诗/poet.song.159000.json','["月入中秋色滿林，摹將好景寄清音。", "自從句奪天工巧，景物無聊直至今。"]'),
('d503d92b-3882-46c6-8571-31a971a559b0','以魯直露溼何郎試湯餠爲韻賦酴醾七首  其一','舒邦佐','宋','宋诗','song-poetry','','[]','石竹麝香臍，博山水沈炷。',24,'全唐诗/poet.song.159000.json','["石竹麝香臍，博山水沈炷。", "勾引愛香人，攀花春筍露。"]'),
('396db0d9-a07e-4cd9-95f6-aef41a8f60bf','以魯直露溼何郎試湯餠爲韻賦酴醾七首  其二','舒邦佐','宋','宋诗','song-poetry','','[]','江南萬玉妃，肌膚冰雪立。',24,'全唐诗/poet.song.159000.json','["江南萬玉妃，肌膚冰雪立。", "平生愛淡粧，不作胭脂溼。"]'),
('340559f9-656d-475a-92e2-f091d1a4df48','以魯直露溼何郎試湯餠爲韻賦酴醾七首  其三','舒邦佐','宋','宋诗','song-poetry','','[]','金沙與同架，並蒂更連柯。',24,'全唐诗/poet.song.159000.json','["金沙與同架，並蒂更連柯。", "紅白雖相宜，品藻當如何。"]'),
('4a470575-93a9-4779-bf05-d83e391c1459','以魯直露溼何郎試湯餠爲韻賦酴醾七首  其四','舒邦佐','宋','宋诗','song-poetry','','[]','倚窗春睡覺，折玉滿手香。',24,'全唐诗/poet.song.159000.json','["倚窗春睡覺，折玉滿手香。", "篸雲疑未穩，指點問檀郎。"]'),
('d3cb04c1-ad28-4f69-bbcb-1efa128a8d87','以魯直露溼何郎試湯餠爲韻賦酴醾七首  其五','舒邦佐','宋','宋诗','song-poetry','','[]','何面與荀香，美丈夫可試。',24,'全唐诗/poet.song.159000.json','["何面與荀香，美丈夫可試。", "不學海棠花，只如妃子睡。"]'),
('f980d54f-989a-4483-91e5-ce8a0fe612ed','以魯直露溼何郎試湯餠爲韻賦酴醾七首  其六','舒邦佐','宋','宋诗','song-poetry','','[]','昨日落酒杯，引我卧醉鄉。',24,'全唐诗/poet.song.159000.json','["昨日落酒杯，引我卧醉鄉。", "對午猶未醒，支頤聽煮湯。"]'),
('135fd7f0-470c-49f4-85c1-de0785481ff8','以魯直露溼何郎試湯餠爲韻賦酴醾七首  其七','舒邦佐','宋','宋诗','song-poetry','','[]','愛花莫看花，如饑貪畫餠。',24,'全唐诗/poet.song.159000.json','["愛花莫看花，如饑貪畫餠。", "一笑大江橫，此句須參請。"]'),
('336fa168-750e-4e32-ac89-1aa6532da9e4','以昌黎驗長常携尺爲韻賦筍五首  其一','舒邦佐','宋','宋诗','song-poetry','','[]','前晚尚錐鋒，昨日突鎗劍。',24,'全唐诗/poet.song.159000.json','["前晚尚錐鋒，昨日突鎗劍。", "今朝又稍長，吾曾刻竹驗。"]'),
('e10e50ac-8fc7-48d3-85b4-6b833c6cb04a','以昌黎驗長常携尺爲韻賦筍五首  其二','舒邦佐','宋','宋诗','song-poetry','','[]','突兀出藩來，頗似逞狂蕩。',24,'全唐诗/poet.song.159000.json','["突兀出藩來，頗似逞狂蕩。", "高下列階前，又如識少長。"]'),
('0e7bddbc-fc84-4526-9bf4-4cc6e2b7c89a','以昌黎驗長常携尺爲韻賦筍五首  其三','舒邦佐','宋','宋诗','song-poetry','','[]','行矣脫錦綳，笙竽奏風篁。',24,'全唐诗/poet.song.159000.json','["行矣脫錦綳，笙竽奏風篁。", "歲晚尤可敬，霜雪不改常。"]'),
('4177b866-8cc2-42ed-bbe9-4c1a7226ebca','以昌黎驗長常携尺爲韻賦筍五首  其四','舒邦佐','宋','宋诗','song-poetry','','[]','吾家蒼頭奴，斫玉手自携。',24,'全唐诗/poet.song.159000.json','["吾家蒼頭奴，斫玉手自携。", "云恐春風惡，吹開枝高低。"]'),
('325c8142-407a-439f-866e-7e090645d5e5','以昌黎驗長常携尺爲韻賦筍五首  其五','舒邦佐','宋','宋诗','song-poetry','','[]','我至再三惜，恨不長百尺。',24,'全唐诗/poet.song.159000.json','["我至再三惜，恨不長百尺。", "要夏結清陰，蔭我醉眠石。"]'),
('3b251b5e-c1d1-4022-9762-65d2b3a8e64a','雨後即事','舒邦佐','宋','宋诗','song-poetry','','[]','昨日雨不歇，薄晚雲未收。',216,'全唐诗/poet.song.159000.json','["昨日雨不歇，薄晚雲未收。", "更闌望天宇，雲浄月如鈎。", "曉開讀書窗，日光潑雙眸。", "蔬飯羹一盂，起傍吾廬游。", "一洗塵土昏，水竹清更幽。", "問花無恙否，低面含嬌羞。", "驗筍長幾何，突角凌羊牛。", "前日移新荷，常恐水蓋頭。", "池邊報平安，小葉三四浮。", "竹林叫鈎輈，柳陰鳴栗留。", "趁晴欲雙飛，更著喚婦鳩。", "物適吾亦適，投筇思悠悠。", "却歸堂上坐，蒼頭獻茶甌。", "兒聲清且美，讀書如瀉油。", "靜裏無聲樂，閒中不繫舟。", "不知腰金公，曾識此樂不。", "我生微官縛，有如冠沐猴。", "長恐舍此去，永愧池上鷗。"]'),
('8922d7c2-9854-4519-88e3-f2461abe9b0d','回廟山放船','舒邦佐','宋','宋诗','song-poetry','','[]','快時一箭走飛篷，緩也委蛇碧玉中。',32,'全唐诗/poet.song.159000.json','["快時一箭走飛篷，緩也委蛇碧玉中。", "遲速無心安樂法，從今不怕打頭風。"]'),
('98a7d1b0-9df3-4252-a23b-39f27e12e13f','三衢阻雪至永豐道中又雪','舒邦佐','宋','宋诗','song-poetry','','[]','前日堆銀凍未消，今朝滿地踏瓊瑶。',32,'全唐诗/poet.song.159000.json','["前日堆銀凍未消，今朝滿地踏瓊瑶。", "一杯蘸甲寒威退，只要行人著酒澆。"]'),
('0fb7f9dc-30f7-468d-b32c-de3cda9bb5d7','回進賢道中','舒邦佐','宋','宋诗','song-poetry','','[]','遥憐兒女數還期，自秣歸驂趁曉雞。',32,'全唐诗/poet.song.159000.json','["遥憐兒女數還期，自秣歸驂趁曉雞。", "乾鵲有靈煩送喜，馬蹄今日踏江西。"]'),
('538fc7fa-f449-43b3-bab1-9a17f9369711','蠶婦歎','舒邦佐','宋','宋诗','song-poetry','','[]','舍南舍北爭采桑，欲老未老蠶滿筐。',64,'全唐诗/poet.song.159000.json','["舍南舍北爭采桑，欲老未老蠶滿筐。", "曉切葉縷細且長，夜夢繭簇白間黄。", "繰成萬絲手中香，醫得三月眼前瘡。", "有餘更著輸官忙，無衣敢歌卒歲章。"]'),
('8d5d5af3-103f-4839-8a82-69827cd05902','謾題','舒邦佐','宋','宋诗','song-poetry','','[]','世網角雄雌，官途爭是非。',24,'全唐诗/poet.song.159000.json','["世網角雄雌，官途爭是非。", "人方酣蟻戰，吾自送鴻飛。"]'),
('526e543b-712b-4bfa-b8cb-3c4466eb32d1','小院','舒邦佐','宋','宋诗','song-poetry','','[]','小院無人到，徐徐影轉花。',48,'全唐诗/poet.song.159000.json','["小院無人到，徐徐影轉花。", "池平初鬭蛤，柳老半藏鴉。", "矛戟猶封筍，槍旗欲試茶。", "一邱并一壑，只此是生涯。"]'),
('87a68f6b-1326-4d8f-af21-b9fc7323af25','隠几','舒邦佐','宋','宋诗','song-poetry','','[]','隠几香一炷，時于靜裏求。',48,'全唐诗/poet.song.159000.json','["隠几香一炷，時于靜裏求。", "心源須得得，世路任悠悠。", "佛國菩提樹，莊園不繫舟。", "忘機吾自信，何必驗沙鷗。"]'),
('bdf7bcc8-1c15-4c17-8823-772daeb71b28','仿古','舒邦佐','宋','宋诗','song-poetry','','[]','雪花點破潘郎鬢，始得荷衣上釣蓑。',64,'全唐诗/poet.song.159000.json','["雪花點破潘郎鬢，始得荷衣上釣蓑。", "蠶經一眠再眠後，船歷順風逆風多。", "雲烟過眼竟何有，星斗在天終不磨。", "著鞭古人乃吾事，長檠莫換短檠歌。"]'),
('ad5148c9-d2d3-4062-add4-e31c2bde347c','晚步','舒邦佐','宋','宋诗','song-poetry','','[]','晚來頗憶林塘幽，又拄烏籐款款游。',64,'全唐诗/poet.song.159000.json','["晚來頗憶林塘幽，又拄烏籐款款游。", "細雨斜風三日後，落花啼鳥半春休。", "不知何處數聲笛，喚起幽人一點愁。", "頼有青蛙知客恨，笙歌一部起池頭。"]'),
('db4a4036-f768-4412-8442-f52e125cb110','夢覺','舒邦佐','宋','宋诗','song-poetry','','[]','夢覺還尋夢，胚胎一想中。',48,'全唐诗/poet.song.159000.json','["夢覺還尋夢，胚胎一想中。", "失身邯鄲枕，得意大槐宮。", "周在蝶何在，蕉空鹿亦空。", "自憐心未靜，起坐究幡風。"]'),
('bf8b632c-fd33-4fda-9c49-37577b86e1d3','伏枕','舒邦佐','宋','宋诗','song-poetry','','[]','索索葉多雨，夢驚窗月明。',48,'全唐诗/poet.song.159000.json','["索索葉多雨，夢驚窗月明。", "一念墮世網，百慮戰心兵。", "天上麒麟閣，沙邊鷗鷺盟。", "展轉復展轉，孤鴻三兩聲。"]'),
('8d8e3cea-363b-4662-b7ce-4d4380c6fb4b','贈太素脈王道人爲端夫病起解嘲','舒邦佐','宋','宋诗','song-poetry','','[]','按指如醫細切膚，對人便肯說榮枯。',32,'全唐诗/poet.song.159000.json','["按指如醫細切膚，對人便肯說榮枯。", "我今跳出榮枯外，試問先生脈得無。"]'),
('42bf7e2c-8f99-4967-a464-bfb991e46379','贈畫魚童秀才','舒邦佐','宋','宋诗','song-poetry','','[]','我本江湖一釣徒，錦鱗到眼便歡呼。',32,'全唐诗/poet.song.159000.json','["我本江湖一釣徒，錦鱗到眼便歡呼。", "他年蓴鱠歸來日，添箇漁竿入畫圖。"]'),
('9edaae08-2c8b-4351-805a-2cdd099fe742','讀退之傳','舒邦佐','宋','宋诗','song-poetry','','[]','退之二十八，三上宰相書。',48,'全唐诗/poet.song.159000.json','["退之二十八，三上宰相書。", "晚折王廷湊，駡佛戒鱷魚。", "少時及壯時，君試觀何如。", "士養要如此，合抱凌太虛。"]'),
('0fa65545-88e7-4134-a43f-d7f9d39afa40','讀廣平梅花賦','舒邦佐','宋','宋诗','song-poetry','','[]','子猷清雅如此君，菊花冷淡如淵明。',64,'全唐诗/poet.song.159000.json','["子猷清雅如此君，菊花冷淡如淵明。", "古人嗜物非著物，風味相似因適情。", "不見鐵心宋廣平，乃肯一賦寫梅兄。", "愛渠風雪不改清，似我不肯郎張卿。"]'),
('2c2f3af6-b1cd-4f05-800c-5f5d9482e2aa','咏昭君','舒邦佐','宋','宋诗','song-poetry','','[]','奉春前日策和親，夷夏雌雄恰始分。',32,'全唐诗/poet.song.159000.json','["奉春前日策和親，夷夏雌雄恰始分。", "今日呼韓朝渭上，如何萬里嫁昭君。"]'),
('6cc8fb40-6a63-4876-b311-1cfff153b766','讀開元遺事','舒邦佐','宋','宋诗','song-poetry','','[]','錦綳兒啼妃子笑，雞頭肉念祿山來。',32,'全唐诗/poet.song.159000.json','["錦綳兒啼妃子笑，雞頭肉念祿山來。", "三郎若肯憐湯餠，豈被香囊作禍胎。"]'),
('3d5014e3-2528-4655-a6a8-47904926fbff','讀東坡韓文公廟碑','舒邦佐','宋','宋诗','song-poetry','','[]','盡道潮陽因駡佛，誰知忠諫得天知。',32,'全唐诗/poet.song.159000.json','["盡道潮陽因駡佛，誰知忠諫得天知。", "鱷魚夜徙衡雲散，請看而今玉局碑。"]'),
('c8158cb4-4b87-4d4e-9169-e8a8cbacc5ba','送簡賀州五首  其一','舒邦佐','宋','宋诗','song-poetry','','[]','人生五馬貴，畫戟擁朱輪。',48,'全唐诗/poet.song.159000.json','["人生五馬貴，畫戟擁朱輪。", "朱輪亦細事，舒卷方在身。", "官至二千石，此手要活人。", "請將胸中書，散作五嶺春。"]'),
('3e20903f-18de-4680-b19e-a23c42519f34','送簡賀州五首  其二','舒邦佐','宋','宋诗','song-poetry','','[]','朔風撼木落，莫驚客店霜。',48,'全唐诗/poet.song.159000.json','["朔風撼木落，莫驚客店霜。", "桂林雪片深，成都碧雞坊。", "西南幕中去，尚趣萬里裝。", "今乘刺史車，何嫌驛路長。"]'),
('a20732bb-a5bd-4379-9b96-3f455c766913','送簡賀州五首  其三','舒邦佐','宋','宋诗','song-poetry','','[]','曩時鹽令更，官貧如負債。',48,'全唐诗/poet.song.159000.json','["曩時鹽令更，官貧如負債。", "而今舊法復，私販奪公賣。", "且莫作是想，亟欲目前快。", "有錢藏之民，畢竟根本在。"]'),
('9fe82a41-c3ee-4ca0-8431-d5877e5ee85f','送簡賀州五首  其四','舒邦佐','宋','宋诗','song-poetry','','[]','摩挲風月堂，應記中庸公。',48,'全唐诗/poet.song.159000.json','["摩挲風月堂，應記中庸公。", "牆頭荔子熟，勿翦比國風。", "此翁出嶺來，兩頰丹砂紅。", "但云身力健，不言檳榔功。"]'),
('e7216136-f4e0-4e56-84f1-6653357801b7','送簡賀州五首  其五','舒邦佐','宋','宋诗','song-poetry','','[]','我作送行詩，勸終鋪美意。',48,'全唐诗/poet.song.159000.json','["我作送行詩，勸終鋪美意。", "吾君方急賢，侍從有虛位。", "兩府多故人，東閣欠奇士。", "如送鄭尚書，韻必以來字。"]'),
('1ecade5a-d512-4d3d-b103-3b613bdb8ac5','送陳糾','舒邦佐','宋','宋诗','song-poetry','','[]','我昔場屋計，夜傍讀書螢。',240,'全唐诗/poet.song.159000.json','["我昔場屋計，夜傍讀書螢。", "開卷啖公文，如味五侯鯖。", "今年觸熱來，著脚湘山青。", "暗中摸索著，紫髯照天庭。", "風前笑語香，陡豁病眼醒。", "一日駕征車，問訊短長亭。", "買酒酌別君，我歌君試聽。", "命薄成雌甲，字慙識一丁。", "文場與宦海，從公與乞靈。", "飄然舍我去，却作參商星。", "我歌雖不滿，民謠如轟霆。", "謂公三年留，陰德滿幽囹。", "束縛老奸手，兩造必細聆。", "民自以不冤，刑期于無刑。", "是宜薦鶚書，風吹上青冥。", "更鋪錦上花，姓名記御屏。", "不揮玉堂翰，必勒燕然銘。", "文章特一技，九鼎重朝廷。", "人生幾緉屐，早畫凌烟形。", "衡陽有來雁，一字訪風萍。"]'),
('7ccfbf7c-9f30-4472-9dc3-8df87837e26b','送湖南潘帥赴召','舒邦佐','宋','宋诗','song-poetry','','[]','道傳伊洛政龔黄，肯爲人間富貴忙。',64,'全唐诗/poet.song.159000.json','["道傳伊洛政龔黄，肯爲人間富貴忙。", "愛滿棠陰踰五嶺，種成荔子又三湘。", "貪賢急召恩雖渥，因病求閒策本長。", "聞說晦翁天下士，更將出處細商量。"]'),
('5d7ecb4d-2fc7-4483-9a07-3df2ce691de6','和林帥喜湯王二魁將還','舒邦佐','宋','宋诗','song-poetry','','["\u897f\u6e56"]','爛醉春風玉不頹，自封喜信入湘來。',64,'全唐诗/poet.song.159000.json','["爛醉春風玉不頹，自封喜信入湘來。", "同鄉多少同年士，兩榜何如兩奪魁。", "瓊苑宴開應共醉，西湖賞罷更同回。", "早歸多謝文翁力，莫待平安家信催。"]'),
('68e2f2a2-516e-440d-9c04-78e7164c016b','挽余倅二首  其一','舒邦佐','宋','宋诗','song-poetry','','[]','自踏功名地，斯心每淡如。',48,'全唐诗/poet.song.159000.json','["自踏功名地，斯心每淡如。", "東南雖數任，來往祇單車。", "上相逢知己，清時草辟書。", "才寬天命窄，轓左換靈輿。"]'),
('3d17ff66-3251-4213-9b36-104a72318b81','挽余倅二首  其二','舒邦佐','宋','宋诗','song-poetry','','[]','仕接湖南北，逢人問起居。',48,'全唐诗/poet.song.159000.json','["仕接湖南北，逢人問起居。", "蚤曾師硯席，非但托鄉閭。", "夢裏詩春草，毫端賦子虛。", "諸郎圖不朽，當共葺遺書。"]'),
('07752e18-58a5-4b81-8cd2-71f19f13e093','以詩追墨','舒邦佐','宋','宋诗','song-poetry','','[]','萬竈燒松有妙功，分張猶未及隣翁。',32,'全唐诗/poet.song.159000.json','["萬竈燒松有妙功，分張猶未及隣翁。", "陶泓毛穎來呼友，要爲幽齋草送窮。"]'),
('fe87fcdc-9f67-438a-8bc4-f350d0b062af','遺術士','舒邦佐','宋','宋诗','song-poetry','','[]','欲壽莫誇堯丙子，欲貴莫疑雌甲辰。',32,'全唐诗/poet.song.159000.json','["欲壽莫誇堯丙子，欲貴莫疑雌甲辰。", "學取燕山人姓竇，自然五桂一靈椿。"]'),
('29e26da8-1b65-4169-acd8-504c7e7037a1','聞杜鵑','舒邦佐','宋','宋诗','song-poetry','','[]','衆禽栖息不聞聲，獨向三更月裏鳴。',32,'全唐诗/poet.song.159000.json','["衆禽栖息不聞聲，獨向三更月裏鳴。", "終日勸歸歸未肯，故教枕上聽分明。"]'),
('9e858a56-ccb1-4474-8c53-51714696c74b','送張倉移漕廣西','舒邦佐','宋','宋诗','song-poetry','','[]','賓鴻度月叫秋寒，天怕炎方雨露乾。',256,'全唐诗/poet.song.159000.json','["賓鴻度月叫秋寒，天怕炎方雨露乾。", "繡衣使者持玉節，先送春風入蛋蠻。", "嶺南日日望行色，湖南百姓爭卧轍。", "兩路行人界上爭，去思來暮歌謳接。", "廣鹽變法是誰謀，直至而今病未瘳。", "嶺上逢人須細問，遠方根本是深憂。", "廣吏從來恃天遠，北歸南載無空返。", "埋輪家世本澄清，無使老蠶自營繭。", "莫嫌嶺路去逡巡，桂林見說最宜人。", "筍樣山峰羅樣水，錦囊收得越精神。", "直聲曾動天顔喜，更有元台作知己。", "諫坡言路著此翁，所謂如尊乃勇爾。", "大蘇文章繼老蘇，魏徵勳業付魏謩。", "傳家况有黄金印，行入衣冠盛事圖。", "門下書生知此意，戀戀不爲兒女計。", "黄花時節送君行，梅花時節迎歸騎。"]'),
('f77253fe-334b-47c2-8553-0739858b24b6','送孫憲就任除祕監赴召','舒邦佐','宋','宋诗','song-poetry','','[]','閶闔排雲叫玉旒，延齡不相白麻收。',320,'全唐诗/poet.song.159000.json','["閶闔排雲叫玉旒，延齡不相白麻收。", "圜橋留住不肯住，古來只說陽道州。", "千載風流正相似，難處郊禋能有幾。", "不顧諸郎尚白丁，扁舟夜發浮湘水。", "富貴酖人如蜜甜，小兒嗜蜜幾曾嫌。", "全家先遯無人覺，惟有誠齋句裏拈。", "回鴈峰前再秋色，哀矜折獄多陰德。", "彈壓湖山處處春，楚波不動平如席。", "不論朱墨細如麻，夜判千張燭有花。", "老吏相看驚吐舌，如箭中的無少差。", "世上紛紛幾桃李，過却韶華盡紛委。", "老松閲世傲風霜，萬牛挽入明光裏。", "蓬萊弱水多逆船，人生一到已稱仙。", "重來况是文章伯，豈但舊物王青氈。", "一佛出世從此度，紫薇花下皆平步。", "更看健筆繳詞頭，恰似當時在言路。", "六一老僊贊萬微，益公首轉造化機。", "廬陵自有三台種，他日聲名翦樣齊。", "三十年前韓一識，三十年後供吏役。", "朝天好施一丸丹，教我春風生羽翼。"]'),
('d7477da3-30a2-45a8-b2d2-175c93ca68d9','張推上巳出郊尋花送至詩軸次韻','舒邦佐','宋','宋诗','song-poetry','','[]','重三投曉出郊坰，躍馬歸來趁晚晴。',64,'全唐诗/poet.song.159000.json','["重三投曉出郊坰，躍馬歸來趁晚晴。", "筆卷雲烟歸賦詠，軸聯珠玉鬭晶明。", "我從多病三春裏，轉覺浮生萬事輕。", "夜半惟歌盤谷序，肯如仲叔請繁纓。"]'),
('09954391-39de-4baa-af44-ce1f17063453','張推水亭賞蓮惠詩次韻','舒邦佐','宋','宋诗','song-poetry','','[]','玉環妖血不飛天，化作芙蕖滿眼前。',64,'全唐诗/poet.song.159000.json','["玉環妖血不飛天，化作芙蕖滿眼前。", "恰有六郎來比似，便哦七字鬭清妍。", "曉粧洗露漢宮女，晚步凌波水府仙。", "得待蜜房成玉蛹，送煩纖手剝新蓮。"]'),
('e27de4dd-c005-43dc-bc1b-f12293bc5923','花光寺送使者書壁','舒邦佐','宋','宋诗','song-poetry','','[]','白沙翠竹釣魚磯，家在江南未得歸。',32,'全唐诗/poet.song.159000.json','["白沙翠竹釣魚磯，家在江南未得歸。", "最恨花光山下路，數聲杜宇背人飛。"]'),
('b3a47594-c71d-4c21-ae7e-3b3ffa2b6c78','桃花','舒邦佐','宋','宋诗','song-poetry','','[]','恨題玄都觀，歡入武陵谿。',24,'全唐诗/poet.song.159000.json','["恨題玄都觀，歡入武陵谿。", "花面無今古，人心自笑啼。"]'),
('d6cd1f42-2f32-445a-9b59-31956fe0370a','題三石屏  其一','舒邦佐','宋','宋诗','song-poetry','','[]','烟霧冥濛雨意垂，遠山隠隠抹修眉。',32,'全唐诗/poet.song.159000.json','["烟霧冥濛雨意垂，遠山隠隠抹修眉。", "急催行李投前店，似我當年在道時。"]'),
('c043af4a-c92f-401f-ab68-502a46a1595b','題三石屏  其二','舒邦佐','宋','宋诗','song-poetry','','[]','正是江南雪霽天，素娥特地弄嬋娟。',32,'全唐诗/poet.song.159000.json','["正是江南雪霽天，素娥特地弄嬋娟。", "山川一望皆如剡，只欠渠儂訪戴船。"]'),
('99a217fc-b323-4eda-8a40-51456fffc8d9','題三石屏  其三','舒邦佐','宋','宋诗','song-poetry','','[]','月姊携爐出廣寒，鎔銀爲水又爲山。',32,'全唐诗/poet.song.159000.json','["月姊携爐出廣寒，鎔銀爲水又爲山。", "夜來歸去忘收却，陷入浯溪石壁間。"]'),
('46f21c74-5e4e-408c-9773-710948ccbd84','春日即事五首  其一','舒邦佐','宋','宋诗','song-poetry','','[]','正晝東風自展扉，雙雙燕子望巢飛。',32,'全唐诗/poet.song.159000.json','["正晝東風自展扉，雙雙燕子望巢飛。", "楊花却是元無定，吹落南隣不肯歸。"]'),
('8d09dd3a-2500-4854-a554-530357f351d1','春日即事五首  其二','舒邦佐','宋','宋诗','song-poetry','','[]','架上酴醾萬玉浮，當年攀折爲遲留。',32,'全唐诗/poet.song.159000.json','["架上酴醾萬玉浮，當年攀折爲遲留。", "而今老病空相對，花不羞人人自羞。"]'),
('a1f567ae-b7e1-4cd3-aad9-b1b20fcc55f2','春日即事五首  其三','舒邦佐','宋','宋诗','song-poetry','','[]','桃杏酣酣著意紅，當時只要嫁東風。',32,'全唐诗/poet.song.159000.json','["桃杏酣酣著意紅，當時只要嫁東風。", "而今却被東風誤，一片西飛一片東。"]'),
('cff78423-5d50-4645-bbb8-b46330bd887e','春日即事五首  其四','舒邦佐','宋','宋诗','song-poetry','','[]','鳴鳩乳燕寂無聲，蜜熟花蜂亦懶營。',32,'全唐诗/poet.song.159000.json','["鳴鳩乳燕寂無聲，蜜熟花蜂亦懶營。", "睡起卷簾春已晚，竹籬穿筍兩三莖。"]'),
('7cd37fa4-7427-4dfa-9099-a5fa63d143a2','春日即事五首  其五','舒邦佐','宋','宋诗','song-poetry','','[]','穀雨催秧蠶再眠，采桑女伴罷鞦韆。',32,'全唐诗/poet.song.159000.json','["穀雨催秧蠶再眠，采桑女伴罷鞦韆。", "前村亦少游人到，牛歇濃陰人餉田。"]'),
('cc8e3470-056d-40fe-ad56-82425ff6ff8b','春暮','舒邦佐','宋','宋诗','song-poetry','','[]','日月一箭過，春光又別人。',48,'全唐诗/poet.song.159000.json','["日月一箭過，春光又別人。", "竹孫纔解籜，梅子已生仁。", "閲世真旋磨，看詩老斲輪。", "壯懷因病落，孤負百年身。"]'),
('7d33e8a2-01eb-478f-b1b3-446b51c8e048','睡起','舒邦佐','宋','宋诗','song-poetry','','[]','睡起挼挲兩眼眵，卷簾惟見水平池。',32,'全唐诗/poet.song.159000.json','["睡起挼挲兩眼眵，卷簾惟見水平池。", "小窗幽寂無人到，自撥爐薰試一旗。"]'),
('797aa204-6ed5-417b-8064-891f5c4be72d','聞野有饑殍感歎','舒邦佐','宋','宋诗','song-poetry','','[]','豌豆斬新綠，櫻桃爛熟紅。',48,'全唐诗/poet.song.159000.json','["豌豆斬新綠，櫻桃爛熟紅。", "一年春色過，大半雨聲中。", "仆野傷饑殍，祈天願歲豐。", "有誰捐白粲，相伴減青銅。"]'),
('28bb5c8c-ee8d-4012-a5a4-4dffab7870ad','初夏二首  其一','舒邦佐','宋','宋诗','song-poetry','','[]','稍久梅黄雨，新晴麥熟天。',48,'全唐诗/poet.song.159000.json','["稍久梅黄雨，新晴麥熟天。", "寸懷煎百慮，一病費三年。", "方冊强遮眼，短窗時送眠。", "三生償業盡，四體合安便。"]'),
('150be74e-aa34-4429-931f-2361f26e819e','初夏二首  其二','舒邦佐','宋','宋诗','song-poetry','','[]','盧橘金珠似，楊梅火齊如。',48,'全唐诗/poet.song.159000.json','["盧橘金珠似，楊梅火齊如。", "燕銜春去後，蟬噪夏陰初。", "藥訪三年艾，心凝一束書。", "老身仍著病，節物最關渠。"]'),
('f4093cf2-81e2-4cf6-8fc0-67dd496ab030','立夏後熱甚既而楝花風作極寒','舒邦佐','宋','宋诗','song-poetry','','[]','炎官司印未十日，暑氣駸駸著病翁。',32,'全唐诗/poet.song.159000.json','["炎官司印未十日，暑氣駸駸著病翁。", "卷地吹來忽驚散，今朝還遇楝花風。"]'),
('2f335f0b-e895-43b2-bec7-c5d7682a5746','讀陳黄詩','舒邦佐','宋','宋诗','song-poetry','','[]','四海黄太史，百年陳後山。',48,'全唐诗/poet.song.159000.json','["四海黄太史，百年陳後山。", "意深識者少，味永到尤難。", "夜靜參禪悅，天晴窺管斑。", "心知言未契，猶隔一重關。"]'),
('a1e101db-fe61-488e-a0cc-a9ab63ec74d7','自歎二首  其一','舒邦佐','宋','宋诗','song-poetry','','[]','莫莫更莫莫，休休復休休。',48,'全唐诗/poet.song.159000.json','["莫莫更莫莫，休休復休休。", "平生都是錯，一病盡堪羞。", "龜爲靈鑽殻，膏因明出油。", "細思根本悴，端的是招憂。"]'),
('2ce64a18-cc62-4a99-ab8c-6d20f92bcc2d','自歎二首  其二','舒邦佐','宋','宋诗','song-poetry','','[]','怡顔今得盼庭柯，黄鳥啼邊綠蔭多。',32,'全唐诗/poet.song.159000.json','["怡顔今得盼庭柯，黄鳥啼邊綠蔭多。", "回歎此生肝肺涸，只因雕篆損天和。"]'),
('27f53231-77d5-4db6-88c0-6f8e3a54438d','榴花','舒邦佐','宋','宋诗','song-poetry','','[]','萬綠枝頭幾點春，逢人偏喜上烏雲。',32,'全唐诗/poet.song.159000.json','["萬綠枝頭幾點春，逢人偏喜上烏雲。", "出來只爲當時暑，故翦紅綃皺作裙。"]'),
('58e89089-e6cc-43e8-8e5e-c0ffb2ef9613','寄端夫三首  其一','舒邦佐','宋','宋诗','song-poetry','','[]','萱草榴花照眼明，水團角黍滿盤清。',32,'全唐诗/poet.song.159000.json','["萱草榴花照眼明，水團角黍滿盤清。", "文殊問疾移秋晚，空想敲門剝啄聲。"]'),
('6e4545d2-fa3b-4a60-a204-51c9063b3709','寄端夫三首  其二','舒邦佐','宋','宋诗','song-poetry','','[]','遲子來時細講論，未須著語策奇勳。',32,'全唐诗/poet.song.159000.json','["遲子來時細講論，未須著語策奇勳。", "庖丁妙在牛先解，水上風行自有文。"]'),
('73b429ab-d37f-4f2e-9eaa-5ade4d79e93d','寄端夫三首  其三','舒邦佐','宋','宋诗','song-poetry','','[]','求田未用太匆忙，且况毛錐覓太倉。',32,'全唐诗/poet.song.159000.json','["求田未用太匆忙，且况毛錐覓太倉。", "擇地讀書終不惡，莫教辜負北窗涼。"]'),
('78c97c93-ca28-4075-a3f2-8c4c3a415511','午睡','舒邦佐','宋','宋诗','song-poetry','','[]','博山烟斷嬾重添，屋角無聲雀去簷。',32,'全唐诗/poet.song.159000.json','["博山烟斷嬾重添，屋角無聲雀去簷。", "午夢欲成雞喚醒，卧看修竹映疎簾。"]'),
('eb71688e-7879-45a0-8015-893d96e03f93','春晚','舒邦佐','宋','宋诗','song-poetry','','[]','桑柘枝頭一一空，林巒放出畫屏風。',32,'全唐诗/poet.song.159000.json','["桑柘枝頭一一空，林巒放出畫屏風。", "鷺鷥驚晚歸飛急，零亂昏烟一抹中。"]'),
('67cc8fda-2e45-4de5-8ea4-3fd26dc5a530','捲簾','舒邦佐','宋','宋诗','song-poetry','','[]','隔簾見竹早清幽，卷起疎簾滿眼秋。',32,'全唐诗/poet.song.159000.json','["隔簾見竹早清幽，卷起疎簾滿眼秋。", "一搭夕陽收不得，被人都送上簾鈎。"]'),
('2242f4ad-b9fc-4349-86fb-e9e452b8a9ce','憶官舍芙蕖','舒邦佐','宋','宋诗','song-poetry','','[]','官池無數擁紅妝，日日全家坐晚涼。',32,'全唐诗/poet.song.159000.json','["官池無數擁紅妝，日日全家坐晚涼。", "官職已拋無夢去，尚疑身繞一池香。"]'),
('8dcefa39-8984-4bd6-8f87-22432c07e0cc','秋暑極熾而雨作凉氣翛然','舒邦佐','宋','宋诗','song-poetry','','[]','日輪停午汗珠融，簾箔都無半點風。',32,'全唐诗/poet.song.159000.json','["日輪停午汗珠融，簾箔都無半點風。", "喚起睡龍行一雨，病身移入水晶宮。"]'),
('26408b44-ee6a-4596-8fe6-76db2fcd992c','聞蟬','舒邦佐','宋','宋诗','song-poetry','','[]','紗幮紋簟北窗眠，只道清聲比管絃。',32,'全唐诗/poet.song.159000.json','["紗幮紋簟北窗眠，只道清聲比管絃。", "誰念夕陽官道裏，幾多客旅聽凄然。"]'),
('88011614-2275-41ce-b6e6-b75b3b18cd97','立秋後十日','舒邦佐','宋','宋诗','song-poetry','','[]','萬綠枝頭一葉黄，秋風恰則到林塘。',32,'全唐诗/poet.song.159000.json','["萬綠枝頭一葉黄，秋風恰則到林塘。", "晚雲更作瀟瀟雨，拾得人間一夜涼。"]'),
('e06c375d-2f92-404c-ad30-f85e4007efea','雨後','舒邦佐','宋','宋诗','song-poetry','','[]','積雨洗殘暑，翛然窗戶涼。',108,'全唐诗/poet.song.159000.json','["積雨洗殘暑，翛然窗戶涼。", "蠅蚊不須驅，時至自退藏。", "琤然一葉下，梧桐隕秋黄。", "仰視天宇闊，賓鴻初南翔。", "兒時親燈火，二尺便宜光。", "咀嚼復吟哦，惟恐更漏忙。", "老來病如縛，空對書滿箱。", "短檠置牀頭，猶渴不能漿。", "人生捨此樂，百年謾風狂。"]'),
('dc5817c2-4b10-4912-bec7-0901c1557af5','至後有感','舒邦佐','宋','宋诗','song-poetry','','[]','窮冬萬木脫，風葉無停計。',84,'全唐诗/poet.song.159000.json','["窮冬萬木脫，風葉無停計。", "老樹露槎牙，四旁誰擁蔽。", "泛視林莽間，一一獻憔悴。", "昨夜新陽復，根荄抱生意。", "天將九轉丹，一粒回元氣。", "三陽即爲泰，原野爭明媚。", "老樹亦逢春，綠陰看垂地。"]'),
('12be3205-0c9b-45dd-a3a2-6ecf06e7c665','殘臘書懷','舒邦佐','宋','宋诗','song-poetry','','[]','冰池照日暖初融，準擬迎春更餞冬。',64,'全唐诗/poet.song.159000.json','["冰池照日暖初融，準擬迎春更餞冬。", "盃酒乍疎情少緒，尺緘稽報病多慵。", "殘年斷送風和雪，晚節相依竹與松。", "回首思量十年事，倦投孤枕聽鳴鐘。"]'),
('efaf379b-997f-470e-8a62-280f1e0f497c','梅花','舒邦佐','宋','宋诗','song-poetry','','[]','千林氣脈未全歸，一點清香已著枝。',64,'全唐诗/poet.song.159000.json','["千林氣脈未全歸，一點清香已著枝。", "每愛月窗橫瘦影，敢將水墨污冰姿。", "淡妝出屋新相見，索笑巡簷舊有詩。", "不見化工先著力，雪中風韻最相宜。"]'),
('888f36a7-42ac-4c46-b1cd-f058271df835','小巷','舒邦佐','宋','宋诗','song-poetry','','[]','蕭條一徑微，來往覺人稀。',48,'全唐诗/poet.song.159000.json','["蕭條一徑微，來往覺人稀。", "忽聽隣家閙，歡尋稚子歸。", "卷書真是懶，添火且相依。", "强起扶行處，斜陽正滿扉。"]'),
('20c4bc97-ec49-4ff2-b233-36f9db425929','瓶梅','舒邦佐','宋','宋诗','song-poetry','','[]','病眼因君得再明，依前風骨照人清。',32,'全唐诗/poet.song.159000.json','["病眼因君得再明，依前風骨照人清。", "憑誰說與司花女，伴我長開過一生。"]'),
('cfcd7b4a-342a-469a-87f7-22d56e6fa646','丁巳正月五日','舒邦佐','宋','宋诗','song-poetry','','[]','春滯猶爲臘，年移已換正。',48,'全唐诗/poet.song.159000.json','["春滯猶爲臘，年移已換正。", "節從忙裏過，愁向病邊生。", "小雨止還作，虛窗暗又明。", "時光與心事，無一可娛情。"]'),
('3ae96dd3-1641-425a-8078-543d34994fbc','春半即事','舒邦佐','宋','宋诗','song-poetry','','[]','春來晴景少，晝夜已平分。',48,'全唐诗/poet.song.159000.json','["春來晴景少，晝夜已平分。", "寒鎖花藏莟，風微水皺紋。", "端成空識字，誰可共論文。", "惟有銅爐在，時拈柏子焚。"]'),
('5e2b3e40-1144-4dce-a00d-ed5f979f5e49','病中口占','舒邦佐','宋','宋诗','song-poetry','','["\u897f\u6e56"]','拂枕投牀鼻息鳴，鄰雞報午夢還驚。',64,'全唐诗/poet.song.159000.json','["拂枕投牀鼻息鳴，鄰雞報午夢還驚。", "一春已過半春了，十日曾無五日晴。", "喚客難同藉草飲，隔牆虛認賣花聲。", "十年前憶西湖上，柳蔭蘇隄取次行。"]'),
('ca6ecfe6-cbc5-4d69-b615-a88fe113a1e2','嘲燕子','舒邦佐','宋','宋诗','song-poetry','','[]','去歲相過日，朱簾正上鈎。',48,'全唐诗/poet.song.159000.json','["去歲相過日，朱簾正上鈎。", "雙雙如舊識，一一話離愁。", "留爲荷花夏，歸因梧葉秋。", "今年頭轉白，還識主人不。"]'),
('cf49fda1-2bdb-4b82-b8d3-5102656f4308','爲端夫病起解嘲','舒邦佐','宋','宋诗','song-poetry','','[]','折臂三公古尚傳，神全何必問形全。',32,'全唐诗/poet.song.159000.json','["折臂三公古尚傳，神全何必問形全。", "前身恐是婁師德，試向沙頭覓渡船。"]'),
('3e29db1b-c8c2-4c88-a49e-c6a1cd2c8c52','至日見梅','舒邦佐','宋','宋诗','song-poetry','','[]','插向書窗小小瓶，看來看去眼增明。',32,'全唐诗/poet.song.159000.json','["插向書窗小小瓶，看來看去眼增明。", "花瓶莟子能多少，占却人間無限情。"]'),
('dadc9635-18c4-4f81-811d-091966c1ffb8','紀秀野之景','舒邦佐','宋','宋诗','song-poetry','','[]','秀野吾曾到，名新景亦嘉。',48,'全唐诗/poet.song.159000.json','["秀野吾曾到，名新景亦嘉。", "雨移新到竹，晴接舊來花。", "矗矗山圍立，團團樹繞家。", "病中心漫往，無計聚摶沙。"]'),
('e3cdb6c8-f54a-4f72-8a15-627f4fb8a677','和王令尹游園之作','舒邦佐','宋','宋诗','song-poetry','','[]','官事何時了，偷忙得餉閒。',48,'全唐诗/poet.song.159000.json','["官事何時了，偷忙得餉閒。", "清風寒食裏，飛絮落花間。", "靈運池生草，淵明鞠見山。", "詩來令細讀，玉佩響珊珊。"]'),
('86488c40-c0b2-4cd1-8bb6-d873c23268e5','久雨望晴十月六日夜雷雨大作','舒邦佐','宋','宋诗','song-poetry','','[]','十月天猶暖，渾如二月晴。',48,'全唐诗/poet.song.159000.json','["十月天猶暖，渾如二月晴。", "雷聲兼雨勢，春令已冬行。", "稻穟多生耳，田家有歎聲。", "官倉須玉粒，早爲挂銅鉦。"]'),
('80ccd5e6-5767-49e8-b686-a44e1380eaeb','送履正赴省','舒邦佐','宋','宋诗','song-poetry','','[]','萬里雲衢著脚初，臨行尚肯過吾廬。',64,'全唐诗/poet.song.159000.json','["萬里雲衢著脚初，臨行尚肯過吾廬。", "風雲得助子方快，冰玉相依我不如。", "驛路響鈴看報捷，殿門放鑰待傳臚。", "逾科又見龍飛榜，此度傳衣應不虛。"]'),
('a1e232b0-529f-4f37-a58a-346eebf390aa','送致遠赴耒陽酒官','舒邦佐','宋','宋诗','song-poetry','','[]','雲凍長空晝亦昏，誰歟剝啄扣柴門。',64,'全唐诗/poet.song.159000.json','["雲凍長空晝亦昏，誰歟剝啄扣柴門。", "故人言向瀟湘去，此別應須歲月論。", "衡嶽五峰瞻勝槩，耒江千載弔詩魂。", "舊游倘有人相問，爲說扶犁教子孫。"]'),
('fb1eb960-e1b5-4943-ae2d-aaadaa611c7f','挽左相京太師四首  其一','舒邦佐','宋','宋诗','song-poetry','','[]','皇華方北返，植纛指西風。',48,'全唐诗/poet.song.159000.json','["皇華方北返，植纛指西風。", "蜀謂今清獻，戎言昔富公。", "民夷兩心服，勳業百年同。", "贈與齊溫國，功高報亦隆。"]'),
('1bf6522e-df50-44d3-91c3-965b6f89e49d','挽左相京太師四首  其二','舒邦佐','宋','宋诗','song-poetry','','[]','聖代多名相，誰如德量寬。',48,'全唐诗/poet.song.159000.json','["聖代多名相，誰如德量寬。", "平心消黨與，著力援孤寒。", "禮極三宮養，天開二聖歡。", "盡忠扶孝治，烽火自平安。"]'),
('b93abf72-7c19-4822-af65-7935edb9b4c9','挽左相京太師四首  其三','舒邦佐','宋','宋诗','song-poetry','','[]','堯考聞憂日，公身病瘁時。',48,'全唐诗/poet.song.159000.json','["堯考聞憂日，公身病瘁時。", "哀情知痛極，疾勢轉增危。", "梁壞將安放，天胡不憗遺。", "此爲天下慟，未敢哭其私。"]'),
('031ab9aa-57ca-4e55-b040-7b79b07eb847','挽左相京太師四首  其四','舒邦佐','宋','宋诗','song-poetry','','[]','自際朱絃賞，逢人說項斯。',48,'全唐诗/poet.song.159000.json','["自際朱絃賞，逢人說項斯。", "蜚章先剡上，薦墨更交馳。", "遽卧漳濱疾，如轟薦福碑。", "空流一襟淚，無路送靈輀。"]'),
('3c8070f7-c46f-45be-ac00-64f940f6fef1','題同年郭丞遯齋','舒邦佐','宋','宋诗','song-poetry','','[]','清江子郭子，作齋以遯名。',168,'全唐诗/poet.song.159000.json','["清江子郭子，作齋以遯名。", "傍人或不解，謂將拋塵纓。", "著語競挽住，軒翥九萬程。", "吾聞遯之象，山止而天行。", "止如子綦木，行如亞夫兵。", "養靜以須動，淵嘿藏雷聲。", "乃識箇中趣，非專隠遯情。", "雖然遯六爻，四陽理分明。", "雖有艮在內，二陰要研精。", "尾厲苟不審，嘉肥何由亨。", "艮齋謝夫子，江南老先生。", "君齋雖名遯，三爻自艮萌。", "南豐一瓣香，好請子細評。", "再拜若有得，爲語年弟兄。"]'),
('5071b25c-3e99-416d-b3be-f93b94121d76','送馮勉仲赴省','舒邦佐','宋','宋诗','song-poetry','','[]','客餞旗亭酒半酣，摶風九萬送鵬南。',64,'全唐诗/poet.song.159000.json','["客餞旗亭酒半酣，摶風九萬送鵬南。", "薄勞汗馬功收一，肯怨長途玉獻三。", "去去梅花催驛騎，看看柳色鬭恩藍。", "長篇好上劉蕡策，莫作書生無用談。"]'),
('832f3224-9d0c-41b6-a1d7-7de0bacdc47a','和許宰寓武邑賡楊丞靖安八詠  其一','舒邦佐','宋','宋诗','song-poetry','','[]','市人常是醉昏昏，買盡青銅酒已渾。',32,'全唐诗/poet.song.159000.json','["市人常是醉昏昏，買盡青銅酒已渾。", "健倒投床都不問，日高猶未啟重門。"]'),
('fb00e950-2651-4c06-83fa-d79c7c98c3fc','和許宰寓武邑賡楊丞靖安八詠  其二','舒邦佐','宋','宋诗','song-poetry','','[]','君似春風自襲人，無情鷗鳥亦相親。',32,'全唐诗/poet.song.159000.json','["君似春風自襲人，無情鷗鳥亦相親。", "莫驚仕路風波惡，便憶家園自在身。"]'),
('474c686e-e1f7-4ecb-af89-89141ab85469','和許宰寓武邑賡楊丞靖安八詠  其三','舒邦佐','宋','宋诗','song-poetry','','[]','我有淵明日涉園，桃蹊柳徑漸清繁。',32,'全唐诗/poet.song.159000.json','["我有淵明日涉園，桃蹊柳徑漸清繁。", "却嫌市井喧囂近，悔不誅茆住遠村。"]'),
('5368e685-06d9-46e7-9619-9cfe68b0f6b0','和許宰寓武邑賡楊丞靖安八詠  其四','舒邦佐','宋','宋诗','song-poetry','','[]','風旗獵獵半欹斜，日日相傳便到家。',32,'全唐诗/poet.song.159000.json','["風旗獵獵半欹斜，日日相傳便到家。", "幾度兒童騎竹馬，斜陽影裏簇汀沙。"]'),
('4adbffbd-82b4-4d4a-bc06-8ee2aca14ea9','和許宰寓武邑賡楊丞靖安八詠  其五','舒邦佐','宋','宋诗','song-poetry','','[]','帥幕潭潭庇萬間，已知流水與高山。',32,'全唐诗/poet.song.159000.json','["帥幕潭潭庇萬間，已知流水與高山。", "定應不負刀頭約，合浦明珠早早還。"]'),
('ad5c65fb-c726-4445-b682-0b6cf658ec49','和許宰寓武邑賡楊丞靖安八詠  其六','舒邦佐','宋','宋诗','song-poetry','','[]','好語飛來散綺霞，清新俊逸屬詩家。',32,'全唐诗/poet.song.159000.json','["好語飛來散綺霞，清新俊逸屬詩家。", "著人似醉菖蒲酒，有味如嘗橄欖茶。"]'),
('d47bef5e-5c9a-4733-ab5b-793f6d5b2160','和許宰寓武邑賡楊丞靖安八詠  其七','舒邦佐','宋','宋诗','song-poetry','','[]','家書寫罷報平安，酒坐圍紅且醉觀。',32,'全唐诗/poet.song.159000.json','["家書寫罷報平安，酒坐圍紅且醉觀。", "別後雙溪春色散，應無賣鏡去尋官。"]'),
('21e63660-ae09-48f4-85e2-1867dcf094df','和許宰寓武邑賡楊丞靖安八詠  其八','舒邦佐','宋','宋诗','song-poetry','','[]','里巷繰車日日忙，今年又喜熟蠶桑。',32,'全唐诗/poet.song.159000.json','["里巷繰車日日忙，今年又喜熟蠶桑。", "公家無欠私家樂，細葛含風翦更長。"]'),
('7fcb15ea-86c4-4323-899b-007d49ef1fd0','秋晚','滕岑','宋','宋诗','song-poetry','','[]','槭槭霜風勁，駸駸物象彫。',48,'全唐诗/poet.song.159000.json','["槭槭霜風勁，駸駸物象彫。", "屢遷憐蟋蟀，一敗笑芭蕉。", "林葉疎逾響，山雲薄易消。", "雖無遠行役，對此亦何聊。"]'),
('5e65a0e2-4338-4725-9eb9-763fd6c86911','拄杖','滕岑','宋','宋诗','song-poetry','','[]','久矣相隨若弟昆，周全險阻可須論。',64,'全唐诗/poet.song.159000.json','["久矣相隨若弟昆，周全險阻可須論。", "斷橋測水露半影，野路擉泥留亂痕。", "癡坐自憐今日嬾，顛持敢忘昔年恩。", "得君分付吾何恨，休向林間打睡門。"]'),
('ee4bf3a0-ee4a-4fbd-9137-091ce4b34c8b','蔣中丞庭下芙蓉  其一','滕岑','宋','宋诗','song-poetry','','[]','西風吹下一庭秋，秋自無聊花更愁。',32,'全唐诗/poet.song.159000.json','["西風吹下一庭秋，秋自無聊花更愁。", "醉臉晚來紅拂掠，未妨蕭瑟却風流。"]'),
('5c1846a3-a452-4c66-88db-2e6d79adec58','蔣中丞庭下芙蓉  其二','滕岑','宋','宋诗','song-poetry','','[]','莫把秋芳與春比，物生各各以時行。',32,'全唐诗/poet.song.159000.json','["莫把秋芳與春比，物生各各以時行。", "只今獨步西風裏，那得春花與抗衡。"]'),
('740c5f87-55dd-4b4f-ab99-86d24e4b45e7','蔣中丞庭下芙蓉  其三','滕岑','宋','宋诗','song-poetry','','[]','菊與爲朋竹與隣，閉門誰見曉粧新。',32,'全唐诗/poet.song.159000.json','["菊與爲朋竹與隣，閉門誰見曉粧新。", "不須多羨蘇堤好，車馬往來塵污人。"]'),
('64177272-50c2-45e6-8cb1-0a2f5c4817c7','上鄭廣文','滕岑','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','瓦注非真巧，昌歜非衆嗜。',120,'全唐诗/poet.song.159000.json','["瓦注非真巧，昌歜非衆嗜。", "我詩本不工，好之弗肯置。", "胡能致溫飽，頗復作災祟。", "無鹽不自知，刻畫要妍媚。", "先生六藝學，已得聖賢秘。", "三絕笑鄭虔，詩律乃遊戲。", "伊予亦何幸，茲獲巾屨侍。", "豈惟怯大巫，正自慚小技。", "却嗟賈長江，哦詩尹不避。", "文公倘見容，願教推敲字。"]'),
('b9f47194-ac70-427a-85c4-b645c5dcb2bb','鼓腹無所思朝起暮歸眠淵明詩也以詩定韻爲十詩  其一','滕岑','宋','宋诗','song-poetry','','[]','郊墟遠人煙，棲迹在衡宇。',48,'全唐诗/poet.song.159000.json','["郊墟遠人煙，棲迹在衡宇。", "年齡迫衰謝，漸覺有病苦。", "眼如隔羅縠，耳僅聞鍾鼓。", "手中一枝筇，藉以扶傴僂。"]'),
('4bbf880f-f00d-45e0-8c36-3dbb799f8098','鼓腹無所思朝起暮歸眠淵明詩也以詩定韻爲十詩  其二','滕岑','宋','宋诗','song-poetry','','[]','少習舉子業，不能中科目。',48,'全唐诗/poet.song.159000.json','["少習舉子業，不能中科目。", "暮竟爲尉丞，州縣甘碌碌。", "四任奉真祠，一家仰寸祿。", "勿云腹負予，予亦負此腹。"]'),
('357ec2d3-5ba8-48df-8186-c45963220052','鼓腹無所思朝起暮歸眠淵明詩也以詩定韻爲十詩  其三','滕岑','宋','宋诗','song-poetry','','[]','居閑閲往史，掩卷忽長吁。',48,'全唐诗/poet.song.159000.json','["居閑閲往史，掩卷忽長吁。", "兒聞翁吁聲，取酒滿注盂。", "悠然盡三酌，雜慮散如驅。", "乃知此神物，不可一日無。"]'),
('8c9e4f14-a31d-460d-a0ef-5ac4bb928c7f','鼓腹無所思朝起暮歸眠淵明詩也以詩定韻爲十詩  其四','滕岑','宋','宋诗','song-poetry','','[]','我居西山下，距城半里所。',48,'全唐诗/poet.song.159000.json','["我居西山下，距城半里所。", "門前有雀羅，戶內無阿堵。", "小園桃李空，數稜獨苦苣。", "同心相過時，小摘爲烹煮。"]'),
('37f54cd4-f150-4d03-ab67-9b926a229bef','鼓腹無所思朝起暮歸眠淵明詩也以詩定韻爲十詩  其五','滕岑','宋','宋诗','song-poetry','','[]','我前有萬古，昨夢那無追。',48,'全唐诗/poet.song.159000.json','["我前有萬古，昨夢那無追。", "我後有萬世，未夢安可期。", "欲知今現在，正似昨夢時。", "夢中無實事，徒自勞心思。"]'),
('6ef2f2fe-120d-4cf4-a3ad-a9c06edcbb13','鼓腹無所思朝起暮歸眠淵明詩也以詩定韻爲十詩  其六','滕岑','宋','宋诗','song-poetry','','[]','立夏少半月，穀雨是今朝。',48,'全唐诗/poet.song.159000.json','["立夏少半月，穀雨是今朝。", "梅子酸著齒，麥穗長半腰。", "天運不暫停，又將轉斗杓。", "無復冬裘御，重取夏扇摇。"]'),
('4b5ba473-a0fb-4c2f-ae7e-0093b9eff8d7','鼓腹無所思朝起暮歸眠淵明詩也以詩定韻爲十詩  其七','滕岑','宋','宋诗','song-poetry','','[]','芳菲去無迹，人家綠陰裏。',48,'全唐诗/poet.song.159000.json','["芳菲去無迹，人家綠陰裏。", "有園屋西偏，足以縱步履。", "酴醾香絕奇，橘花香更美。", "日烘香自發，不待微風起。"]'),
('6fdb9693-88e0-4061-b470-b4aa3fe71fb8','鼓腹無所思朝起暮歸眠淵明詩也以詩定韻爲十詩  其八','滕岑','宋','宋诗','song-poetry','','[]','萬籟止不作，寂寂山居夜。',48,'全唐诗/poet.song.159000.json','["萬籟止不作，寂寂山居夜。", "鼓聲起神祠，磬聲來佛舍。", "幽人啟樓窗，片月光相射。", "此景不可孤，呼兒具杯斝。"]'),
('ab893995-9490-4432-aaa1-71352d10dd8a','鼓腹無所思朝起暮歸眠淵明詩也以詩定韻爲十詩  其九','滕岑','宋','宋诗','song-poetry','','[]','神龍固難豢，天馬豈易鞿。',48,'全唐诗/poet.song.159000.json','["神龍固難豢，天馬豈易鞿。", "淵明肯折腰，爲此五斗微。", "我本田野人，初不慕輕肥。", "食未從人乞，隠不待賦歸。"]'),
('c3f6aa33-da9d-47d2-bcae-f8ffb90e7c1e','鼓腹無所思朝起暮歸眠淵明詩也以詩定韻爲十詩  其一○','滕岑','宋','宋诗','song-poetry','','[]','我讀淵明詩，或至忘食眠。',48,'全唐诗/poet.song.159000.json','["我讀淵明詩，或至忘食眠。", "人物葛天民，度越羲黄前。", "胸中抱真淳，筆下雜言詮。", "妄譏閑情賦，詎識其超然。"]'),
('a6460045-61fe-4333-93d2-e3d55db48ea7','三月十二日晚雨因取淵明詩微雨洗高林清飈矯雲翮之句定韻賦十詩翌日雨未已姪坦師來相招時方賦六首暮雨暗還舍遂足十韻  其一','滕岑','宋','宋诗','song-poetry','','[]','中年知學道，所得不造微。',48,'全唐诗/poet.song.159000.json','["中年知學道，所得不造微。", "老來衰拙甚，動與世俗違。", "詩書束高閣，蓬藋掩壞扉。", "自應車馬絕，不待門牆揮。"]'),
('7b482fa6-6156-4e2d-9438-15f47d2d4b1a','三月十二日晚雨因取淵明詩微雨洗高林清飈矯雲翮之句定韻賦十詩翌日雨未已姪坦師來相招時方賦六首暮雨暗還舍遂足十韻  其二','滕岑','宋','宋诗','song-poetry','','[]','蠶婦正望晴，耕夫又須雨。',48,'全唐诗/poet.song.159000.json','["蠶婦正望晴，耕夫又須雨。", "蠶既惡濕葉，牛惟便潤土。", "我不事農桑，薄祿仰官府。", "衣食有不足，何敢怨貧窶。"]'),
('6273cd74-5489-4ecb-b153-bf64903d2353','三月十二日晚雨因取淵明詩微雨洗高林清飈矯雲翮之句定韻賦十詩翌日雨未已姪坦師來相招時方賦六首暮雨暗還舍遂足十韻  其三','滕岑','宋','宋诗','song-poetry','','[]','自得林下趣，窮處甘如薺。',48,'全唐诗/poet.song.159000.json','["自得林下趣，窮處甘如薺。", "白雲爲朋友，青山是昆弟。", "幽池萍未生，閑來弄清泚。", "照影不能悟，徒自塵纓洗。"]'),
('90255f13-350a-4645-b622-f6e94913cd53','三月十二日晚雨因取淵明詩微雨洗高林清飈矯雲翮之句定韻賦十詩翌日雨未已姪坦師來相招時方賦六首暮雨暗還舍遂足十韻  其四','滕岑','宋','宋诗','song-poetry','','[]','風吹飛絮亂，日照遊絲高。',48,'全唐诗/poet.song.159000.json','["風吹飛絮亂，日照遊絲高。", "晴景方可愛，暮雨忽瀟瀟。", "老人蚤睡眠，夢覺鷄戒朝。", "簷聲鳴階除，雲氣冒山椒。"]'),
('64897490-4570-4ab6-9dbc-05a99b8fa581','三月十二日晚雨因取淵明詩微雨洗高林清飈矯雲翮之句定韻賦十詩翌日雨未已姪坦師來相招時方賦六首暮雨暗還舍遂足十韻  其五','滕岑','宋','宋诗','song-poetry','','[]','去歲所種竹，今歲望成林。',48,'全唐诗/poet.song.159000.json','["去歲所種竹，今歲望成林。", "竹萌猶未見，時節春已深。", "逮茲一雨潤，犢角庶可尋。", "切勿輕剪馘，長養令蕭森。"]'),
('6bcdb4fc-18fa-4bb6-85c2-2d480b01c8ed','三月十二日晚雨因取淵明詩微雨洗高林清飈矯雲翮之句定韻賦十詩翌日雨未已姪坦師來相招時方賦六首暮雨暗還舍遂足十韻  其六','滕岑','宋','宋诗','song-poetry','','[]','久雨愛晴色，久晴欣雨聲。',48,'全唐诗/poet.song.159000.json','["久雨愛晴色，久晴欣雨聲。", "下人自分別，上天了無情。", "人喜春色麗，又悲秋氣清。", "是皆妄心耳，四序奚虧成。"]'),
('66cfe0ae-aef2-43ab-b73b-14e93ad6bb8c','三月十二日晚雨因取淵明詩微雨洗高林清飈矯雲翮之句定韻賦十詩翌日雨未已姪坦師來相招時方賦六首暮雨暗還舍遂足十韻  其七','滕岑','宋','宋诗','song-poetry','','[]','遠寺有緇徒，殷勤久見招。',48,'全唐诗/poet.song.159000.json','["遠寺有緇徒，殷勤久見招。", "是日籃輿出，輕雨颯晨飈。", "稽首謁佛像，焚香坐僧寮。", "豈惟飯滿鉢，兼有酒盈瓢。"]'),
('c73d1c6a-9bf0-4f6b-ac2f-97aec65fb97c','三月十二日晚雨因取淵明詩微雨洗高林清飈矯雲翮之句定韻賦十詩翌日雨未已姪坦師來相招時方賦六首暮雨暗還舍遂足十韻  其八','滕岑','宋','宋诗','song-poetry','','[]','靜觀一世人，忙多閑者少。',48,'全唐诗/poet.song.159000.json','["靜觀一世人，忙多閑者少。", "鬚髮已剝除，應接亦紛擾。", "何術生羽翼，物外得輕矯。", "難求九轉丹，且盡一尊醥。"]'),
('9cf4bf12-35d8-4f0c-a8fd-73dedc191c20','三月十二日晚雨因取淵明詩微雨洗高林清飈矯雲翮之句定韻賦十詩翌日雨未已姪坦師來相招時方賦六首暮雨暗還舍遂足十韻  其九','滕岑','宋','宋诗','song-poetry','','[]','老人見桃花，悟者有靈雲。',48,'全唐诗/poet.song.159000.json','["老人見桃花，悟者有靈雲。", "我見亦有悟，花前飲玉醺。", "可憐南北家，論說事紛紜。", "爲問參老禪，何如參麵君。"]'),
('9073bdf9-0632-4555-aeaf-7c37f4756277','閑題','滕岑','宋','宋诗','song-poetry','','[]','漏雲殘日凄欲陰，占巢歸鷺紛投林。',64,'全唐诗/poet.song.159000.json','["漏雲殘日凄欲陰，占巢歸鷺紛投林。", "風吹曠野暮色白，山近小窗秋意深。", "已將夢事了得喪，更憑杯酒寄浮沉。", "書生習氣難料理，有底苦吟勞此心。"]'),
('d7d4d52c-a3e2-4709-80a0-066b0d6f0c08','遊西湖五首  其一','滕岑','宋','宋诗','song-poetry','','["\u897f\u6e56"]','白浪吹船投跨浦，黄塵撲帽走沙河。',32,'全唐诗/poet.song.159000.json','["白浪吹船投跨浦，黄塵撲帽走沙河。", "若無西湖一慰眼，奈此客中勞悴何。"]'),
('8683a9b4-0e31-43b4-a427-81bda6f1fae8','遊西湖五首  其二','滕岑','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雪寒映湖湖水明，西子淡粧仍淺顰。',32,'全唐诗/poet.song.159000.json','["雪寒映湖湖水明，西子淡粧仍淺顰。", "不會吳兒底心性，冒寒湖上去尋春。"]'),
('92a12547-b7c2-494b-aa31-fe81ac4a7e3a','遊西湖五首  其三','滕岑','宋','宋诗','song-poetry','','["\u897f\u6e56"]','林君廬不存已久，蘇公堤比舊尤佳。',32,'全唐诗/poet.song.159000.json','["林君廬不存已久，蘇公堤比舊尤佳。", "絕憐夾堤柳漸暗，誰見傍廬梅正花。"]'),
('27886303-3c03-4d33-9c1f-a62e2d3fdef1','遊西湖五首  其四','滕岑','宋','宋诗','song-poetry','','["\u897f\u6e56"]','乍來乍去堤邊鷺，似有似無煙裏山。',32,'全唐诗/poet.song.159000.json','["乍來乍去堤邊鷺，似有似無煙裏山。", "何人爲展古畫軸，塵暗縑綃濃淡間。"]'),
('aa2bd10c-8da3-483e-9427-ee0ffff18a02','遊西湖五首  其五','滕岑','宋','宋诗','song-poetry','','["\u897f\u6e56"]','豐樂樓頭沸管絃，拍床喚酒記當年。',32,'全唐诗/poet.song.159000.json','["豐樂樓頭沸管絃，拍床喚酒記當年。", "而今寂寞空欄楯，樓下漣漪自宛然。"]'),
('6c1d5342-9f18-419c-af4c-25f655eadaf4','江上望西興','滕岑','宋','宋诗','song-poetry','','[]','跨浦橋邊萬里風，客帆去盡暮江空。',32,'全唐诗/poet.song.159000.json','["跨浦橋邊萬里風，客帆去盡暮江空。", "西興只在斜陽裏，白壁青林淡染紅。"]'),
('ebcd5eba-4e6d-41a8-9cb4-efa8be069a52','次韻樂天目昏','滕岑','宋','宋诗','song-poetry','','[]','百年今已八十五，此去光陰能幾多。',64,'全唐诗/poet.song.159000.json','["百年今已八十五，此去光陰能幾多。", "足病半生爲我祟，目昏今日奈渠何。", "也知亂膜無方法，正爲躭書被折磨。", "瞽者欲行須用杖，不如安穩坐盤陀。"]'),
('0398f91b-79fb-4635-94c6-abacdfcb3f3b','記前身','滕岑','宋','宋诗','song-poetry','','[]','廣智紹興初，有僧清首坐。',276,'全唐诗/poet.song.159000.json','["廣智紹興初，有僧清首坐。", "頗亦有禪學，非但嚴經課。", "吾祖知其人，尊之如達磨。", "延歸羞香飯，間亦閑相過。", "祖時年已老，無孫繼耕播。", "耿耿常在念，不敢與人言。", "此僧偶聞之，使之禱佛前。", "且云韶國師，道場在玉泉。", "凡人求男女，如觀音應緣。", "祖遂相約往，此僧遽欣然。", "是夕僧坐逝，有偈人共傳。", "祖即焚香拜，前諾師豈負。", "靈魄决不昧，請與師同去。", "祖如師在日，拱手侍行步。", "既至即影響，幡脚轉不住。", "已而得吉卜，有孫生歲暮。", "人云所生孫，即是師前身。", "往來無處驗，虛實何足論。", "識者聞之笑，愚者以爲真。", "可憐滕氏子，一生命窮薄。", "晚逃儒事佛，兩皆無所覺。", "若果是此僧，無乃行路錯。", "聊復成此詩，一任人貶駮。"]'),
('b60bb93e-2490-41b7-9954-9e8293ce9990','九日求米','滕岑','宋','宋诗','song-poetry','','[]','絕糧缺酒兩堪悲，寧可無盃不可饑。',64,'全唐诗/poet.song.159000.json','["絕糧缺酒兩堪悲，寧可無盃不可饑。", "謾有黄花供老眼，正無紅粒續晨炊。", "太官羔酒何須羨，朝士茱萸亦謾思。", "聊與重陽添故事，不妨乞米賦新詩。"]'),
('1bf4b4d3-1c82-4f61-b1cb-0d002f5acd40','和陶淵明飲酒詩  其一','滕岑','宋','宋诗','song-poetry','','[]','風浪渺平陸，吾行將安之。',60,'全唐诗/poet.song.159000.json','["風浪渺平陸，吾行將安之。", "酒中有樂國，猶是太古時。", "孰云道里長，一觴自臻茲。", "不知有先死，况復憂與疑。", "何辭日一往，蟹螯正堪持。"]'),
('accc633d-64be-4ace-90f9-641f3c1139ac','和陶淵明飲酒詩  其二','滕岑','宋','宋诗','song-poetry','','[]','拏舟漾明月，把酒對青山。',48,'全唐诗/poet.song.159000.json','["拏舟漾明月，把酒對青山。", "月影涵山扉，妙處端難言。", "回觴勸鷗鷺，吾與爾忘年。", "適意祇自知，詎可他人傳。"]'),
('6283b634-1e3a-408e-849a-302d28ab8304','和陶淵明飲酒詩  其三','滕岑','宋','宋诗','song-poetry','','[]','人性政自靜，動者乃妄情。',60,'全唐诗/poet.song.159000.json','["人性政自靜，動者乃妄情。", "紛紛相傾奪，富貴與功名。", "形存神已亡，嗟汝難久生。", "豈知曠士懷，古井波不驚。", "醪酒輔吾體，不待金丹成。"]'),
('79378530-8d65-470c-ab78-9af21796bdf6','和陶淵明飲酒詩  其四','滕岑','宋','宋诗','song-poetry','','[]','今我思故里，身不能奮飛。',72,'全唐诗/poet.song.159000.json','["今我思故里，身不能奮飛。", "登高眺山川，孰知予心悲。", "却思大化中，萬類本無依。", "何者爲我廬，是處皆可歸。", "幽憂不自釋，齒髮日變衰。", "不如傾茲酒，杯行無固違。"]'),
('0b0064bd-c286-400f-b85a-37e750f0386b','和陶淵明飲酒詩  其五','滕岑','宋','宋诗','song-poetry','','[]','秋風入我室，百蟲自相喧。',60,'全唐诗/poet.song.159000.json','["秋風入我室，百蟲自相喧。", "中夜卧不周，起視河漢偏。", "念我平生友，託體歸青山。", "遊魂往何方，千載不復還。", "人生共如此，但醉勿復言。"]'),
('e7b4f692-b051-4103-b8b9-eb9a50c9bd8e','和陶淵明飲酒詩  其六','滕岑','宋','宋诗','song-poetry','','[]','古人不可見，滔滔天下是。',48,'全唐诗/poet.song.159000.json','["古人不可見，滔滔天下是。", "淵明捨之歸，惜此三徑毀。", "樽中幸有酒，飲事付自爾。", "我觀飲酒詩，信矣質而綺。"]'),
('95ae5f7a-47da-4f3e-80d4-552aa4e348af','和陶淵明飲酒詩  其七','滕岑','宋','宋诗','song-poetry','','[]','堂堂東坡公，文章萬人英。',60,'全唐诗/poet.song.159000.json','["堂堂東坡公，文章萬人英。", "嘗和飲酒詩，曲盡今古情。", "平生不解飲，而獨喜客傾。", "仇池一仙去，九韶瘖不鳴。", "不知幾百年，斯人還復生。"]'),
('dd6d2a31-998b-4bab-ac36-250bcd460fc6','和陶淵明飲酒詩  其八','滕岑','宋','宋诗','song-poetry','','[]','嵇康故人達，醉中凜英姿。',60,'全唐诗/poet.song.159000.json','["嵇康故人達，醉中凜英姿。", "因送孤飛鴻，手撫枯桐枝。", "聊將絃上意，寓此胸中奇。", "才高身不容，諒非人力爲。", "麟傷終可歎，龍化真難羈。"]'),
('b004ef38-635d-4490-b91a-c6a75064b956','和陶淵明飲酒詩  其九','滕岑','宋','宋诗','song-poetry','','[]','我遊桐君山，霽色天地開。',96,'全唐诗/poet.song.159000.json','["我遊桐君山，霽色天地開。", "秋水凈遠矚，秋山入奇懷。", "茲遊有夙約，所願喜不乖。", "巖巖彼高閣，上有浮雲棲。", "其下插奫淪，百尺不見泥。", "同來二三友，斗酒相戲諧。", "笑語飛鳥上，醉眼風煙迷。", "醒時日已墮，明月照我回。"]'),
('75ac1a73-6076-4f80-b355-8b64c8e446fe','和陶淵明飲酒詩  其一○','滕岑','宋','宋诗','song-poetry','','[]','壯士志四方，小夫守一隅。',60,'全唐诗/poet.song.159000.json','["壯士志四方，小夫守一隅。", "所稟既殊科，所趣亦異塗。", "毋論賢與愚，等爲造物驅。", "豈如飲家流，一醉不願餘。", "兩忘適與莫，畢世醉鄉居。"]'),
('7205bbc5-3c94-444a-9862-e89192bf752c','和陶淵明飲酒詩  其一一','滕岑','宋','宋诗','song-poetry','','[]','煌煌佳菊花，開遍溪傍道。',72,'全唐诗/poet.song.159000.json','["煌煌佳菊花，開遍溪傍道。", "後時難獨立，得伴秋光老。", "孤芳迫霜露，采采及未槁。", "浮我白玉醪，色香相媚好。", "悠然盡數酌，人棄我所寶。", "一榻醉曲肱，何必遊人表。"]'),
('773a9eda-5445-49bf-b5c4-f25a437020e4','和陶淵明飲酒詩  其一二','滕岑','宋','宋诗','song-poetry','','[]','止酒盟諸神，覆杯未幾時。',72,'全唐诗/poet.song.159000.json','["止酒盟諸神，覆杯未幾時。", "有客苦相勸，持杯前致辭。", "人生足煩惱，至樂實在茲。", "欲飲恐渝盟，不飲客見疑。", "我性本嗜飲，强止良自欺。", "爲客盡一醉，惟神其聽之。"]'),
('db21ad79-fc3e-42be-b076-734ed6f5c5ac','和陶淵明飲酒詩  其一三','滕岑','宋','宋诗','song-poetry','','[]','嗣宗初亦仕，偶愛東平境。',60,'全唐诗/poet.song.159000.json','["嗣宗初亦仕，偶愛東平境。", "復求步兵尉，在職未嘗醒。", "當世疾如仇，妙音誰復領。", "吾詳竹林人，此士誠脫頴。", "至今群蝨喻，言與丹青炳。"]'),
('4bbbd6c2-216f-4833-8a92-da91c2e106d5','和陶淵明飲酒詩  其一四','滕岑','宋','宋诗','song-poetry','','[]','佳辰菊始華，白衣適爾至。',60,'全唐诗/poet.song.159000.json','["佳辰菊始華，白衣適爾至。", "開樽且復坐，徑向叢邊醉。", "陶死向千載，風流孰其次。", "達人豈在酒，寓意乃爲貴。", "吾知元亮賢，嗜酒不嗜味。"]'),
('d8c6a6aa-3f00-45d5-b989-6a25232b4b01','和陶淵明飲酒詩  其一五','滕岑','宋','宋诗','song-poetry','','[]','愛酒揚子雲，家世一區宅。',60,'全唐诗/poet.song.159000.json','["愛酒揚子雲，家世一區宅。", "校書登天祿，落拓聊寓迹。", "彼視漢公卿，何啻相什百。", "著書效周易，人笑玄尚白。", "儻非桓譚輩，詆誚誰與惜。"]'),
('a744caaa-236f-4a26-a120-c802ed939115','和陶淵明飲酒詩  其一六','滕岑','宋','宋诗','song-poetry','','[]','佛氏苦戒酒，詳見所譯經。',72,'全唐诗/poet.song.159000.json','["佛氏苦戒酒，詳見所譯經。", "謂人諸罪業，多以酒故成。", "酒豈能造罪，心爲物變更。", "心空罪亦空，徑造金仙庭。", "今我舉茲酒，聊救饑腸鳴。", "雖云違佛戒，初匪墮俗情。"]'),
('cb6a6bc9-cbd9-492d-b6cc-a7bdb1d3d9e1','和陶淵明飲酒詩  其一七','滕岑','宋','宋诗','song-poetry','','[]','少小慕至道，壯大無所得。',60,'全唐诗/poet.song.159000.json','["少小慕至道，壯大無所得。", "歲月忽如流，行年向不惑。", "爾來涉憂患，視聽半昏塞。", "誰能更苦辛，舉戰蠻觸國。", "但願常醉眠，萬事付一默。"]'),
('a23bd7cf-ef4e-4c65-800c-37b2ad035fda','和陶淵明飲酒詩  其一八','滕岑','宋','宋诗','song-poetry','','[]','有客衣百衲，狂言如病風。',48,'全唐诗/poet.song.159000.json','["有客衣百衲，狂言如病風。", "一飲至數斗，醉卧官道中。", "我嘗延之飲，問對略可通。", "告我珠異雀，無輕發其弓。"]'),
('4bbde98e-37fd-4ef1-a588-b4d300462b82','和陶淵明飲酒詩  其一九','滕岑','宋','宋诗','song-poetry','','[]','昔人揣才力，寧隠不願仕。',84,'全唐诗/poet.song.159000.json','["昔人揣才力，寧隠不願仕。", "仕者要及物，隠者止爲己。", "祿豐責已重，外勞中愧恥。", "何如未仕時，優游安井里。", "吾觀隠者傳，沉湎亦見紀。", "而於公卿輩，小累譏不止。", "布衣有真樂，勢位何足恃。"]'),
('8a8839f4-6c32-4a59-b519-0fbd76014f8e','和陶淵明飲酒詩  其二○','滕岑','宋','宋诗','song-poetry','','[]','是非俱幻影，妄別僞與真。',120,'全唐诗/poet.song.159000.json','["是非俱幻影，妄別僞與真。", "世界如空華，謾分澆與淳。", "古人今何在，千載一夢新。", "唐虞且空虛，豈復有隋秦。", "况我此之身，天地一微塵。", "區區欲徇世，用力嗟徒勤。", "邇來稍自悟，遂與杯酌親。", "世味如嚼蠟，說酒猶生津。", "朝醉忘盥頮，暮醉忘冠巾。", "世人自我異，我豈異世人。"]'),
('cc0f79cf-2887-4cc4-b4f0-76d61449ba07','贈徐谷三絕  其一','滕岑','宋','宋诗','song-poetry','','[]','解后逢君醉山縣，殷勤訪我到江城。',32,'全唐诗/poet.song.159000.json','["解后逢君醉山縣，殷勤訪我到江城。", "閑携箬笠無人識，狂殺癡兒問五行。"]'),
('95998be3-8117-441e-b8d2-d13912943549','贈徐谷三絕  其二','滕岑','宋','宋诗','song-poetry','','[]','裂去儒冠今幾年，顛毛蕭索任垂肩。',32,'全唐诗/poet.song.159000.json','["裂去儒冠今幾年，顛毛蕭索任垂肩。", "相逢記得初相識，回首西風一泫然。"]'),
('a58560b7-4f19-41ab-b440-c053db35c8c1','贈徐谷三絕  其三','滕岑','宋','宋诗','song-poetry','','[]','曾向林間對酒巵，不嫌俗物亦伸眉。',32,'全唐诗/poet.song.159000.json','["曾向林間對酒巵，不嫌俗物亦伸眉。", "江湖若許同歸去，能爲先生理釣絲。"]'),
('f16338bb-f772-4d4b-880d-2581d0e6b891','贈何應叔','滕岑','宋','宋诗','song-poetry','','[]','一面玉泉三載前，重來雲翮已翩然。',64,'全唐诗/poet.song.159000.json','["一面玉泉三載前，重來雲翮已翩然。", "筆端何自得許妙，林下不當迍此賢。", "作箇分明蟻宮夢，勝渠辛苦鳥窠禪。", "無鹽定自廢刻畫，索我惡詩何處傳。"]'),
('2cf38d61-1798-4293-a13c-ad9cc371a5d6','寄友人王晉老','滕岑','宋','宋诗','song-poetry','','[]','送君行日雪揚飛，曾幾何時畫箑揮。',64,'全唐诗/poet.song.159000.json','["送君行日雪揚飛，曾幾何時畫箑揮。", "自別空驚鬚髮變，得書聊證夢魂非。", "紫樞白簡家聲在，黄卷青燈生事微。", "悟得隨緣安樂法，不應羈旅更沾衣。"]'),
('084885cd-68a3-4893-8e7d-e2288fe6cacd','綠柿寄開欲遊釣臺以詩謝','滕岑','宋','宋诗','song-poetry','','[]','西城好在朱夫子，屈指經年隔笑談。',64,'全唐诗/poet.song.159000.json','["西城好在朱夫子，屈指經年隔笑談。", "忽枉尺書相勞苦，更蒙綠柿遠分甘。", "似聞欲訪嚴陵瀨，何惜暫辭彌勒龕。", "已約桐君候舟楫，當令風月往迎參。"]'),
('a7da43d1-49a8-4ba9-b436-536085b60a7c','酴醾  其一','滕岑','宋','宋诗','song-poetry','','[]','紅紫從渠巧鬭新，不妨自著素衣巾。',32,'全唐诗/poet.song.159000.json','["紅紫從渠巧鬭新，不妨自著素衣巾。", "中庭今夜群仙戲，總是廣寒宮裏人。"]'),
('6d4172d0-ac2e-422c-9701-f2dbbbbe4cc3','酴醾  其二','滕岑','宋','宋诗','song-poetry','','[]','向人未肯吐芳心，玉困香融己不禁。',32,'全唐诗/poet.song.159000.json','["向人未肯吐芳心，玉困香融己不禁。", "久矣禪心無色想，如何對此獨沉吟。"]'),
('ce0e86a9-f325-46d6-9fb3-ac93e1bf7aeb','酴醾  其三','滕岑','宋','宋诗','song-poetry','','[]','群芳誰不讓天柔，笑殺金沙敢並遊。',32,'全唐诗/poet.song.159000.json','["群芳誰不讓天柔，笑殺金沙敢並遊。", "少借餘妍入樽酒，真堪一斗博凉州。"]'),
('2cabbe78-7810-47c6-8d9b-23103fb6acfb','杏花','滕岑','宋','宋诗','song-poetry','','[]','君家兩杏閙春色，濃淡臙脂染不齊。',32,'全唐诗/poet.song.159000.json','["君家兩杏閙春色，濃淡臙脂染不齊。", "試喚趙昌來貌取，若邊好著白鷴棲。"]'),
('1f01390c-8d28-4c6c-b887-4db55ed4f95b','次韻歐公殘杏','滕岑','宋','宋诗','song-poetry','','[]','春風雖高却不寒，扶杖起散腰脚頑。',128,'全唐诗/poet.song.159000.json','["春風雖高却不寒，扶杖起散腰脚頑。", "昨朝陰晦忽開霽，造物變化胡可原。", "休嫌出遊日色薄，大勝坐聽簷聲潺。", "百歲光陰人易老，一年時節春易闌。", "但知良辰合大醉，豈羨顯官乘高軒。", "桃花飄零李花在，垂柳嫋娜芳草繁。", "誰能有藥扶我足，使我郊野窮躋攀。", "山公接䍦自倒著，吾髮已禿久不冠。"]'),
('2114c594-5bb3-4c0f-8568-5a07143bc3fa','梅花  其一','滕岑','宋','宋诗','song-poetry','','[]','欲尋好句乞梅花，從實平章不要誇。',32,'全唐诗/poet.song.159000.json','["欲尋好句乞梅花，從實平章不要誇。", "且道色香誰可比，口纔擬議即成差。"]'),
('b29c33bb-a2d9-4837-9c76-b21e919056f6','梅花  其二','滕岑','宋','宋诗','song-poetry','','[]','論白人惟議冰雪，言香佛亦取旃檀。',32,'全唐诗/poet.song.159000.json','["論白人惟議冰雪，言香佛亦取旃檀。", "旃檀冰雪固大好，只恐將渠比並難。"]'),
('0db3726f-2c12-4e16-aea3-f30baa9bd45a','梅花  其三','滕岑','宋','宋诗','song-poetry','','[]','色香其實無與比，摹寫百端良可嗟。',32,'全唐诗/poet.song.159000.json','["色香其實無與比，摹寫百端良可嗟。", "我今與下語一則，此是梅花非別花。"]'),
('106e9e05-7680-41fe-9827-c1f4d84ea9b1','擬名都篇','滕岑','宋','宋诗','song-poetry','','[]','名都一何綺，宇內第一州。',156,'全唐诗/poet.song.159000.json','["名都一何綺，宇內第一州。", "富貴習奢靡，𣊓御乃其尤。", "沈沈彼大屋，繚垣峻而脩。", "主人正恩幸，執事近冕旒。", "金多不可計，勢張渠得儔。", "藻幄群艷女，雕輿盛華騶。", "器用尚方亞，服食中禁侔。", "園池亦何似，三島與十洲。", "稱者不勝談，觀者徒眩眸。", "迅雷忽下擊，飛電仍窮搜。", "方恃金玉堅，遽爲烟霧收。", "天道不可欺，崇替定難籌。", "陳迹變陵谷，誰復爲悲憂。"]'),
('f87e2f3c-bc4f-4de0-92e8-f30361ea34df','甲申大水二首  其一','滕岑','宋','宋诗','song-poetry','','[]','吾州背山面江流，一雨便有泛溢憂。',67,'全唐诗/poet.song.159000.json','["吾州背山面江流，一雨便有泛溢憂。", "况復梅霖倒江海，白晝洶若龍移湫。", "眼看上流沒高樹，下流屋廬渺無處。", "君不見甲子之歲至甲申，如此災變已三度。"]'),
('dc1017eb-9003-4aad-afae-e79de8e690d0','甲申大水二首  其二','滕岑','宋','宋诗','song-poetry','','[]','歙水震蕩方流東，婺水南來塞其衝。',67,'全唐诗/poet.song.159000.json','["歙水震蕩方流東，婺水南來塞其衝。", "二水爭雄屹不去，孤城匯爲河伯宮。", "經旬水落流民復，身存不用嗟無屋。", "君不見去年金虜破淮壖，城郭千里無人煙。"]'),
('e39bf587-57ec-4a68-af07-c9ac046f51b5','辛丑大水','滕岑','宋','宋诗','song-poetry','','[]','天公哀此生人苦，潸然出涕灑下土。',176,'全唐诗/poet.song.159000.json','["天公哀此生人苦，潸然出涕灑下土。", "五晝五夜涕不已，平陸成河山作渚。", "是方爲邑本霔下，今者之變頃未覩。", "何止人家水半扉，或壓或溺遍處所。", "舉家老稚幾爲魚，夜乘一葉投山塢。", "雖知此邦禍可免，頗念吾廬欹莫拄。", "朝登山巔聊放目，流尸蔽江可勝數。", "何處奔洪之所擠，一旦至斯辜非汝。", "天公用是涕愈流，陽侯正自喜且舞。", "我願天公且收涕，憂之反傷亦奚補。", "但令老眼開日月，蒼生自然得安堵。"]'),
('70489dec-d4bc-4984-b7ec-44b6ee71c3df','秋江四絕  其一','滕岑','宋','宋诗','song-poetry','','[]','十日江頭一向風，差差寒浪白吹空。',32,'全唐诗/poet.song.159000.json','["十日江頭一向風，差差寒浪白吹空。", "漁舠輊小不如葉，信意低昂風浪中。"]'),
('27f91963-2d0f-46b0-9c5e-c32dea949c70','秋江四絕  其二','滕岑','宋','宋诗','song-poetry','','[]','風色蕭蕭日色晴，晚潮未到水波平。',32,'全唐诗/poet.song.159000.json','["風色蕭蕭日色晴，晚潮未到水波平。", "繫槎艇子關蓬睡，不管溪南喚渡聲。"]'),
('d31705fa-2013-45fc-b44a-d51385caf81d','秋江四絕  其三','滕岑','宋','宋诗','song-poetry','','[]','一川晚色澹煙浮，不覺潮生水倒流。',32,'全唐诗/poet.song.159000.json','["一川晚色澹煙浮，不覺潮生水倒流。", "人語津亭燈火閙，客帆椎鼓過沙洲。"]'),
('d5520c29-2834-4aaf-8957-1741d9725b66','秋江四絕  其四','滕岑','宋','宋诗','song-poetry','','[]','玉輪推上暮雲端，金蹙波心一片瀾。',32,'全唐诗/poet.song.159000.json','["玉輪推上暮雲端，金蹙波心一片瀾。", "隠隠漁舟橫絕去，何人江岸倚樓看。"]'),
('39b3a7a2-ebc2-4616-91c3-4907d2b86de0','山𥖎','滕岑','宋','宋诗','song-poetry','','[]','水仙委蛇江梅老，架上酴醾雪未翻。',32,'全唐诗/poet.song.159000.json','["水仙委蛇江梅老，架上酴醾雪未翻。", "千斛妙香留不用，一時分付與山礬。"]'),
('a71555cf-58d9-4b8b-be51-3fc46ca85fc6','折花','滕岑','宋','宋诗','song-poetry','','[]','清晨折新花，插向玉瓶水。',48,'全唐诗/poet.song.159000.json','["清晨折新花，插向玉瓶水。", "休云離本根，且復新案几。", "置酒就之飲，芳片落杯裏。", "猶勝向中園，容易污泥滓。"]'),
('a469917d-773a-4cf9-8070-6999b75170a6','惜梅  其一','滕岑','宋','宋诗','song-poetry','','[]','沙晴日暖雪消時，春到南枝未覺遲。',32,'全唐诗/poet.song.159000.json','["沙晴日暖雪消時，春到南枝未覺遲。", "東崦人家三百樹，與君扶杖試尋之。"]'),
('01fcd32c-169e-4775-89f9-46880f11e76f','惜梅  其二','滕岑','宋','宋诗','song-poetry','','[]','沈瘦難禁詩作魔，年年詩句爲花多。',32,'全唐诗/poet.song.159000.json','["沈瘦難禁詩作魔，年年詩句爲花多。", "亦知習氣要除盡，奈此高風勝韻何。"]'),
('f8952b13-25b4-4312-9c8e-2a075ad19baa','惜梅  其三','滕岑','宋','宋诗','song-poetry','','[]','牧孺樵童不管春，亂攀曾不比荆榛。',32,'全唐诗/poet.song.159000.json','["牧孺樵童不管春，亂攀曾不比荆榛。", "那知立馬江南客，一萼真香淚一巾。"]'),
('a57584de-5b13-47c6-ad96-d1b644cb9551','玩松竹  其一','滕岑','宋','宋诗','song-poetry','','[]','蕭蕭園中竹，不復數萱草。',60,'全唐诗/poet.song.159000.json','["蕭蕭園中竹，不復數萱草。", "蒼蒼池上松，豈更問蘋藻。", "二物吾所愛，難爲俗人道。", "竹如吾之節，松似吾之老。", "煙雨風月中，形聲俱媚好。"]'),
('7d05a6c5-3878-4499-ab00-f628a9184893','玩松竹  其二','滕岑','宋','宋诗','song-poetry','','[]','馬目在屋南，龍峰在屋北。',60,'全唐诗/poet.song.159000.json','["馬目在屋南，龍峰在屋北。", "南爲山所障，北半露山色。", "頼有竹與松，足供予燕息。", "竹乃前歲栽，種自別墅得。", "松長已百年，不知誰所植。"]'),
('12be1801-8fb9-4c7d-8013-0a3ad7f11a12','寒雞','滕岑','宋','宋诗','song-poetry','','[]','寒雞强知曉，初鳴夢驚破。',72,'全唐诗/poet.song.159000.json','["寒雞强知曉，初鳴夢驚破。", "我事不在早，援衾且復卧。", "待旦枕戈寢，將朝盛服坐。", "吾生無怨仇，吾責非輔佐。", "况當苦寒月，北風正掀簸。", "且復待午暄，徐起畢經課。"]'),
('ceac3321-921f-4619-8846-fadc016107c9','擬白馬篇','滕岑','宋','宋诗','song-poetry','','[]','白馬紫遊韁，意氣何飄揚。',132,'全唐诗/poet.song.159000.json','["白馬紫遊韁，意氣何飄揚。", "五陵富貴子，人謂天上郎。", "春華動新鞭，□蓋生輝光。", "行經幾臺觀，下馬毬鞠場。", "吹彈陳妙伎，歌舞集名倡。", "歡醉未云足，揮散千金彊。", "朝遊曛莫返，訖春以爲常。", "天祿揚子雲，矻矻事文章。", "草玄既自苦，投閣仍自傷。", "平生甚愛酒，何曾酣杯觴。", "較彼萬不如，虛名何足臧。"]'),
('d0089a51-1dcc-4c53-b6b9-fc21e3902874','官捕虎行','滕岑','宋','宋诗','song-poetry','','[]','世無壯士力扼虎，群虎食人人莫禦。',192,'全唐诗/poet.song.159000.json','["世無壯士力扼虎，群虎食人人莫禦。", "上官付之無奈何，懸賞謾令招獵戶。", "獵戶徒能逐麕麂，初非法中虎匠比。", "心膽既怯賞又輕，誰肯向前判一死。", "官遣弓兵相助佐，獵戶見之氣先挫。", "心憂得賞爲所分，眼見有虎容渠過。", "弓兵散在村落中，村民鷄犬爲一空。", "四足之虎未可捕，兩足之人與虎同。", "真虎爲患時一出，人虎爲患朝連久。", "東鄉聞虎在西隣，人虎又向西鄉集。", "野外晡時即掩關，椎蘇不復更登山。", "人虎難避愈真虎，縱爲虎食不聞官。"]'),
('68f4a58e-0d8a-498a-9160-8feb1a9ce9e6','次韻樂天山居','滕岑','宋','宋诗','song-poetry','','[]','不能蚤歲作農夫，强學爲儒途路迂。',64,'全唐诗/poet.song.159000.json','["不能蚤歲作農夫，强學爲儒途路迂。", "老有微官沾薄祿，鈍無捷徑上榮衢。", "遥峰窣堵似屏展，近岸拒霜如錦鋪。", "莫笑吾廬大幽寂，眼前此景一村無。"]'),
('80f905f6-f2d7-407d-a77e-c0d2c7dec7dd','和方薄山居','滕岑','宋','宋诗','song-poetry','','[]','江村宜晚景，老眼見來稀。',48,'全唐诗/poet.song.159000.json','["江村宜晚景，老眼見來稀。", "遠岫屏六出，殘霞錦一機。", "月華池上好，暑氣竹間微。", "不羨御風列，旬餘五日歸。"]'),
('b5acd969-083b-4e5e-a080-c8f1ac5868c1','次韻樂天村居','滕岑','宋','宋诗','song-poetry','','[]','池水浮黄葉，窗扉列翠嵐。',48,'全唐诗/poet.song.159000.json','["池水浮黄葉，窗扉列翠嵐。", "蟻歷新夢破，鷗已舊盟寒。", "足病喜安坐，目昏愁遠看。", "無人來問道，不用倒幡竿。"]'),
('814f5375-dea0-426e-b6b1-498bbcc38227','題釣臺對嚴氏樓三首  其一','滕岑','宋','宋诗','song-poetry','','[]','扁舟江上幾曾經，山崦層樓似畫屏。',32,'全唐诗/poet.song.159000.json','["扁舟江上幾曾經，山崦層樓似畫屏。", "豈料今爲倚樓客，誰能添我入丹青。"]'),
('c6f1e7e1-3420-4fa6-a0f3-98916a0d5eb5','題釣臺對嚴氏樓三首  其二','滕岑','宋','宋诗','song-poetry','','[]','乃祖高懷傲帝王，遠孫依舊晦文章。',32,'全唐诗/poet.song.159000.json','["乃祖高懷傲帝王，遠孫依舊晦文章。", "不須苦要爲官去，看水看山味最長。"]'),
('10e1d24a-df19-4383-99fa-695448344283','題釣臺對嚴氏樓三首  其三','滕岑','宋','宋诗','song-poetry','','[]','秋江不許一塵染，只有青山倒影寒。',32,'全唐诗/poet.song.159000.json','["秋江不許一塵染，只有青山倒影寒。", "我欲移家來住此，煩君先爲斬魚竿。"]'),
('05ff0f3e-ec9f-46ff-bbfc-efa91d8f52f5','樓上偶成  其一','滕岑','宋','宋诗','song-poetry','','[]','高閣前依柳，幽窗下見池。',48,'全唐诗/poet.song.159000.json','["高閣前依柳，幽窗下見池。", "廢書凡累日，倚檻獨多時。", "谷暖花開遍，山長鳥去遲。", "千窮坐一拙，元自不關詩。"]'),
('d16b764a-f357-4430-96a4-dd0068563eb2','樓上偶成  其二','滕岑','宋','宋诗','song-poetry','','[]','隴麥已抽穟，山田未立苗。',48,'全唐诗/poet.song.159000.json','["隴麥已抽穟，山田未立苗。", "雨聲愁昨夕，晴色喜今朝。", "柳絮青天雪，松風陸地潮。", "山居足幽事，吾隠不須招。"]'),
('2c64045a-5826-4ef0-a008-ccfcbab6a9ef','次韻樂天村居卧病  其一','滕岑','宋','宋诗','song-poetry','','[]','巖桂花已空，時節秋尚暮。',72,'全唐诗/poet.song.159000.json','["巖桂花已空，時節秋尚暮。", "叢菊夾徑幽，猶未金鈿露。", "好客喚不來，衰疾推不去。", "山園何寂寥，秋聲起竹樹。", "西郊遠塵境，更在山崦住。", "自應親友絕，休問何以故。"]'),
('13063f94-487e-4d92-a08f-c8deb026f318','次韻樂天村居卧病  其二','滕岑','宋','宋诗','song-poetry','','[]','平林卷宿霧，白日行黄道。',72,'全唐诗/poet.song.159000.json','["平林卷宿霧，白日行黄道。", "窗橫四圍山，門掩三徑草。", "老人苦夜永，褰衣起常早。", "既無姬妾侍，寧有衾禂抱。", "身心兩清浄，衰病反爲好。", "問我年幾何，年已踰綽老。"]'),
('afc72600-0f81-45cb-983f-af1db25af9ff','次韻樂天村居卧病  其三','滕岑','宋','宋诗','song-poetry','','[]','瓦盞茅柴濁，磚鑪榾柮紅。',48,'全唐诗/poet.song.159000.json','["瓦盞茅柴濁，磚鑪榾柮紅。", "味如飲醽醁，暖勝燎蒿蓬。", "萬種皆幻事，一真惟太空。", "舊氈敷故絮，小閤卧衰翁。"]'),
('96b3c670-de6d-4a13-99c7-120adb7448f1','題永泰顯上人箇中菴  其一','滕岑','宋','宋诗','song-poetry','','[]','葛藤遍諸方，悟者能幾箇。',48,'全唐诗/poet.song.159000.json','["葛藤遍諸方，悟者能幾箇。", "誰知箇中庵，鑪火但趺坐。", "齋鉢幸不空，法輪常自磨。", "饑餐困來眠，工夫沒量大。"]'),
('f985c5b7-e78f-4732-9161-18a7a0a05ff2','題永泰顯上人箇中菴  其二','滕岑','宋','宋诗','song-poetry','','[]','內外及中間，無處尋這箇。',48,'全唐诗/poet.song.159000.json','["內外及中間，無處尋這箇。", "若捨內外中，又向鬼窟坐。", "團團踏故迹，笑殺牛挽磨。", "隨處即箇中，始顯機用大。"]'),
('efdec532-ffbf-4169-89c0-4dcfea3c1a7f','南新慈照寺','滕岑','宋','宋诗','song-poetry','','[]','平生不踏南新路，早歲嘗誦東坡詩。',67,'全唐诗/poet.song.159000.json','["平生不踏南新路，早歲嘗誦東坡詩。", "青牛聾僧今不見，慈照乃有那律師。", "君不見世間萬事皆兒嬉，不如聾盲百不知。", "雙明閣上夕陽時，一笑二子閑爭棋。"]'),
('c86664ef-2c3f-43d0-b26f-b94fedcc83cd','中興碑','滕岑','宋','宋诗','song-poetry','','[]','字畫端重無傾欹，文辭簡古有刺譏。',128,'全唐诗/poet.song.159000.json','["字畫端重無傾欹，文辭簡古有刺譏。", "高堂一見爲却立，知是浯水中興碑。", "當時長安望浯水，相去不知幾千里。", "斯文自合上送官，如何鑱向千巖底。", "二公用意深復深，知我罪我俱無心。", "不向一時求賞音，億代寶之如璆琳。", "孽臣之事置莫說，尚喜蠶頭未訛缺。", "紛紛理亂墮空虛，千古斷崖懸日月。"]'),
('9577f58c-2082-40c5-9aa7-7ca6b573bf18','白紵歌  其一','滕岑','宋','宋诗','song-poetry','','[]','白紵舞女楊花輕，玉笙學得悲鳳鳴。',72,'全唐诗/poet.song.159000.json','["白紵舞女楊花輕，玉笙學得悲鳳鳴。", "爛然繁星上華檠，凉苑夜宴風氣清。", "美人酒半粧臉明，寶釵綰髻歌欲傾。", "良宵人人願君醉，豈問徧誰得君意，君其歡娛至萬歲。"]'),
('633f71ae-b14a-4263-8ac6-2eedfdfb8705','白紵歌  其二','滕岑','宋','宋诗','song-poetry','','[]','白紵舞衫記初著，月明侍宴臨飛閣。',80,'全唐诗/poet.song.159000.json','["白紵舞衫記初著，月明侍宴臨飛閣。", "舞餘香暖苒浮襟，進前持酒力不任。", "君王凝笑盃未覆，不惜低徊重舞曲。", "當時一身備百好，月不長圓秋易老。", "白紵凄凉棄篋中，不悲見棄悲秋風。"]'),
('5538cc00-627a-42cf-929b-2dc9f269cb7a','短歌行','滕岑','宋','宋诗','song-poetry','','[]','鑄黄金，服白玉，方法難成日月促。',96,'全唐诗/poet.song.159000.json','["鑄黄金，服白玉，方法難成日月促。", "十年著書五車讀，功名未就鬢髮禿。", "海水可盡山可平，人心何日息營營。", "安期羨門果何在，賈誼劉向終奚成。", "前人不悟已如此，後人還復躡其軌。", "玉東西，金叵羅，君不肯醉當奈何。"]'),
('38a38742-78f6-4364-8544-c783ce6e9e21','行路難','滕岑','宋','宋诗','song-poetry','','[]','行路難，東南地傾水瀰漫。',248,'全唐诗/poet.song.159000.json','["行路難，東南地傾水瀰漫。", "三江五湖滄海寬，魚龍出沒肆神姦。", "萬斛不勞一蹴翻，江水有潮溪有灘。", "錢塘潮頭平越山，乘潮寄命呼吸間。", "上灘篙挽寸步慳，下灘小跌淪奔湍。", "我行河道差若安，亡奈衆堰爲阻艱。", "兩牛力盡費躋攀，咫尺猶如限重關。", "行路難，西南之險更莫言。", "一山至有百八盤，猿猱欲上愁復還。", "汝如憚行要登船，恐汝膽落濆淖旋。", "此去投北經中原，崑崙萬里傾濁瀾。", "一吞數舟歲常然，舟楫么麽吁難全。", "陸行崤函車不前，况復羊腸萬屈蟠。", "其餘禹歷諸山川，深入無底高㨖天。", "行路難，有如此，不如閉門且隠几。", "門前有地平如砥，無憂那憂勃堆起。"]'),
('2a6ba330-1871-4bcf-b6ba-6c537c05887f','樂天狂歌詞','滕岑','宋','宋诗','song-poetry','','[]','憶昔少狂逸，無酒即典衣。',72,'全唐诗/poet.song.159000.json','["憶昔少狂逸，無酒即典衣。", "痛飲至爛醉，危坐讀楚詞。", "今我已衰老，不復如前癡。", "尚要飲酒醪，聊用度歲時。", "爲儒不登第，爲郎又乏貲。", "無衣以準酒，狂歌徒爾爲。"]'),
('d2a59f77-37d3-4937-bd1c-bde5ab4302c0','句  其一','滕岑','宋','宋诗','song-poetry','','[]','苔痕遺鳥爪，菊本寄蛩音。',12,'全唐诗/poet.song.159000.json','["苔痕遺鳥爪，菊本寄蛩音。"]'),
('b35c1fa6-7983-41b6-8b19-75e7bab2a82b','句  其二','滕岑','宋','宋诗','song-poetry','','[]','客櫓行何晚，鄰機織未休。',12,'全唐诗/poet.song.159000.json','["客櫓行何晚，鄰機織未休。"]'),
('0696f330-ef2b-4f29-a308-cd923a77821c','句  其三','滕岑','宋','宋诗','song-poetry','','[]','老屋險不仆，寒袍半欲紪。',12,'全唐诗/poet.song.159000.json','["老屋險不仆，寒袍半欲紪。"]'),
('0894f540-cd63-4ade-b438-b90b294abb73','西北有高樓','楊冠卿','宋','宋诗','song-poetry','','[]','西北有高樓，氤氳臨大路。',72,'全唐诗/poet.song.159000.json','["西北有高樓，氤氳臨大路。", "飛簷轉春風，綺窗鏁雲霧。", "姣服者誰子，傾城此容與。", "娟娟長眉青，不受脂澤汙。", "娉婷惜不嫁，恐爲蕩子悞。", "寫心汎清瑟，獨不怨遲暮。"]'),
('31454c70-e80c-4a61-a9f8-93b0d02beefc','東方有一士','楊冠卿','宋','宋诗','song-poetry','','[]','東方有一士，不見心忡忡。',60,'全唐诗/poet.song.159000.json','["東方有一士，不見心忡忡。", "尺璧未足多，夙好良所同。", "永懷不能寐，攬衣出房櫳。", "遥夜未渠央，取琴和秋蟲。", "豈無時世交，諒彼不相容。"]'),
('a615aef4-fd04-44f6-be55-fe131c631795','銅雀妓','楊冠卿','宋','宋诗','song-poetry','','[]','分盡餘香空寶奩，罷臨歌舞夜厭厭。',64,'全唐诗/poet.song.159000.json','["分盡餘香空寶奩，罷臨歌舞夜厭厭。", "清蹕不傳虛繡帳，洞房月在西陵上。", "玉殿塵埃閑御仗，翠眉忍上平臺望。", "宮車一去不復還，畫羅金縷尚斑斑。"]'),
('54ce0f0c-8ece-487e-b554-e64462d97370','赤玉簫','楊冠卿','宋','宋诗','song-poetry','','[]','玉簫早入凉王墓，弓劍衣冠只同處。',64,'全唐诗/poet.song.159000.json','["玉簫早入凉王墓，弓劍衣冠只同處。", "千年邂逅出人間，顔色聲音幸如故。", "雲門曲譜不分明，趙瑟齊竽各自名。", "傳看樂府無人識，此簫收聲甘棄擲。"]'),
('3716c9db-fd3e-4f2d-96c2-7776a29f15a0','秋懷十首微雲淡河漢疏雨滴梧桐爲韻  其一','楊冠卿','宋','宋诗','song-poetry','','[]','寒蟬初停號，客燕催將歸。',48,'全唐诗/poet.song.159000.json','["寒蟬初停號，客燕催將歸。", "吾亦客一世，去此復焉依。", "歛袵聽物變，著書明化機。", "深參漆園吏，渠語甚精微。"]'),
('71a474a1-22bf-4023-a7c2-1018e8b2dd86','秋懷十首微雲淡河漢疏雨滴梧桐爲韻  其二','楊冠卿','宋','宋诗','song-poetry','','[]','秋風不肯來，如挽弓百斤。',48,'全唐诗/poet.song.159000.json','["秋風不肯來，如挽弓百斤。", "忽然徑排戶，態度殊不文。", "方深裘褐憂，暮雨低行雲。", "焚香快熟睡，夢破尚微曛。"]'),
('fd493d0c-0c82-4bd6-b361-aa9523d16eda','秋懷十首微雲淡河漢疏雨滴梧桐爲韻  其三','楊冠卿','宋','宋诗','song-poetry','','[]','呼船下平湖，山如髻鬟瞰。',48,'全唐诗/poet.song.159000.json','["呼船下平湖，山如髻鬟瞰。", "物華逼摇落，水明天淡淡。", "中藏今古愁，歲月不可勘。", "爲語羊征南，聲名本來蹔。"]'),
('965784a4-b074-4873-b5a7-7a7ab74598ab','秋懷十首微雲淡河漢疏雨滴梧桐爲韻  其四','楊冠卿','宋','宋诗','song-poetry','','[]','饑來詎堪忍，振履商頌歌。',48,'全唐诗/poet.song.159000.json','["饑來詎堪忍，振履商頌歌。", "時人不料理，政可著巖阿。", "喻龜且曳尾，勸公無渡河。", "一朝失脚去，寧得此婆娑。"]'),
('3843bd81-9bc3-4b65-9157-af4d1fa2310d','秋懷十首微雲淡河漢疏雨滴梧桐爲韻  其五','楊冠卿','宋','宋诗','song-poetry','','[]','古人例躬耕，我坐老無斷。',48,'全唐诗/poet.song.159000.json','["古人例躬耕，我坐老無斷。", "勇爲梁父吟，已媿杜鵑喚。", "幽幽桃華源，尚不知有漢。", "婦子彼何爲，徒使人意亂。"]'),
('d7dcf2fd-dba2-45fb-a926-0585689f09ed','秋懷十首微雲淡河漢疏雨滴梧桐爲韻  其六','楊冠卿','宋','宋诗','song-poetry','','[]','月上天無雲，樹陰散扶疎。',48,'全唐诗/poet.song.159000.json','["月上天無雲，樹陰散扶疎。", "秋聲生寂歷，凉颸滿吾廬。", "幸此尊有酒，敢歌食無魚。", "陶然且一醉，世間各賢愚。"]'),
('77ce3b83-545d-4478-9788-70499499aaeb','秋懷十首微雲淡河漢疏雨滴梧桐爲韻  其七','楊冠卿','宋','宋诗','song-poetry','','[]','春秧困深寒，夏穗仍愍雨。',48,'全唐诗/poet.song.159000.json','["春秧困深寒，夏穗仍愍雨。", "書來西江西，赤地掃瓜芋。", "墨數食指多，坐羞長袖舞。", "憂憂米如珠，南山采薇去。"]'),
('1a498566-3b50-42b3-bc24-0ac5155ac827','秋懷十首微雲淡河漢疏雨滴梧桐爲韻  其八','楊冠卿','宋','宋诗','song-poetry','','[]','晚雲蹔垂陰，零露不成滴。',48,'全唐诗/poet.song.159000.json','["晚雲蹔垂陰，零露不成滴。", "隣牆幾好樹，葉下聲策策。", "一燈同夜闌，此抱誰與適。", "前身豈壁魚，甘擅文字癖。"]'),
('dda6aff1-bd50-4ce7-89ee-3a218a3385a0','秋懷十首微雲淡河漢疏雨滴梧桐爲韻  其九','楊冠卿','宋','宋诗','song-poetry','','[]','憂來抵揬人，衰懷小城孤。',48,'全唐诗/poet.song.159000.json','["憂來抵揬人，衰懷小城孤。", "解圍頼從事，幾成不支梧。", "所憂豈其私，天高信難呼。", "努力加餐飯，世緣久崎嶇。"]'),
('2e8f8584-d94e-49d3-b3e7-b70f9b49cc00','秋懷十首微雲淡河漢疏雨滴梧桐爲韻  其一○','楊冠卿','宋','宋诗','song-poetry','','[]','幽花上籬落，寒煙婘楸桐。',48,'全唐诗/poet.song.159000.json','["幽花上籬落，寒煙婘楸桐。", "絡緯勉婦織，暮色凄房櫳。", "日月如跳丸，蟲魚不書攻。", "髮黑今益白，脫巾成老翁。"]'),
('80fdcdc0-176a-400b-b963-63cd3762175b','北亭','楊冠卿','宋','宋诗','song-poetry','','[]','北風無時休，荒山路綿綿。',48,'全唐诗/poet.song.159000.json','["北風無時休，荒山路綿綿。", "老馬被吹揚，却立不肯前。", "我僕行且仆，竟日數里間。", "悠然欲何適，正坐歸無田。"]'),
('8b167a6c-d5d5-4f7a-9b6f-9342629c88c3','感事','楊冠卿','宋','宋诗','song-poetry','','[]','我車昔載脂，柳色初濯濯。',48,'全唐诗/poet.song.159000.json','["我車昔載脂，柳色初濯濯。", "及歸脫征驂，柳葉半黄落。", "恍然僅一夢，已費十晦朔。", "祇應爲客老，惘惘不自覺。"]'),
('e29fde7a-86b0-4598-ae31-9eaf4d97fd1d','赴城南隠居小集','楊冠卿','宋','宋诗','song-poetry','','[]','白雨濯青山，孤雲靄餘姿。',96,'全唐诗/poet.song.159000.json','["白雨濯青山，孤雲靄餘姿。", "溶溶荒江水，近岸生清漪。", "扶輿出城府，眷此幽人期。", "茅茨倚林麓，秀薄相參差。", "欣茲蹔解带，虛白明朝曦。", "向來旅窮徼，抑鬰中懷悲。", "相逢輒顧笑，觴酒相淋漓。", "春風不日去，淹留我何爲。"]'),
('d8025f15-6aa2-4668-ad26-489a948ebd6a','悲秋  其一','楊冠卿','宋','宋诗','song-poetry','','[]','秋色遽如許，客心徒自驚。',48,'全唐诗/poet.song.159000.json','["秋色遽如許，客心徒自驚。", "盈盈露花泣，策策風樹鳴。", "別影詎可吊，强懷不能平。", "軒車幾時還，惻愴難爲情。"]'),
('92f77405-b77d-4d28-98ba-11c4135811f9','悲秋  其二','楊冠卿','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','沄沄西江水，送我沙邊舟。',48,'全唐诗/poet.song.159000.json','["沄沄西江水，送我沙邊舟。", "當時送行客，勉我無久留。", "晤言宛如昨，庭葉忽再秋。", "人生寸心違，何以消吾憂。"]'),
('b52601f8-9e98-4c85-aa6f-bfd2f129aed2','夜坐看月  其一','楊冠卿','宋','宋诗','song-poetry','','[]','南風掃陰翳，快若誅神姦。',60,'全唐诗/poet.song.159000.json','["南風掃陰翳，快若誅神姦。", "日暮天無雲，月出房心間。", "幽人倦蒸溽，癡坐山中山。", "連連甲子雨，幸此天破慳。", "清明皆我有，何但窺一斑。"]'),
('bf56fa2f-262f-41f7-9a69-6b81c6c19bbc','夜坐看月  其二','楊冠卿','宋','宋诗','song-poetry','','[]','春泥少曾乾，天漏幾不補。',60,'全唐诗/poet.song.159000.json','["春泥少曾乾，天漏幾不補。", "冥觀赤烏飛，喜見長虹吐。", "修竹來清風，孤光相媚嫵。", "心神濯冰壺，何必須起舞。", "更欲尋斷橋，前溪有饑虎。"]'),
('3fc6986b-7d17-44fe-8f66-02840a762434','夜坐看月  其三','楊冠卿','宋','宋诗','song-poetry','','[]','春夏季孟間，草木蔽山骨。',60,'全唐诗/poet.song.159000.json','["春夏季孟間，草木蔽山骨。", "青蒼靄芳華，煙霏相出沒。", "適從憂患場，觀化超理窟。", "無心岫間雲，有定水中月。", "我方意如如，誰尚書咄咄。"]'),
('e73d9759-2604-42bd-a6c9-c4943c297806','暮景  其一','楊冠卿','宋','宋诗','song-poetry','','[]','鞍馬來殊方，祇園已秋寂。',48,'全唐诗/poet.song.159000.json','["鞍馬來殊方，祇園已秋寂。", "虛堂耿清夜，卧聽寒雨滴。", "永懷平生願，浩蕩誰與適。", "愁心正紛如，西風韻鄰笛。"]'),
('223d398a-3a7b-463e-9189-cf266f5cd052','暮景  其二','楊冠卿','宋','宋诗','song-poetry','','[]','客行無常期，遠適亦有歸。',48,'全唐诗/poet.song.159000.json','["客行無常期，遠適亦有歸。", "家人具膏沐，垢髮幸一晞。", "可憐兒時面，坐受塞色欺。", "看鏡恍如失，功名定何時。"]'),
('ff1e9a2b-4097-4466-8399-f8debaa23b36','九日  其一','楊冠卿','宋','宋诗','song-poetry','','[]','晨風戰枯荷，清霜殺高柳。',48,'全唐诗/poet.song.159000.json','["晨風戰枯荷，清霜殺高柳。", "人生俯仰間，能得幾重九。", "節序來無停，已及黄花酒。", "流落拾遺心，西江獨回首。"]'),
('a8b82930-9abe-43d8-be84-7a6722af42d1','九日  其二','楊冠卿','宋','宋诗','song-poetry','','[]','寒花有餘馨，香醪甜勝蜜。',48,'全唐诗/poet.song.159000.json','["寒花有餘馨，香醪甜勝蜜。", "紅萸爾相宜，飣餖雜梨栗。", "家家事行樂，似恐更無日。", "時日豈不佳，人意自難詰。"]'),
('5e45a88a-ea87-4937-a532-bddfa8e583b3','九日  其三','楊冠卿','宋','宋诗','song-poetry','','[]','凄凉少陵老，梓州九日詩。',48,'全唐诗/poet.song.159000.json','["凄凉少陵老，梓州九日詩。", "朝廷入夢想，弟妹天一涯。", "我亦困羈旅，千古同其悲。", "不忍嗅新菊，惟思詠江蘺。"]'),
('7b3797a9-9f41-46c8-bdc9-3039c9773c17','晚思','楊冠卿','宋','宋诗','song-poetry','','[]','花意就銷歇，芳樹初陰陰。',60,'全唐诗/poet.song.159000.json','["花意就銷歇，芳樹初陰陰。", "薄帷受清吹，鳥聲幽院深。", "感此時節改，素標不勝簪。", "取酒洗玉船，慰我懷古心。", "小醉睨落景，歸盟猶可尋。"]'),
('66385ade-1e30-4b5e-a9ea-3b84e12e725f','久客倦遊歸憩僧坊有懷蓬居梵竺卿寂光常不輕','楊冠卿','宋','宋诗','song-poetry','','[]','志士長骯髒，曲鈎封公侯。',72,'全唐诗/poet.song.159000.json','["志士長骯髒，曲鈎封公侯。", "得喪亦何有，賢愚同一丘。", "日月如跳丸，少年今白頭。", "胡爲浪自苦，九折不停輈。", "龐眉碧眼禪，一笑萬事休。", "遼鶴我言歸，君其來與遊。"]'),
('135c5eb6-262d-4b8f-86fc-df4bb641f3c9','冬半山間忽見桃花客云江梅已芳且約一笑花下','楊冠卿','宋','宋诗','song-poetry','','[]','緣雲梯逕穿林麓，歲晚山寒風折木。',64,'全唐诗/poet.song.159000.json','["緣雲梯逕穿林麓，歲晚山寒風折木。", "司花爲我發春妍，繁紅幾樹驚愁目。", "有美人兮在空谷，似笑漫山總粗俗。", "淡煙疎雨羅浮村，萬里相將跨黄鵠。"]'),
('acbac0a1-6213-4ebe-a9bf-64be1b21005e','秋日麻姑山','楊冠卿','宋','宋诗','song-poetry','','[]','擲米作珠璣，麻姑已僊去。',72,'全唐诗/poet.song.159000.json','["擲米作珠璣，麻姑已僊去。", "滄海變桑田，乾坤自今古。", "我來訪靈蹤，日落青山暮。", "玉殿瑣清秋，霞裾隔煙霧。", "戶外黄冠師，三問三不顧。", "騎麟翳鳳凰，笑指虛無路。"]'),
('96d1fc4d-a60d-49ff-82ac-5364868ca10f','未至池陽五里有齊山寺寺後巖石巉然緣崖而上絕頂有翠微亭即杜樊川九日携壺地也自亭而西憩集仙洞','楊冠卿','宋','宋诗','song-poetry','','[]','泉石吾膏肓，佳處每忘返。',72,'全唐诗/poet.song.159000.json','["泉石吾膏肓，佳處每忘返。", "携壺上翠微，一雨秋政晚。", "千巖如獻狀，秀色疊層巘。", "緣雲梯逕入，危磴石偃蹇。", "洞戶訪真僊，丹成骨已換。", "羽化今幾年，鸞鵠若在眼。"]'),
('5b5fe447-1fed-4af0-9333-fbe9be1357c3','自馬當而上至壺口三鍾石蒼崖壁立下瞰層淵湍流急甚釣叟穴其傍往來自若吾恐其爲蜚僊也故作是詩','楊冠卿','宋','宋诗','song-poetry','','[]','千崖削蒼壁，萬仞臨深淵。',72,'全唐诗/poet.song.159000.json','["千崖削蒼壁，萬仞臨深淵。", "老翁立其傍，習慣若自然。", "笑歌驚波瀾，步武生雲煙。", "我欲從之遊，結茅山之巔。", "舉瓢酌天漿，醉拍洪崖肩。", "明月夜橫玉，共看凌波僊。"]'),
('0b3a3525-a95f-4549-a3be-165bb3082091','古有採鞠茱萸篇而無一語及淵明長房舊事鞠茱於此其亦有憾矣乎九日戲爲鞠茱補闕其體則準之簡文  其一','楊冠卿','宋','宋诗','song-poetry','','[]','落英拾秋鞠，委佩紉芳蘭。',60,'全唐诗/poet.song.159000.json','["落英拾秋鞠，委佩紉芳蘭。", "以其清且芬，可服仍可餐。", "吳茱味苦辛，奚亦登君盤。", "囊紗縈臂玉，恍記汝南山。", "黄鵠招不來，僊子何時還。"]'),
('68ccf751-c600-41c8-a859-60ad29756d4f','古有採鞠茱萸篇而無一語及淵明長房舊事鞠茱於此其亦有憾矣乎九日戲爲鞠茱補闕其體則準之簡文  其二','楊冠卿','宋','宋诗','song-poetry','','[]','紅塵著脚雙鬢斑，折腰五斗真作難。',48,'全唐诗/poet.song.159000.json','["紅塵著脚雙鬢斑，折腰五斗真作難。", "巾車一去不復還，歸卧柴桑紫翠間。", "東籬悠然見南山，欲辯忘言心自閑。"]'),
('d923f4e6-0220-4728-81ec-f09d1a5eadeb','又漁社李先生寵以和篇復用韻  其一','楊冠卿','宋','宋诗','song-poetry','','[]','南國有秋茱，芳馨襲椒蘭。',60,'全唐诗/poet.song.159000.json','["南國有秋茱，芳馨襲椒蘭。", "臞儒山澤間，晨霞却朝餐。", "置之紅錦囊，薦以黄金盤。", "瓶乳下青雲，一笑頹玉山。", "雞犬聽湛浮，遼鶴將自還。"]'),
('cf4a3cff-ebf4-4c92-bab9-ece3899d1fc4','又漁社李先生寵以和篇復用韻  其二','楊冠卿','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','西風寒巖鞠蘂斑，索米長安得路難。',48,'全唐诗/poet.song.159000.json','["西風寒巖鞠蘂斑，索米長安得路難。", "投林倦翼蚤知還，袖手歸來三徑間。", "雲屏萬疊匡廬山，鶴唳猿啼千古閑。"]'),
('2cb58362-a9a8-410c-80e6-566ed869a65a','三輔黄圖載趙飛燕太液池結裾遊宋公雞跖載飛燕太液池歸風送遠曲俱謂飛燕欲御風仙去雜用古語戲題於後  其一','楊冠卿','宋','宋诗','song-poetry','','[]','飲飛挾宸舟，彩鷁粲雲母。',88,'全唐诗/poet.song.159000.json','["飲飛挾宸舟，彩鷁粲雲母。", "波涵太液秋，影動靈鼉吼。", "觀雲棹水擷菱蕖，馮夷擊鼓羣龍趍。", "飄飄仙袂隨風舉，帝憐飛燕結纓裾。", "當時得意更深眷，承恩日在昭陽殿。", "茲遊奇絕冠平生，三十六宮俱健羨。"]'),
('805825c8-d36d-435c-81ab-d9457830cf7c','三輔黄圖載趙飛燕太液池結裾遊宋公雞跖載飛燕太液池歸風送遠曲俱謂飛燕欲御風仙去雜用古語戲題於後  其二','楊冠卿','宋','宋诗','song-poetry','','[]','瑶池翠水波粼粼，日暮寒生碧草春。',64,'全唐诗/poet.song.159000.json','["瑶池翠水波粼粼，日暮寒生碧草春。", "阿嬌厭貯黄金屋，來歌送遠歸風曲。", "仙乎去故而就新，歌聲嘹亮遏行雲。", "黄鵠一去無消息，人間有情淚沾臆。"]'),
('04fc77a6-3405-452f-ab55-a841a621210a','秋夜吟','楊冠卿','宋','宋诗','song-poetry','','[]','銅壺漏澀秋宵永，翠梧葉落敲金井。',64,'全唐诗/poet.song.159000.json','["銅壺漏澀秋宵永，翠梧葉落敲金井。", "錦帳香消枕玉寒，驚迴昨夢難重省。", "起來刁斗連營靜，碧雲飛下征鴻影。", "蠻牋誰遣寄相思，鏁窗笑剪并刀冷。"]'),
('77b2c9fa-d767-4814-8c1d-0c534ea2f00a','秋琴詠','楊冠卿','宋','宋诗','song-poetry','','[]','巖花月彩浮，井桐露珠滴。',60,'全唐诗/poet.song.159000.json','["巖花月彩浮，井桐露珠滴。", "悲秋適有念，擁琴坐西壁。", "古音拂朱弦，一倡千慮滌。", "無雲山雨飛，松風寒淅瀝。", "魚龍盡出聽，萬籟天地寂。"]'),
('b0df3ff0-304c-4652-9606-99392a23ad41','秋夜對酒用前韻','楊冠卿','宋','宋诗','song-poetry','','[]','夜雨急復疎，簷溜秋聲滴。',60,'全唐诗/poet.song.159000.json','["夜雨急復疎，簷溜秋聲滴。", "虛堂夢乍驚，青燈餘四壁。", "牢愁推不去，濁酒詎能滌。", "蒲萄出西凉，瓶耻無餘瀝。", "兀坐倚枯木，棲心寄禪寂。"]'),
('ecb895c8-78ff-47b8-a444-ef03163dec12','採芙蓉詞','楊冠卿','宋','宋诗','song-poetry','','[]','采采芙蓉華，集之以爲裳。',48,'全唐诗/poet.song.159000.json','["采采芙蓉華，集之以爲裳。", "自彼若耶谿，登于君子堂。", "馨香壓紉蘭，把玩卑瓊芳。", "佩服古無斁，懷人思沅湘。"]'),
('09450f86-2192-485b-9e22-6b6842f71797','商婦吟','楊冠卿','宋','宋诗','song-poetry','','[]','妾本良家子，嫁作商人婦。',120,'全唐诗/poet.song.159000.json','["妾本良家子，嫁作商人婦。", "蕩子去不歸，幽閨長獨守。", "平生松栢心，歲晚柯葉茂。", "飄絮亂因風，肯若道傍柳。", "朝來尋姪娣，典衣換春酒。", "郵籤訪水程，去問夫健否。", "白面誰家郎，下馬清谿口。", "却立不肯前，邀妾相先後。", "寧知天壤間，貴賤從其偶。", "妾身雖同塗，妾心終不負。"]'),
('9e53bb61-e4e2-46ae-9d31-a67e43f2a666','少年樂用李賀韻','楊冠卿','宋','宋诗','song-poetry','','[]','青雲年少歡娛地，脆弦繁筦東風裏。',64,'全唐诗/poet.song.159000.json','["青雲年少歡娛地，脆弦繁筦東風裏。", "金狨醉倚玉驄驕，歸去畫橋臨綠水。", "釵梁斜嚲雲鬟墜，錦帳美人初睡起。", "促上紅茵翻舞袂，春愁不展眉峰翠。"]'),
('c6da2b9a-c541-4e5f-9c8b-0986412a4ff3','美人在空谷','楊冠卿','宋','宋诗','song-poetry','','[]','有美人兮在空谷，肌膚冰雪顔如玉。',96,'全唐诗/poet.song.159000.json','["有美人兮在空谷，肌膚冰雪顔如玉。", "珠袖輕綃卷翠雲，日暮天寒倚修竹。", "自言久住黄金屋，舞遍霓裳羽衣曲。", "昭陽春盡音信稀，傷心暗蹙眉峰綠。", "百年日月雙車轂，富貴榮華如轉燭。", "蓬海迢迢天六六，馭風歸去騎黄鵠。"]'),
('039aa926-2951-4cb4-9a40-d233eb5fa723','山阿步月吟','楊冠卿','宋','宋诗','song-poetry','','[]','遊子莫何之，攬衣出京華。',96,'全唐诗/poet.song.159000.json','["遊子莫何之，攬衣出京華。", "松舟逐桂檝，渺然下驚波。", "夜久羣動息，明星耿斜河。", "維舟亂石間，步月前山阿。", "霞佩凌空僊，瑶章方詠歌。", "見我若舊識，問訊今如何。", "我欲從之遊，長嘯入雲蘿。", "可仰不可攀，高峰鬰嵯峨。"]'),
('03d9b06f-6063-457c-9dd2-842381d7404e','久雨新霽蚤過松竹道院復以雨歸因用汪彥章一春略無十日晴之句','楊冠卿','宋','宋诗','song-poetry','','[]','一春略無十日晴，竈前濈濈蛙黽生。',64,'全唐诗/poet.song.159000.json','["一春略無十日晴，竈前濈濈蛙黽生。", "晨興登視雲霽平，攬衣出門聊意行。", "東風吹拂酒面醒，花光掠我雙眼明。", "舉頭還聽鳩婦鳴，歸來有酒愁獨傾。"]'),
('b664f36d-723e-4b1d-ac20-6ffd7355fd8c','翌日晴霽復用韻述所見','楊冠卿','宋','宋诗','song-poetry','','[]','癡雲挾雨雨不晴，門外野田春水生。',64,'全唐诗/poet.song.159000.json','["癡雲挾雨雨不晴，門外野田春水生。", "登臨一望莽然平，滄波十里舟可行。", "農人枵腹愁弗醒，今朝喜見天日明。", "前村相去幾牛鳴，試問誰家廩粟傾。"]'),
('87a4df2d-d244-4e56-a0dd-ac3eebb35f44','趙仲實如吳江扁舟來別因以送之','楊冠卿','宋','宋诗','song-poetry','','[]','少年結交翰墨場，舉頭不覺雙鬢蒼。',64,'全唐诗/poet.song.159000.json','["少年結交翰墨場，舉頭不覺雙鬢蒼。", "世塗巇嶮如羊腸，交情耐久無炎凉。", "我今讀書松竹莊，君兮去去吳松江。", "音書莫惜頻寄將，新詩分我古錦囊。"]'),
('fb10fac5-c461-482b-8c6a-8a4a8307a87d','九月二十一夜夢至亂山叢石間出憩道傍拂石坐古榕下仰視木杪蘿蔓凌空興欲蜚舉既覺哦成古篇','楊冠卿','宋','宋诗','song-poetry','','[]','古榕夾道周，老榦參天碧。',84,'全唐诗/poet.song.159000.json','["古榕夾道周，老榦參天碧。", "溜雨四十圍，下視庭前栢。", "垂根相勾聯，敷蔭接南國。", "凌寒不改柯，閲人如過客。", "山空秋月明，路遠車塵寂。", "清遊記昨夢，危坐倚孤石。", "矯首睇雲蘿，雙鳬生羽翼。"]'),
('e15ddb2c-4d60-49ac-83ad-453ab0d9f40b','秦侯不調累年識者嘆息茲以規恢祕略親簡上知有詔復其官亨衢自此發軔聞之喜甚爲作古篇','楊冠卿','宋','宋诗','song-poetry','','[]','天驕飽肉氣勇决，憶昨彎弧射漢月。',288,'全唐诗/poet.song.159000.json','["天驕飽肉氣勇决，憶昨彎弧射漢月。", "玉關保障烽燧驚，豺狼塞路人蹤絕。", "將軍方著從事衫，指揮義士征河南。", "設奇間道依嵩谷，百戰崎嶇不解驂。", "攻城陷陣收殊績，捷書夜到甘泉北。", "天子興嗟恨見晚，俾將樓船護江國。", "將軍擊檝誓中流，英風凜凜氣橫秋。", "胡爲拘縶不得逞，歸戴南冠效楚囚。", "一朝奮激肝膽露，剌剌羞聞婢子語。", "袖携文字幾千言，徑趍閶闔排雲去。", "帝敕天丁下取將，玉音誦之聲琅琅。", "侍臣却立屏東箱，奇謀創見驚未嘗。", "明日北門天子詔，似怪十年猶不調。", "盡還故秩問所從，豪傑中原資號召。", "我今塵敝黑貂裘，藥裹關心萬事休。", "挑燈看劍夜無寐，耿耿猶懷嫠婦憂。", "相期談笑青油幕，關河去展規恢略。", "燕然碣石與天齊，爲君重勒千丈碑。"]'),
('4a53b647-60da-4cb1-957e-1403f48f6902','秋日自武林病歸漁社李使君惠以長篇誦之再四沈疴脫然','楊冠卿','宋','宋诗','song-poetry','','[]','憶昨走京華，炎曦晝方赫。',156,'全唐诗/poet.song.159000.json','["憶昨走京華，炎曦晝方赫。", "終日無一欣，夢遶舊泉石。", "西風趁驚波，茲焉掛帆席。", "千年遼鶴歸，客屨戶外積。", "雕胡飯新炊，雲腴飲甘液。", "杞狗雜苓龜，夜吠更晨吸。", "榮華風中煙，得喪付兒劇。", "寧復效轅駒，長鳴悲伏櫪。", "李侯金閨彥，氣與嵩華敵。", "龍門世莫攀，冰鑒古無匹。", "駃騠千里駿，晨炊共蓐食。", "高吟動鬼神，落筆風雨疾。", "句誦血模糊，妙理難致詰。"]'),
('73cbc6a8-564d-4df3-a8fc-8f877e7754a7','古意','楊冠卿','宋','宋诗','song-poetry','','[]','渥漥天馬倈，虎脊而龍膺。',120,'全唐诗/poet.song.159000.json','["渥漥天馬倈，虎脊而龍膺。", "追電籋浮雲，滅沒如流星。", "絡以黄金鞿，閑之白玉京。", "王良驂帝御，望舒引前旌。", "朝踏交河冰，暮清瀚海塵。", "歸憇華山陽，談笑靜甲兵。", "胡爲芻豆拘，下與駑駘并。", "羊腸困九折，鹽車縶長纓。", "懸金方市駿，引脰聊一鳴。", "伯樂肯回顧，價其十倍增。"]'),
('667d4689-c0ed-46b6-ba7c-61acad43d914','天孫徠','楊冠卿','宋','宋诗','song-poetry','','[]','珠宮貝闕天女孫，膠轕璇璣緯星辰。',48,'全唐诗/poet.song.159000.json','["珠宮貝闕天女孫，膠轕璇璣緯星辰。", "徠遊河漢儷於神，神儲崧嶽生甫申。", "胸中文字覷天巧，黼黻帝躬臨下民。"]'),
('0ddf9b42-8152-46a2-bd92-d4f33921d213','平郴蠻','楊冠卿','宋','宋诗','song-poetry','','[]','孽狐鼪鬼嘯篁竹，紅綃帕首郴江曲。',96,'全唐诗/poet.song.159000.json','["孽狐鼪鬼嘯篁竹，紅綃帕首郴江曲。", "萬牛臠炙甕行酒，黨伍穰穰萃林藪。", "牙璋夜半起兵符，雲旗驛騎爭馳驅。", "搜原剔藪殲渠魁，巢顛子覆苕葦枯。", "虎臣獻凱錫珪組，玉帛金錢充棟宇。", "追蹤漢相不言功，山河带礪傳無窮。"]'),
('773d2923-d565-4ef2-af1a-01adbef67452','祀明堂','楊冠卿','宋','宋诗','song-poetry','','[]','總章備物嚴秋饗，尊祖合祠規汶上。',64,'全唐诗/poet.song.159000.json','["總章備物嚴秋饗，尊祖合祠規汶上。", "宰臣恭肅相明禋，精意潛交通肸蠁。", "殊庭朝薦燎煙升，陰雲剝落天日明。", "百神駿奔風馬下，休嘉協應年穀成。"]'),
('b03f4241-a5a8-4217-89fe-a99aca414fae','除關征','楊冠卿','宋','宋诗','song-poetry','','[]','翠華憶昨臨吳津，駕言直欲蘇遠民。',64,'全唐诗/poet.song.159000.json','["翠華憶昨臨吳津，駕言直欲蘇遠民。", "三尺土階茅不剪，舜循堯道慈而儉。", "姬公制國有常經，什一更除關市征。", "男畊女織餘布粟，却笑二吾猶不足。"]'),
('9a7ca0dc-a5d3-4f42-8973-02ba30b4bb83','天孫吟','楊冠卿','宋','宋诗','song-poetry','','[]','天孫黼黻文，膠轕璇璣外。',60,'全唐诗/poet.song.159000.json','["天孫黼黻文，膠轕璇璣外。", "大巧本無爲，女工卑組繪。", "胡爲小兒女，纓弁雜環珮。", "庭羅餰餌香，設祠祈且拜。", "臨池五綵絲，更結相連愛。"]'),
('6725112d-999d-45cf-88fb-c8f177f9709f','仙遊','楊冠卿','宋','宋诗','song-poetry','','[]','迢迢秋夜長，娟娟霜月明。',204,'全唐诗/poet.song.159000.json','["迢迢秋夜長，娟娟霜月明。", "隠几觀萬變，頫仰周八紘。", "人間厭謫墮，翳鳳騎長鯨。", "寥天排雲征，高步撫流星。", "羣僊羅道周，有若相逢迎。", "旌羽絢虹蜺，環珮鏘葱珩。", "問我來何遲，携手上玉京。", "陛級扣靈瑣，班聯簉紫庭。", "綠章奏封事，清問殊哀矜。", "飲之以雲腴，錫之以瓊英。", "下拜亟登受，倏然雲霧興。", "杳不知其所，變化無留形。", "俄頃雙青鸞，銜牋報歸程。", "望舒肅前驅，徒御了不驚。", "歸時夜未央，仰視河漢橫。", "天風西南來，隠隠笙竽聲。", "鈞天認帝所，昨夢愴難成。"]'),
('b0003569-013b-46ce-b8c1-4ab5b99eeb56','從李使君假記室吏','楊冠卿','宋','宋诗','song-poetry','','[]','阿㜷嘔心兒，佩囊有奚奴。',96,'全唐诗/poet.song.159000.json','["阿㜷嘔心兒，佩囊有奚奴。", "杜陵短褐翁，抄詩聽小胥。", "我生味風雅，古人思與俱。", "家無儋石儲，誰其供指呼。", "主翁居專城，鴈鶩紛庭除。", "記史飽餘閑，願言假一夫。", "授以烏絲欄，副之玉蟾蜍。", "晴窗掃桐葉，細字蠅頭書。"]'),
('218aecbe-6282-4415-aae0-71817c339de2','倚梧歎','楊冠卿','宋','宋诗','song-poetry','','[]','白首寄人間，萍泛無休日。',48,'全唐诗/poet.song.159000.json','["白首寄人間，萍泛無休日。", "撐腸五千卷，豈乏濟時術。", "富貴不可期，惆悵難再述。", "日暮倚庭梧，寒風聽蕭瑟。"]'),
('de7d1a5c-b459-4c5d-b682-8893d1a57897','懷古','楊冠卿','宋','宋诗','song-poetry','','[]','干將補弊履，鉛刀割全牛。',48,'全唐诗/poet.song.159000.json','["干將補弊履，鉛刀割全牛。", "千金市駿骨，鼓車役驊騮。", "薛燭已云遠，伯樂不可求。", "此理難致詰，吾其賦歸休。"]'),
('dbeb18b5-cf05-43e3-bbb2-2a4d45b32149','冬十月百卉盡芳','楊冠卿','宋','宋诗','song-poetry','','[]','淳熙戊戌冬十月，恰似東風三月時。',64,'全唐诗/poet.song.159000.json','["淳熙戊戌冬十月，恰似東風三月時。", "冰霜不變沍寒色，溪壑次第回春姿。", "花情柳意已無耐，紅英粉艷爭紛披。", "道傍牛喘不復問，欲了公事真癡兒。"]'),
('b2289db3-f3c8-400a-847f-d08912dbbdcc','麻姑山東涉千堆壠至射亭宿黄氏新館','楊冠卿','宋','宋诗','song-poetry','','[]','姑山鏁靈壇，千阜如堆玉。',48,'全唐诗/poet.song.159000.json','["姑山鏁靈壇，千阜如堆玉。", "山回路轉間，射亭見新築。", "主人雅好事，借我南窗宿。", "一夢到無何，夢覺黄粱熟。"]'),
('17c6b0af-c526-430f-b02b-381ebd342a7b','別鄭大用于潯陽','楊冠卿','宋','宋诗','song-poetry','','[]','子真千載士，流風凜然存。',112,'全唐诗/poet.song.159000.json','["子真千載士，流風凜然存。", "襟期輩古人，喜見雲礽孫。", "客裏青燈連夜語，痛飲忘形到爾汝。", "掀髯一笑倚胡床，浩歌赤壁凌雲句。", "楓葉荻花秋，送客令人愁。", "挽君君不留，今日具扁舟。", "我欠蓋頭茅一把，何時去結雞豚社。", "澤畔行吟醉復醒，共看屬玉雙飛下。"]'),
('92401a15-993d-4ee7-ac47-8d2453b5543d','辛丑殘臘前一日扁舟東歸阻風馬當乞靈祠下','楊冠卿','宋','宋诗','song-poetry','','[]','維舟桑落洲，十日風和雨。',132,'全唐诗/poet.song.159000.json','["維舟桑落洲，十日風和雨。", "雨餘江波平，山橫眉黛嫵。", "急呼黄帽郎，來扣靈真宇。", "椒桂薦芳馨，魚龍忽掀舞。", "巨浪拍天浮，萬疊震鼉鼓。", "淮洲十里間，蜚檝不可渡。", "三老前跪陳，珍貝非神予。", "願言點歸裝，勿爲神所怒。", "我生窶且貧，窮塗一羈旅。", "照乘乏明珠，落霞有佳句。", "稽首謝龍君，放我扁舟去。"]'),
('409cb14d-efa9-49ad-994a-546df2fda5b9','壬寅夏五月將治嚴陵之裝欲用李長吉故事買奚奴負詩囊以歸呈谷隠趙使君','楊冠卿','宋','宋诗','song-poetry','','[]','少年學書劍，矯首睨八荒。',60,'全唐诗/poet.song.159000.json','["少年學書劍，矯首睨八荒。", "閶闔記昔遊，霞佩高頡頏。", "一跌下青雲，意氣久不揚。", "乞取平頭奴，提携古錦囊。", "歸釣富春瀨，濯纓歌滄浪。"]'),
('5cdbbad4-2423-4c22-9a3f-14ab5b9fa397','壬寅仲冬晦日同吳監丞游延祥宮延祥蓋和靖所居也','楊冠卿','宋','宋诗','song-poetry','','[]','霜日炫晴晝，湖光掠眼明。',216,'全唐诗/poet.song.159000.json','["霜日炫晴晝，湖光掠眼明。", "散策事幽討，出門聊意行。", "柳塘和靖居，宮殿若化成。", "霞裾赤城仙，笑語相逢迎。", "雲腴飲甘液，琅函披內經。", "趺坐縱名談，妙處俱忘形。", "須臾啟靈鏁，臺沼列萬楹。", "逕路通深杳，宮花不知名。", "石泉鳴佩環，松篁奏竽笙。", "髣髴如鈞天，音韻鏗韺䪫。", "吾皇香案臣，筆力雕陽春。", "危亭倚高寒，意氣干青雲。", "飲酣視八極，神馳白玉京。", "日月看跳丸，羲輪忽西傾。", "歸來十里塘，問訊江梅英。", "斷橋流水香，一枝疎影橫。", "煙淡月昏黄，清於玉壺冰。", "錦囊搜好句，山阿紀前盟。"]'),
('eb98266c-d1e6-4ff2-bc06-1d5f92c37c19','填維揚','楊冠卿','宋','宋诗','song-poetry','','[]','古人肉食無遠謀，腰錢騎鶴向揚州。',96,'全唐诗/poet.song.159000.json','["古人肉食無遠謀，腰錢騎鶴向揚州。", "春風十里珠簾捲，但看竹西歌吹樓。", "天朝選用詩書帥，上策公言須自治。", "屏翰堅持保障功，江淮益壯金湯勢。", "强敵不敢縱南牧，關塞煙迷芳草綠。", "兒童歌舞樂昇平，一曲梅花細柳營。"]'),
('110e834d-bb4b-4891-95cf-e26a51c41d0d','都作院','楊冠卿','宋','宋诗','song-poetry','','[]','天子除戎戒不虞，修車備器會東都。',64,'全唐诗/poet.song.159000.json','["天子除戎戒不虞，修車備器會東都。", "羽林憶昨厭弓矢，剡木弦弧兒戲爾。", "我公號令何精明，武庫森嚴耀五兵。", "威震天驕奠京邑，繇漢以來真鮮及。"]'),
('c1242cee-81d5-4631-b118-8abe2817dff6','春大閲','楊冠卿','宋','宋诗','song-poetry','','[]','波澄青海無傳箭，我公獻納紆皇眷。',96,'全唐诗/poet.song.159000.json','["波澄青海無傳箭，我公獻納紆皇眷。", "修嚴武備選車徒，天下雖安不忘戰。", "車如流水馬如龍，甲耀日兮旌蔽空。", "攙槍熒惑不敢動，獨任朔方無限功。", "天威震疊軍聲壯，會見龍庭焚老上。", "燕然碣石與天齊，爲公重勒千丈碑。"]'),
('54f4c491-89c9-47c4-87fa-27ce00bdb8c5','御書東坡雪詩石刻','楊冠卿','宋','宋诗','song-poetry','','[]','殘更皎月垂半破，西鄰促席寒威挫。',96,'全唐诗/poet.song.159000.json','["殘更皎月垂半破，西鄰促席寒威挫。", "風流玉局老坡仙，雪夜清吟躡郊賀。", "流落人間古錦囊，帝恐天丁下取將。", "賡歌餘暇染宸翰，奎壁昭回龍鳳翔。", "我公稽首拜嘉惠，勒以堅珉貽萬世。", "捲旗擬入蔡州城，傳呼夜示吳元濟。"]'),
('ea50e493-513f-4a62-b571-f7e07055577f','謝人惠油炭  其一','楊冠卿','宋','宋诗','song-poetry','','[]','青藜照天祿，寶炬分金蓮。',60,'全唐诗/poet.song.159000.json','["青藜照天祿，寶炬分金蓮。", "榮遇不可期，膏火徒自煎。", "檠短無餘輝，囊空無留錢。", "一燈假鄰壁，三冬廢塵編。", "殘膏許沾丐，繼晷欣窮年。"]'),
('b95d576d-1407-485c-9cac-19a4fba7bfd9','謝人惠油炭  其二','楊冠卿','宋','宋诗','song-poetry','','[]','陰崖冷徹骨，榾柮殘無煙。',60,'全唐诗/poet.song.159000.json','["陰崖冷徹骨，榾柮殘無煙。", "號寒冰氏子，炙背思負暄。", "主君惠窮塗，施予無所偏。", "爐分天地春，力奪造化權。", "和氣與俱游，死灰欣復然。"]'),
('89907bfd-a1cd-452b-be97-37740a83f2bd','楚有𮑉菜色潔而味辛夜對吳監丞飲飲酣薦之以此恍然如在湖湘間','楊冠卿','宋','宋诗','song-poetry','','[]','山澤有臞儒，骨相無食肉。',120,'全唐诗/poet.song.159000.json','["山澤有臞儒，骨相無食肉。", "平生藜莧腸，愧負詩書腹。", "碧澗掇香芹，雕盤堆苜蓿。", "艱苦謀一飽，未免窮途哭。", "君今食萬錢，肥甘非不足。", "味厭五侯鯖，嘉蔬列瓊玉。", "云自楚中來，芳辛有餘馥。", "一笑下筯空，鯨飲薦醽醁。", "吟餘詩思清，如行湘水曲。", "湘君不復見，直欲跨黄鵠。"]'),
('dcf5e214-c7ac-47f6-8ffd-bcc43dc65675','甲辰季冬殘臘大雪主人以糟玉面貍及尊酒爲餉','楊冠卿','宋','宋诗','song-poetry','','[]','南山白額虎，暴戾日以滋。',132,'全唐诗/poet.song.159000.json','["南山白額虎，暴戾日以滋。", "納諸罟擭中，食肉寢其皮。", "文貍外柔順，玉面而豐肌。", "與世了無忤，奚亦遭危機。", "得非風味殊，尊俎之所宜。", "焚山獵獸者，是以羅致之。", "主翁厭肥甘，鼎食嗤羣兒。", "殷勤築糟丘，遣送持酒巵。", "于時臘將殘，雪花一尺圍。", "玉樓寒起粟，墨突晨未炊。", "得酒且大嚼，勿令兒輩知。"]'),
('c2545660-52a0-4309-961e-85d691a8fcc0','唐劉雲有所思云玉井蒼苔古院深桐花落地無人掃因用其語集古句次韻','楊冠卿','宋','宋诗','song-poetry','','[]','西征登隴首，薄暮有所思。',56,'全唐诗/poet.song.159000.json','["西征登隴首，薄暮有所思。", "所思鬰不見，殘雲傍馬飛。", "逢迎少壯非吾道，百壺且試開懷抱。", "黄帽青鞋歸去來，桐花落地無人掃。"]'),
('64c50618-a65b-4218-aa9e-e5c3ef719f29','謝石佛璉大禪','楊冠卿','宋','宋诗','song-poetry','','[]','人生天地間，百年如逆旅。',108,'全唐诗/poet.song.159000.json','["人生天地間，百年如逆旅。", "榮華風中煙，富貴草頭露。", "得喪能幾何，頫仰即今古。", "師具正法眼，與人一線路。", "紛紛輕薄兒，誰解點頭句。", "冥行方索塗，空滿戶外屨。", "我提沒底籃，採藥空山去。", "覿面偶相逢，舉手便分付。", "彈指了三生，無去亦無住。"]'),
('595b565a-f2f7-4e4e-bce2-76e0229cea2b','寄遠曲用唐人張籍韻','楊冠卿','宋','宋诗','song-poetry','','[]','江南淡蕩煙波煖，蒲萄淥漲春江滿。',48,'全唐诗/poet.song.159000.json','["江南淡蕩煙波煖，蒲萄淥漲春江滿。", "日暮汀洲採白蘋，芹芽出水蘭心短。", "美人去矣隔湘江，誰其贈我明月璫。"]'),
('e5bbafe1-94b9-4159-b4b9-2dd0826bdce8','癸丑仲冬十日蚤晴從中使過蓴湖未幾風雪交作','楊冠卿','宋','宋诗','song-poetry','','[]','黄岡之北蓴湖東，湖光萬頃磨青銅。',64,'全唐诗/poet.song.159000.json','["黄岡之北蓴湖東，湖光萬頃磨青銅。", "樓船東下佽飛集，牙檣十里旌旗紅。", "魚龍震疊馮夷宮，雲容倏忽變晴空。", "鬖髿振袂玉妃舞，雪花撩亂穿疎篷。"]'),
('aced7f02-6037-437c-999e-a15221feca95','泊舟富池乞靈祠下','楊冠卿','宋','宋诗','song-poetry','','[]','大江東南來，馮夷此其宮。',120,'全唐诗/poet.song.159000.json','["大江東南來，馮夷此其宮。", "羣山各獻狀，奔走如游龍。", "將軍萬人傑，智勇摧姦凶。", "草木知威名，旗常紀豐功。", "廟食填茲土，樓閣何穹窿。", "我來拜靈祠，紅日方曈矓。", "神烏集飛檣，雪波捲晴空。", "椒桂薦芳馨，精誠冀感通。", "謂言身半百，扁舟吾欲東。", "羞作賈胡留，願借一帆風。"]'),
('56058278-3960-498a-80e6-71d30fd94998','題郭季寬曉耕宿釣二圖  其一','楊冠卿','宋','宋诗','song-poetry','','[]','牛角橫素書，春犁破朝雨。',24,'全唐诗/poet.song.159000.json','["牛角橫素書，春犁破朝雨。", "鴻鵠志安知，功名心自許。"]'),
('32431fec-a07d-4f87-9e31-e86a3add6cac','題郭季寬曉耕宿釣二圖  其二','楊冠卿','宋','宋诗','song-poetry','','[]','羊裘晦山澤，貂蟬等鴻毛。',24,'全唐诗/poet.song.159000.json','["羊裘晦山澤，貂蟬等鴻毛。", "直鈎道可行，一釣聯六鰲。"]'),
('6f2e3640-4d28-49a8-8628-fd61284870c6','栖霞高士以詩鳴於時方幸締交而赴玉隆之請鶴馭西去挽之不留臨岐告別爲賦二詩  其一','楊冠卿','宋','宋诗','song-poetry','','[]','大雅久不作，正音寂無聞。',72,'全唐诗/poet.song.159000.json','["大雅久不作，正音寂無聞。", "金門栖霞仙，派續修水濆。", "學海障鯨波，筆力杠龍文。", "我誦錦囊句，十年思見君。", "相逢一杯酒，和氣蒸春雲。", "去我鼻端堊，君其揮郢斤。"]'),
('dab4a748-f32d-4455-9277-defeb9c86555','栖霞高士以詩鳴於時方幸締交而赴玉隆之請鶴馭西去挽之不留臨岐告別爲賦二詩  其二','楊冠卿','宋','宋诗','song-poetry','','[]','蛟窟蕩羣妖，霞帷快飛舉。',72,'全唐诗/poet.song.159000.json','["蛟窟蕩羣妖，霞帷快飛舉。", "橫江餘鐵鎖，中流屹砥柱。", "主人謫仙人，道學侔千古。", "紫皇香案前，掉頭不肯住。", "亭懸孺子榻，簾捲西山雨。", "鷄犬許同昇，我欲騎鯨去。"]'),
('99bf9f13-a3d4-4dfc-96e4-cf6b42a880a8','公無渡河','楊冠卿','宋','宋诗','song-poetry','','[]','河流决崑崙，微禹其爲魚。',123,'全唐诗/poet.song.159000.json','["河流决崑崙，微禹其爲魚。", "龍門雖已鑿，犀栧孰可踰。", "老翁被髮鬢如絲，臨流欲渡將何之。", "嫗止翁留翁勿渡，翁不嫗從捨之去。", "中流憑一壺，意謂千金俱。", "一壺勢莫支，千金淪其軀。", "壺兮壺兮翁之{崇|匕/具/夋厶去掉}，鼉吼鯨吞方得意。", "曲終哀怨寫箜篌，鄰女爲君雙墮淚。"]'),
('3807d7fc-106a-455b-a57d-1a7c85165f37','以浯溪磨崖頌爲友人壽','楊冠卿','宋','宋诗','song-poetry','','[]','明皇蠹妖孽，顛倒由祿兒。',168,'全唐诗/poet.song.159000.json','["明皇蠹妖孽，顛倒由祿兒。", "真人奮靈武，羣公任安危。", "笑談收兩京，鑾輅還京師。", "廟社喜重安，鐘簴曾不移。", "詞臣有元結，歌頌鎸浯溪。", "余生千載後，每恨不同時。", "半世看墨本，長哦山谷詩。", "鳴劍馳伊吾，有策噤未施。", "十年客衛府，斗粟不療饑。", "君今聯上閤，婉畫贊籌帷。", "眷簡隆三宮，復始可指期。", "持以爲君壽，勳名書鼎彝。", "明年奉漢觴，重修前殿儀。", "摩挲古崖石，更紀中興碑。"]'),
('e70a104e-d872-4980-8868-f2088688bdd5','崧高詩爲九江趙使君壽  其一','楊冠卿','宋','宋诗','song-poetry','','[]','崧高維嶽，四方之極。',20,'全唐诗/poet.song.159000.json','["崧高維嶽，四方之極。", "維嶽降神，生此王國。"]'),
('67e75298-a2f7-4524-8bbb-b1666d192095','崧高詩爲九江趙使君壽  其二','楊冠卿','宋','宋诗','song-poetry','','[]','綿綿瓜瓞，莫莫葛藟。',20,'全唐诗/poet.song.159000.json','["綿綿瓜瓞，莫莫葛藟。", "周公之孫，齊侯之子。"]'),
('c4e0b73d-9394-4ea6-8906-bb9085c0bedc','崧高詩爲九江趙使君壽  其三','楊冠卿','宋','宋诗','song-poetry','','[]','柔惠且直，小心翼翼。',20,'全唐诗/poet.song.159000.json','["柔惠且直，小心翼翼。", "王親命之，南國是式。"]'),
('f055d98a-4c85-4867-84d5-0314b4fa95c5','崧高詩爲九江趙使君壽  其四','楊冠卿','宋','宋诗','song-poetry','','[]','盡瘁以仕，不懈于位。',20,'全唐诗/poet.song.159000.json','["盡瘁以仕，不懈于位。", "四方于宣，南國之紀。"]'),
('8a1cb391-5ae7-4880-8ec5-fc846f58cd19','崧高詩爲九江趙使君壽  其五','楊冠卿','宋','宋诗','song-poetry','','[]','之綱之紀，允文允武。',20,'全唐诗/poet.song.159000.json','["之綱之紀，允文允武。", "荆舒是懲，四方無侮。"]'),
('471648b1-af11-43e0-9fce-b033ee69c64f','崧高詩爲九江趙使君壽  其六','楊冠卿','宋','宋诗','song-poetry','','[]','旱既太甚，以祈甘雨。',20,'全唐诗/poet.song.159000.json','["旱既太甚，以祈甘雨。", "零雨其濛，介我稷黍。"]'),
('6bd05525-27be-4cd0-81c0-32dc83411d6d','崧高詩爲九江趙使君壽  其七','楊冠卿','宋','宋诗','song-poetry','','[]','黍稷彧彧，去其螟螣。',20,'全唐诗/poet.song.159000.json','["黍稷彧彧，去其螟螣。", "實維豐年，我庾維億。"]'),
('c22d47db-17f5-471b-a637-d005065a40cb','崧高詩爲九江趙使君壽  其八','楊冠卿','宋','宋诗','song-poetry','','[]','萬億及秭，物其旨矣。',20,'全唐诗/poet.song.159000.json','["萬億及秭，物其旨矣。", "此邦之人，云胡不喜。"]'),
('972585a2-d7c6-4e5d-885f-fc48e6cc29ce','崧高詩爲九江趙使君壽  其九','楊冠卿','宋','宋诗','song-poetry','','[]','周邦咸喜，式歌且舞。',20,'全唐诗/poet.song.159000.json','["周邦咸喜，式歌且舞。", "于時語語，厥聲載路。"]'),
('276e6ebc-e4c7-4633-8f22-07e6138b8687','崧高詩爲九江趙使君壽  其一○','楊冠卿','宋','宋诗','song-poetry','','[]','其告維何，自今以始。',20,'全唐诗/poet.song.159000.json','["其告維何，自今以始。", "俾熾而昌，既多受祉。"]'),
('f0c993b5-d42e-49f9-965b-4b49bb847fcc','崧高詩爲九江趙使君壽  其一一','楊冠卿','宋','宋诗','song-poetry','','[]','永錫難老，眉壽保魯。',20,'全唐诗/poet.song.159000.json','["永錫難老，眉壽保魯。", "以佐天子，爲周室輔。"]'),
('9125ba77-460c-4819-a740-d99c41a8b26f','崧高詩爲九江趙使君壽  其一二','楊冠卿','宋','宋诗','song-poetry','','[]','我來自東，小大稽首。',20,'全唐诗/poet.song.159000.json','["我來自東，小大稽首。", "是用作歌，以介眉壽。"]'),
('df2a5ebe-8e24-458f-a745-95420587dc19','庭草','楊冠卿','宋','宋诗','song-poetry','','[]','庭草凄餘碧，江風吹早寒。',48,'全唐诗/poet.song.159000.json','["庭草凄餘碧，江風吹早寒。", "带圍愁裏減，詩律病中寬。", "隠几閑留客，迎門懶不冠。", "蕭然有真處，未易俗人看。"]'),
('a61c6b08-ae72-4050-ba0d-d7a058ab5df5','別襄陽帥','楊冠卿','宋','宋诗','song-poetry','','[]','淮海棠陰已著行，却移小隊入襄陽。',64,'全唐诗/poet.song.159000.json','["淮海棠陰已著行，却移小隊入襄陽。", "江山尚带戎馬氣，齋閤遽聞編簡香。", "自昔聲名滿梁楚，向來爲政壓龔黄。", "風流高出山翁上，不用擎鞭問葛彊。"]'),
('f8710f8d-cd19-403c-9900-2267a41deb25','宿前崗鋪','楊冠卿','宋','宋诗','song-poetry','','[]','老去心猶壯，天邊歲欲除。',48,'全唐诗/poet.song.159000.json','["老去心猶壯，天邊歲欲除。", "喜行新過路，如讀未看書。", "溪水縈回浄，人家遠近居。", "梅花正愁絕，薄暮雨疎疎。"]'),
('f5b4f7e5-d180-4e29-afcf-c307393c36e7','暮雨','楊冠卿','宋','宋诗','song-poetry','','[]','飄飄爲客久，在在與春期。',48,'全唐诗/poet.song.159000.json','["飄飄爲客久，在在與春期。", "暮雨森寒意，花香閟舊枝。", "看成南國老，慚誦北山移。", "已悞世緣惡，懷哉歸去遲。"]'),
('bcd0b1f7-dfb9-4a6a-ae4f-62ef5d5dcb2d','無題','楊冠卿','宋','宋诗','song-poetry','','[]','鶑語丁寧隔曉窗，露翻紅藥鬭新粧。',32,'全唐诗/poet.song.159000.json','["鶑語丁寧隔曉窗，露翻紅藥鬭新粧。", "玉笙莫作相思調，猶恐春歸得見郎。"]'),
('b7487942-ee9c-4561-a8cb-9070526c83ea','記夢  其一','楊冠卿','宋','宋诗','song-poetry','','[]','欹巖松檜轉龍蛇，洞戶仙人字少霞。',32,'全唐诗/poet.song.159000.json','["欹巖松檜轉龍蛇，洞戶仙人字少霞。", "炯炯長眉非是畫，翠翹斜倚碧桃花。"]'),
('c4aa5e65-083f-40d0-aa60-bc6f56eb8c9a','記夢  其二','楊冠卿','宋','宋诗','song-poetry','','[]','問訊人間幾日期，謂言何處是瑶池。',32,'全唐诗/poet.song.159000.json','["問訊人間幾日期，謂言何處是瑶池。", "玉盃飲罷夢中醉，不記神遊話別時。"]'),
('ab56f711-6d95-446f-b900-dcaff1f7b3e5','壬午雜詩  其一','楊冠卿','宋','宋诗','song-poetry','','[]','黄屋非堯意，謳歌有啟歸。',48,'全唐诗/poet.song.159000.json','["黄屋非堯意，謳歌有啟歸。", "德參羲昊古，事與漢唐非。", "喜氣傳千嶂，皇風浹九圍。", "胡亡固無日，智勇舊沈機。"]'),
('53bdb165-b0c8-49da-85cf-fada482935a1','壬午雜詩  其二','楊冠卿','宋','宋诗','song-poetry','','[]','寒甚王親駕，春歸虜請和。',48,'全唐诗/poet.song.159000.json','["寒甚王親駕，春歸虜請和。", "北軍方擁衆，小戍或投戈。", "形勢中朝壯，衰離僞境多。", "燕雲可中裂，豈限白溝河。"]'),
('1dd71f45-94b4-41f4-af9c-6bcb05041b3c','壬午雜詩  其三','楊冠卿','宋','宋诗','song-poetry','','[]','不逆凶渠詐，當須報使回。',48,'全唐诗/poet.song.159000.json','["不逆凶渠詐，當須報使回。", "君恩固寬大，虜意每嫌猜。", "義舉初難廢，兵端莫浪開。", "要知情僞審，往事驗方來。"]'),
('6da4a448-c9bf-4279-adbb-cb1f3a149765','壬午雜詩  其四','楊冠卿','宋','宋诗','song-poetry','','[]','關內攻城戰，淮東却敵兵。',48,'全唐诗/poet.song.159000.json','["關內攻城戰，淮東却敵兵。", "敗亡初妄作，狼狽坐虛名。", "賊勢雖亡命，君心實好生。", "不知他日事，誰築受降城。"]'),
('bb0fe837-8f7f-4275-8f6a-383feea6b655','壬午雜詩  其五','楊冠卿','宋','宋诗','song-poetry','','[]','已分依人老，猶期振袂還。',48,'全唐诗/poet.song.159000.json','["已分依人老，猶期振袂還。", "有愁供白髮，無力買青山。", "北駕方傳蹕，西師已度關。", "孤臣憂國泪，東首落餘潸。"]'),
('2fc3f0eb-ad18-44ab-9dc9-cac6ccddbc01','寄別友生馬千里  其一','楊冠卿','宋','宋诗','song-poetry','','[]','秋鴻社燕幾時休，萬里無家天盡頭。',32,'全唐诗/poet.song.159000.json','["秋鴻社燕幾時休，萬里無家天盡頭。", "青蒻綠蓑今已辦，江湖歸去老漁舟。"]'),
('777a70e8-d63e-40e2-a628-d818dd192157','寄別友生馬千里  其二','楊冠卿','宋','宋诗','song-poetry','','[]','瘴雨蠻煙道路賒，囊書匣劍是生涯。',32,'全唐诗/poet.song.159000.json','["瘴雨蠻煙道路賒，囊書匣劍是生涯。", "海山佳處能相憶，好寄新詩鴈字斜。"]'),
('daa44641-5fc7-4d86-88cb-34f178fe9a0c','齊安  其一','楊冠卿','宋','宋诗','song-poetry','','[]','寂寞東坡對竹樓，兩公陳跡是前修。',32,'全唐诗/poet.song.159000.json','["寂寞東坡對竹樓，兩公陳跡是前修。", "津亭倚柁還商子，雪後獨爲江上遊。"]'),
('9d2211fa-89eb-482b-9197-391537b1070e','齊安  其二','楊冠卿','宋','宋诗','song-poetry','','[]','隻輪不返笑曹瞞，赤壁空臨江水寒。',32,'全唐诗/poet.song.159000.json','["隻輪不返笑曹瞞，赤壁空臨江水寒。", "想得周郎鐃鼓競，小喬相與對春山。"]'),
('9148d9b5-bc1b-47eb-bacd-e901e870dc2e','病後暑退','楊冠卿','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','寬作遲留計，難期歲月功。',48,'全唐诗/poet.song.159000.json','["寬作遲留計，難期歲月功。", "方驚鼠輩舞，未覺馬羣空。", "度暑蘇病骨，涉秋悲候蟲。", "長江二千里，只欠一帆風。"]'),
('afff07c7-66a7-4279-a28d-5ef54017abc0','甲申歲作  其一','楊冠卿','宋','宋诗','song-poetry','','[]','渺渺冰雪盡，欣欣花柳蘇。',48,'全唐诗/poet.song.159000.json','["渺渺冰雪盡，欣欣花柳蘇。", "江澄炫初日，沙潤茁新蔞。", "久客亦勞止，我行猶載驅。", "乾坤如許大，何處著吾廬。"]'),
('6ddcaea4-fde1-4521-a7d7-da918a4c7582','甲申歲作  其二','楊冠卿','宋','宋诗','song-poetry','','[]','急雨來排難，餘蒸頓解嚴。',48,'全唐诗/poet.song.159000.json','["急雨來排難，餘蒸頓解嚴。", "時蜩鳴露柳，客燕度風簾。", "屈指秋無幾，安心氣自恬。", "夜凉都不寐，落月瑩虛簷。"]'),
('1d902f7e-44f1-4fce-ba7e-a1594be82e14','讀杜工部集','楊冠卿','宋','宋诗','song-poetry','','[]','平生忠義不忘君，末路升沈付九原。',64,'全唐诗/poet.song.159000.json','["平生忠義不忘君，末路升沈付九原。", "千古神交真未泯，一時人事可重論。", "摩挲醉眼朝廷在，消息他鄉弟妹存。", "獨閲遺編堪墮淚，秋窗燈火雨昏昏。"]'),
('99296aec-cd7c-49e0-ab3f-20278b398ab6','讀親征詔  其一','楊冠卿','宋','宋诗','song-poetry','','[]','詔語深醇告萬方，便知九鼎不勞扛。',32,'全唐诗/poet.song.159000.json','["詔語深醇告萬方，便知九鼎不勞扛。", "波臣奔走扶黄屋，約束風濤過大江。"]'),
('fc7b8ddb-8336-4f04-b517-00fce2983e6a','讀親征詔  其二','楊冠卿','宋','宋诗','song-poetry','','[]','君王神武不恬兵，氣讋中原一掃平。',32,'全唐诗/poet.song.159000.json','["君王神武不恬兵，氣讋中原一掃平。", "可笑西江喜歸客，便裝行橐待還京。"]'),
('e0d70501-3a15-4c53-bc47-1349f8293d1e','塞上雪中','楊冠卿','宋','宋诗','song-poetry','','[]','雪色迷江國，人誰入蔡城。',48,'全唐诗/poet.song.159000.json','["雪色迷江國，人誰入蔡城。", "窗虛元自白，梅破不勝清。", "佳客苦難喚，清尊只細傾。", "吾衰便靜退，不忍浪談兵。"]'),
('dc737641-c746-4708-b238-2f58fa5f1da6','代別張憲  其一','楊冠卿','宋','宋诗','song-poetry','','[]','澤國春强半，餘寒燕子飛。',48,'全唐诗/poet.song.159000.json','["澤國春强半，餘寒燕子飛。", "絕知懸榻久，故作買舟歸。", "歲月空荒老，行藏有是非。", "功名遊戲爾，此意尚依稀。"]'),
('57dade41-60d5-4508-aeee-fdad8d2f2a51','代別張憲  其二','楊冠卿','宋','宋诗','song-poetry','','[]','老去安爲客，春來不著家。',48,'全唐诗/poet.song.159000.json','["老去安爲客，春來不著家。", "江湖遂良覿，身世入長嗟。", "處死寧無地，謀生信有涯。", "分携感時節，楊柳又藏鴉。"]'),
('73627f49-f59f-485f-9065-c70e16fb5399','回紋四時  其一','楊冠卿','宋','宋诗','song-poetry','','[]','輕風透幕羅衾薄，滿萼嬌紅綴小桃。',32,'全唐诗/poet.song.159000.json','["輕風透幕羅衾薄，滿萼嬌紅綴小桃。", "明月對愁縈錦字，斷絃空暗紫檀槽。"]'),
('ffc2b1e7-37b0-43a1-a91b-f0acb58b47cc','回紋四時  其二','楊冠卿','宋','宋诗','song-poetry','','[]','冰盤瑩靜風簾闔，酪粉嘗殘日影曛。',32,'全唐诗/poet.song.159000.json','["冰盤瑩靜風簾闔，酪粉嘗殘日影曛。", "稜枕印紅斜玉頰，碧衫揎袖整輕雲。"]'),
('6c19afea-6b86-4489-ba2a-ed0dd7079bba','回紋四時  其三','楊冠卿','宋','宋诗','song-poetry','','[]','紋簟浥香餘汗粉，綠眉攢恨舊愁新。',32,'全唐诗/poet.song.159000.json','["紋簟浥香餘汗粉，綠眉攢恨舊愁新。", "焚香夜拜初生月，暮色窗紗薄霧勻。"]'),
('0dbc0862-b241-4044-84a3-816c7e6d0e7d','回紋四時  其四','楊冠卿','宋','宋诗','song-poetry','','[]','霜驚葉落催寒曉，夢破人愁覺夜長。',32,'全唐诗/poet.song.159000.json','["霜驚葉落催寒曉，夢破人愁覺夜長。", "香暗折梅初點玉，鏡鸞呵手試新粧。"]'),
('a2fd82a1-696c-400c-be17-0bef8d99284b','九里松六言','楊冠卿','宋','宋诗','song-poetry','','[]','風聲不斷天籟，鐘韻初知日曛。',28,'全唐诗/poet.song.159000.json','["風聲不斷天籟，鐘韻初知日曛。", "人語驚飛幽鳥，馬蹄踏破輕雲。"]'),
('d391d9af-540b-4ecd-b85c-8275fa7ec360','王幹竹枕甚簡古客有得之者爲賦二絕  其一','楊冠卿','宋','宋诗','song-poetry','','[]','榮枯已熟槐安境，妄幻敢藏鴻寶書。',32,'全唐诗/poet.song.159000.json','["榮枯已熟槐安境，妄幻敢藏鴻寶書。", "一節黑甜參已透，漆園胡蝶浪分疎。"]'),
('f467c4f0-b75b-4cef-ab73-74e58b24f914','王幹竹枕甚簡古客有得之者爲賦二絕  其二','楊冠卿','宋','宋诗','song-poetry','','[]','夜明已賜虢國姊，曲肱又屬東家丘。',32,'全唐诗/poet.song.159000.json','["夜明已賜虢國姊，曲肱又屬東家丘。", "娛寢有人君得計，睡鄉留我取通侯。"]'),
('82286806-16b6-4e8b-b1d0-c185fc748cfa','吳江道中  其一','楊冠卿','宋','宋诗','song-poetry','','[]','野色蒼煙闊，篷籠宿雨開。',48,'全唐诗/poet.song.159000.json','["野色蒼煙闊，篷籠宿雨開。", "湖光與天接，林彩覺春回。", "心事歸雙鬢，年華付一盃。", "松江元赴海，流駛更須催。"]');
